/** Log the current result's actual quoted/PO price so the model self-calibrates. */
/** Headline should-cost of a PCB image result (BOM + fab + assembly), for calibration. */
function pcbHeadlineTotal(r: PCBImageAnalysis): number {
  const cb = (r as unknown as { _confidenceBand?: { totalMid?: number } })._confidenceBand;
  if (cb && typeof cb.totalMid === 'number') return cb.totalMid;
  const co = r.costEstimates;
  return (co?.totalBOMCostGBP ?? 0) + (co?.pcbFabGBP?.mid ?? 0) + (co?.smtAssemblyCostGBP ?? 0);
}

/** Learn-from-actuals loop for the PCB image pipeline — records a 'pcba' calibration
 *  sample so the should-cost self-corrects toward real quotes over time. */
function logActualForPCB(): void {
  const r = pcbImageResult;
  if (!r) { showToast('Run a PCB analysis first', 'warning'); return; }
  const est = pcbHeadlineTotal(r);
  const raw = window.prompt(`Enter the ACTUAL quoted / PO board price for "${r.partName}" (GBP) — the model estimated £${est.toFixed(2)}:`);
  if (raw === null) return;
  const actual = parseFloat(raw.replace(/[^0-9.]/g, ''));
  if (!Number.isFinite(actual) || actual <= 0) { showToast('Please enter a positive number', 'warning'); return; }
  const recs = getCalibrationRecords();
  recs.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    savedAt: Date.now(), commodity: 'pcba',
    region: (r as unknown as { _selectedCountry?: string })._selectedCountry?.toUpperCase() ?? 'CN',
    shouldCost: est, actualCost: actual, currency: 'GBP',
  });
  saveCalibrationRecords(recs);
  const s = computeCalibration(recs, 'pcba');
  showToast(s.applied
    ? `Logged. PCBA now calibrated ×${s.biasFactor} from ${s.n} quotes (MAPE ${s.calibratedMapePct}%). Re-analyze to apply.`
    : `Logged (${s.n}/3 PCBA quotes — need ${3 - s.n} more to calibrate).`, 'info');
}

function logActualQuote(): void {
  // PCB image-to-BOM keeps its result in pcbImageResult (not lastResult) — route there.
  if (pcbImageResult && (activeCommodity === 'pcb_fab' || activeCommodity === 'pcba')) { logActualForPCB(); return; }
  if (!lastResult) { showToast('Run Calculate first, then log the actual', 'warning'); return; }
  const raw = window.prompt(`Enter the ACTUAL quoted / PO unit price for "${lastResult.partName}" (${_displayCurrency}) — the model estimated ${_currFmt(lastResult.total)}:`);
  if (raw === null) return;
  const actual = parseFloat(raw.replace(/[^0-9.]/g, ''));
  if (!Number.isFinite(actual) || actual <= 0) { showToast('Please enter a positive number', 'warning'); return; }
  const recs = getCalibrationRecords();
  recs.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    savedAt: Date.now(),
    commodity: activeCommodity,
    region: (document.getElementById('mfg-region-selector') as HTMLSelectElement)?.value ?? 'UK',
    materialFamily: currentMaterialFamily(),
    shouldCost: lastResult.total,
    actualCost: actual,
    currency: _displayCurrency,
  });
  saveCalibrationRecords(recs);
  // Also attach the actual to this part's knowledge-base case (org memory).
  const kbToken = _authToken();
  if (kbToken) {
    const partName = (document.getElementById('part-name') as HTMLInputElement)?.value || lastResult.partName;
    void fetch('/api/knowledge/actual', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${kbToken}` },
      body: JSON.stringify({ partName, commodity: activeCommodity, actualCost: actual }),
    }).catch(() => { /* offline — local calibration still recorded */ });
  }
  const s = computeCalibration(recs, activeCommodity);
  showToast(s.applied
    ? `Logged. ${activeCommodity.replace(/_/g, ' ')} now calibrated ×${s.biasFactor} from ${s.n} quotes (MAPE ${s.calibratedMapePct}%).`
    : `Logged (${s.n}/${3} quotes for ${activeCommodity.replace(/_/g, ' ')} — need ${3 - s.n} more to calibrate).`, 'info');
  if (lastResult && lastInput) renderInsights(lastResult, lastInput);
}

// ─── Calibration & Actuals (bulk import + coverage) ────────────────────────────

function openCalibrationModal(): void {
  renderCalibrationCoverage();
  el('calibration-modal').style.display = 'flex';
}

/** Ingest a pasted CSV of real actuals into the calibration store, teaching the
 *  model across many segments at once. */
function importActualsFromText(): void {
  const ta = document.getElementById('cal-import-text') as HTMLTextAreaElement | null;
  const status = document.getElementById('cal-import-status');
  const text = ta?.value ?? '';
  if (!text.trim()) { if (status) { status.textContent = 'Paste some CSV rows first.'; status.style.color = 'var(--warning)'; } return; }
  const res = parseActualsCsv(text, Date.now());
  if (res.imported > 0) {
    const recs = getCalibrationRecords();
    recs.push(...res.records);
    saveCalibrationRecords(recs);
    if (ta) ta.value = '';
  }
  if (status) {
    const errNote = res.errors.length ? ` · ${res.skipped} skipped (${escHtml(res.errors.slice(0, 3).join('; '))}${res.errors.length > 3 ? '…' : ''})` : '';
    status.innerHTML = `<strong style="color:${res.imported ? 'var(--success)' : 'var(--danger)'}">Imported ${res.imported} actual${res.imported === 1 ? '' : 's'}</strong>${errNote}`;
  }
  renderCalibrationCoverage();
  // If a costing is on screen, refresh its audit strip so calibration shows immediately.
  if (lastResult && lastInput) renderSelfAudit(lastResult, lastInput);
}

/** Coverage table: every segment (commodity × material × region) with logged
 *  actuals — sample count, learned bias, MAPE, calibrated flag, drift. */
function renderCalibrationCoverage(): void {
  const host = document.getElementById('cal-coverage');
  if (!host) return;
  const recs = getCalibrationRecords();
  const cov = calibrationCoverage(recs);
  const sum = calibrationSummary(recs);
  if (!cov.length) {
    host.innerHTML = `<div style="font-size:0.78rem;color:var(--text-muted);padding:10px 0">No actuals logged yet. Paste a CSV above, or use <strong>Log Actual £</strong> after a costing, to start calibrating.</div>`;
    return;
  }
  const sym = CURRENCY_SYMBOL[_displayCurrency] ?? '';
  void sym;
  const rows = cov.map(c => {
    const drift = segmentDrift(recs, { commodity: c.commodity, materialFamily: c.materialFamily, region: c.region });
    const seg = `${(COMMODITY_LABELS[c.commodity] ?? c.commodity)}${c.materialFamily ? ' · ' + c.materialFamily : ''}${c.region ? ' · ' + c.region : ''}`;
    const badge = c.calibrated
      ? `<span style="background:#e6f4ea;color:#1b6b3a;border-radius:4px;padding:1px 7px;font-size:0.66rem;font-weight:700">×${c.biasFactor}</span>`
      : `<span style="background:#eef1f4;color:#647084;border-radius:4px;padding:1px 7px;font-size:0.66rem">${c.n}/3</span>`;
    const driftCell = drift.drifting
      ? `<span style="color:#8a5300;font-weight:600">⚠ ${drift.deltaPct > 0 ? '+' : ''}${drift.deltaPct}%</span>`
      : '<span style="color:var(--text-muted)">—</span>';
    return `<tr>
      <td style="padding:5px 8px">${escHtml(seg)}</td>
      <td style="padding:5px 8px;text-align:right">${c.n}</td>
      <td style="padding:5px 8px;text-align:center">${badge}</td>
      <td style="padding:5px 8px;text-align:right">${c.calibrated ? c.calibratedMapePct + '%' : '—'}</td>
      <td style="padding:5px 8px;text-align:center">${driftCell}</td>
    </tr>`;
  }).join('');
  host.innerHTML = `
    <div style="font-size:0.74rem;color:var(--text-secondary);margin-bottom:6px">Portfolio: <strong>${sum.totalSamples}</strong> actuals · calibrated MAPE <strong>${sum.weightedCalibratedMapePct}%</strong> (raw ${sum.weightedMapePct}%)</div>
    <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:0.76rem">
      <thead><tr style="border-bottom:1px solid var(--border)">
        <th style="padding:5px 8px;text-align:left">Segment (commodity · material · region)</th>
        <th style="padding:5px 8px;text-align:right">Actuals</th>
        <th style="padding:5px 8px;text-align:center">Bias</th>
        <th style="padding:5px 8px;text-align:right">MAPE</th>
        <th style="padding:5px 8px;text-align:center">Drift</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table></div>`;
}

// ─── Knowledge base (self-learning memory) ─────────────────────────────────────

function _authToken(): string | null {
  return localStorage.getItem('auth_token') ?? sessionStorage.getItem('auth_token');
}

/** Material family of the current costing (library category, e.g. "Aluminium"). */
function currentMaterialFamily(): string | undefined {
  const matId = lastInput?.rawMaterial?.materialId;
  if (!matId) return undefined;
  return library.materials.find(m => m.id === matId)?.category;
}


/** Commodity indices (one representative per category) for the causal cost model. */
function commodityIndices(): CommodityIndexRef[] {
  const out = new Map<string, CommodityIndexRef>();
  for (const c of (_commData?.commodities ?? [])) {
    if (!out.has(c.category)) out.set(c.category, { category: c.category, currentPrice: c.currentPrice, unit: c.unit });
  }
  return [...out.values()];
}

/** Numeric fingerprint of the current part — powers similarity matching. */
function buildCurrentFingerprint(): PartFingerprint {
  const g = cadAnalysisResult?.geometry;
  const feats = cadOCCTGeometry?.features;
  return {
    commodity: activeCommodity,
    materialId: lastInput?.rawMaterial?.materialId,
    materialFamily: currentMaterialFamily(),
    region: (document.getElementById('mfg-region-selector') as HTMLSelectElement)?.value ?? 'UK',
    netWeightKg: lastInput?.rawMaterial?.netWeightKg || undefined,
    annualVolume: parseFloat((document.getElementById('annual-volume') as HTMLInputElement)?.value ?? '') || undefined,
    bboxMaxMm: g ? Math.max(g.boundingBoxMm.x, g.boundingBoxMm.y, g.boundingBoxMm.z) : undefined,
    volumeCm3: g?.estimatedVolumeCm3 || undefined,
    holeCount: feats?.estimatedHoleCount,
    freeFormFaceCount: feats?.freeFormFaceCount,
  };
}

/**
 * The learning loop's client side: after every Calculate, remember this costing in
 * the org knowledge base, retrieve similar past parts, and render suggestions +
 * proactive insights into the #kb-panel placeholder. Silent when offline/signed-out.
 */
async function updateKnowledgePanel(result: PartCostResult): Promise<void> {
  const panel = document.getElementById('kb-panel');
  const token = _authToken();
  if (!panel || !token) return;
  const headers = { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` };
  const fingerprint = buildCurrentFingerprint();
  const partName = (document.getElementById('part-name') as HTMLInputElement)?.value || result.partName || 'Part';
  try {
    // 1. Remember (upsert) this costing as a case.
    void fetch('/api/knowledge/case', {
      method: 'POST', headers,
      body: JSON.stringify({
        partName, fingerprint, totalCost: result.total, currency: _displayCurrency,
        breakdown: result.breakdown,
      }),
    }).catch(() => { /* offline — memory sync skipped */ });

    // 2. Retrieve similar past parts + derived suggestions + proactive insights.
    const resp = await fetch('/api/knowledge/similar', {
      method: 'POST', headers,
      body: JSON.stringify({ fingerprint, currentTotal: result.total, breakdown: result.breakdown, excludePartName: partName }),
    });
    if (!resp.ok) return;
    const data = await resp.json() as {
      similar: SimilarCase[]; suggestions: CaseSuggestion[]; insights: ProactiveInsight[];
      stats: { total: number; withActuals: number };
    };
    const { similar, suggestions, insights, stats } = data;
    if (!similar.length && !insights.length) return;

    const matchRows = similar.map(s => `
      <div style="display:flex;justify-content:space-between;gap:10px;font-size:0.76rem;padding:3px 0;border-bottom:1px dashed var(--border)">
        <span>${escHtml(s.partName)} <span style="color:var(--text-muted)">(${Math.round(s.similarity * 100)}% match: ${s.matchedOn.slice(0, 3).join(', ')})</span></span>
        <span style="white-space:nowrap"><strong>${_currFmt(s.totalCost)}</strong>${s.actualCost ? ` <span style="color:#7c3aed" title="Logged actual quote">· actual ${_currFmt(s.actualCost)}</span>` : ''}</span>
      </div>`).join('');
    const suggRows = suggestions.map(s => `<div style="font-size:0.76rem;margin-top:3px;color:${s.kind === 'warning' ? '#d97706' : 'var(--text-secondary)'}">${s.kind === 'warning' ? '⚠' : '•'} ${escHtml(s.text)}</div>`).join('');
    const insightRows = insights.map(i => `<div style="font-size:0.76rem;margin-top:3px;color:${i.severity === 'attention' ? '#d97706' : 'var(--text-secondary)'}">${i.severity === 'attention' ? '⚠' : 'ℹ'} ${escHtml(i.text)}</div>`).join('');

    panel.innerHTML = `
      <div style="margin-top:8px;padding:12px 14px;border:1px solid var(--border);border-left:4px solid #0ea5e9;border-radius:8px;background:var(--surface-elevated)">
        <div style="display:flex;justify-content:space-between;align-items:baseline;flex-wrap:wrap;gap:8px">
          <div style="font-weight:700;font-size:0.9rem;color:var(--text-primary)">🧠 AI memory — similar past parts</div>
          <div style="font-size:0.7rem;color:var(--text-muted)">Knowledge base: ${stats.total} analyses · ${stats.withActuals} with actuals</div>
        </div>
        ${matchRows ? `<div style="margin-top:6px">${matchRows}</div>` : ''}
        ${suggRows}
        ${insightRows}
      </div>`;
  } catch { /* offline / server down — the panel simply stays empty */ }
}


// ─── App-nav active state (sidebar) ──────────────────────────────────────────
function setNavActive(id: 'home-btn' | 'analytics-btn' | 'news-btn' | 'negotiation-btn' | 'viewer-btn' | null): void {
  document.querySelectorAll('#app-nav .anav-item').forEach(el => el.classList.remove('active'));
  if (id) document.getElementById(id)?.classList.add('active');
  // every view switch passes through here — hide the standalone 3D viewer page
  // (showViewer re-shows it right after calling this)
  document.getElementById('viewer-view')?.style.setProperty('display', 'none');
  // Every view switch passes through here — close the demo-gallery modal so it
  // can't stay glued on top of the next view, and restore page scroll (its
  // opener sets body overflow:hidden).
  const dm = document.getElementById('demo-modal');
  if (dm && dm.style.display !== 'none') { dm.style.display = 'none'; document.body.style.overflow = ''; }
}

