// Set by wirePCBImageZone so the results panel (targeted re-capture) can drop a
// close-up into an upload slot without duplicating the thumbnail/state logic.
let _pcbSetSlot: ((idx: number, file: File) => void) | null = null;

function wirePCBImageZone(): void {
  const analyzeBtn = el<HTMLButtonElement>('pcb-img-analyze-btn');
  const countLabel = el('pcb-img-count');
  const SLOT_LABELS = ['Top side', 'Bottom side', 'Close-up 1', 'Close-up 2', 'Close-up 3'];

  function updateAnalyzeBtn(): void {
    const selected = pcbImageFiles.filter(Boolean);
    const n = selected.length;
    if (countLabel) {
      countLabel.textContent = n === 0
        ? 'No images selected'
        : `${n} image${n > 1 ? 's' : ''} selected (${pcbImageFiles.map((f, i) => f ? SLOT_LABELS[i] : null).filter(Boolean).join(', ')})`;
    }
    if (analyzeBtn) analyzeBtn.disabled = n === 0;
  }

  function setSlot(idx: number, file: File): void {
    pcbImageFiles[idx] = file;
    const thumb = el<HTMLImageElement>(`pcb-img-thumb-${idx}`);
    if (thumb) thumb.src = URL.createObjectURL(file);
    const emptyDiv = el(`pcb-img-slot-empty-${idx}`);
    const filledDiv = el(`pcb-img-slot-filled-${idx}`);
    const slot = el(`pcb-img-slot-${idx}`);
    if (emptyDiv) emptyDiv.style.display = 'none';
    if (filledDiv) filledDiv.style.display = 'block';
    if (slot) slot.style.borderColor = idx === 0 ? 'var(--accent)' : 'rgba(79,142,247,0.4)';
    updateAnalyzeBtn();
  }
  _pcbSetSlot = setSlot;

  function clearSlot(idx: number): void {
    pcbImageFiles[idx] = null;
    const emptyDiv = el(`pcb-img-slot-empty-${idx}`);
    const filledDiv = el(`pcb-img-slot-filled-${idx}`);
    const slot = el(`pcb-img-slot-${idx}`);
    const input = el<HTMLInputElement>(`pcb-img-input-${idx}`);
    if (emptyDiv) emptyDiv.style.display = 'flex';
    if (filledDiv) filledDiv.style.display = 'none';
    if (slot) slot.style.borderColor = '';
    if (input) input.value = '';
    updateAnalyzeBtn();
  }

  // Wire each of the 5 slots
  [0, 1, 2, 3, 4].forEach(idx => {
    const slot = el(`pcb-img-slot-${idx}`);
    const input = el<HTMLInputElement>(`pcb-img-input-${idx}`);
    const removeBtn = el(`pcb-img-remove-${idx}`);

    slot?.addEventListener('click', (e) => {
      if ((e.target as HTMLElement).id === `pcb-img-remove-${idx}`) return;
      input?.click();
    });
    input?.addEventListener('change', () => {
      const f = input?.files?.[0];
      if (f) setSlot(idx, f);
    });
    removeBtn?.addEventListener('click', (e) => {
      e.stopPropagation();
      clearSlot(idx);
    });
  });

  // Analyze button — no argument needed, reads pcbImageFiles state
  analyzeBtn?.addEventListener('click', () => void analyzePCBImages());

  // Drag-and-drop: drop one or multiple files, fill slots in order
  const zone = el('pcb-img-zone');
  zone?.addEventListener('dragover', (e) => { e.preventDefault(); zone.classList.add('drag-over'); });
  zone?.addEventListener('dragleave', () => zone.classList.remove('drag-over'));
  zone?.addEventListener('drop', (e) => {
    e.preventDefault();
    zone.classList.remove('drag-over');
    const dropped = Array.from((e as DragEvent).dataTransfer?.files ?? [])
      .filter(f => f.type.startsWith('image/'))
      .slice(0, 5);
    dropped.forEach(f => {
      const emptySlot = pcbImageFiles.findIndex(s => s === null);
      if (emptySlot !== -1) setSlot(emptySlot, f);
    });
  });

  // BOM file picker (Priority 2)
  const bomPickBtn = el<HTMLButtonElement>('pcb-bom-pick-btn');
  const bomInput = el<HTMLInputElement>('pcb-bom-input');
  const bomLabel = el('pcb-bom-filename');
  bomPickBtn?.addEventListener('click', () => bomInput?.click());
  bomInput?.addEventListener('change', () => {
    const bf = bomInput?.files?.[0] ?? null;
    pcbBOMFile = bf;
    if (bomLabel) bomLabel.textContent = bf
      ? `📋 ${bf.name} (${(bf.size / 1024).toFixed(0)} KB) — used as ground truth`
      : 'No file — AI will extract BOM from image';
  });

  // Automotive NRE toggle (Feature 7)
  const nreToggle = el<HTMLInputElement>('pcb-automotive-nre');
  nreToggle?.addEventListener('change', () => {
    pcbNREEnabled = !!nreToggle.checked;
    if (pcbImageResult) injectPCBImagePanel();
  });
}

/**
 * Downscale a PCB photo to a JPEG bounded by `maxEdge` px before upload.
 * DEFAULT is 1600 px — a balanced resolution that reads most component
 * outlines and larger markings while keeping image-token cost ~3× lower than
 * full-res. Deep-analysis mode passes 2576 px (the max Claude Sonnet 5 / Opus
 * 4.8 accept) when reading tiny IC top-marks on dense boards actually matters.
 * Either way, phone photos (often 4–8 MB) must be bounded or the multi-image
 * request pushes past the Anthropic API's ~32 MB per-request limit → HTTP 413.
 * Falls back to the original file if anything fails.
 */
async function downscaleImageForUpload(file: File, maxEdge = 1600, quality = 0.82): Promise<File> {
  if (!file.type.startsWith('image/')) return file;
  try {
    const dataUrl = await new Promise<string>((resolve, reject) => {
      const r = new FileReader();
      r.onload = () => resolve(r.result as string);
      r.onerror = () => reject(r.error);
      r.readAsDataURL(file);
    });
    const img = await new Promise<HTMLImageElement>((resolve, reject) => {
      const im = new Image();
      im.onload = () => resolve(im);
      im.onerror = () => reject(new Error('image decode failed'));
      im.src = dataUrl;
    });
    const scale = Math.min(1, maxEdge / Math.max(img.width, img.height));
    // Already small in both dimensions and bytes — leave it untouched.
    if (scale >= 1 && file.size < 1_200_000) return file;
    const canvas = document.createElement('canvas');
    canvas.width = Math.max(1, Math.round(img.width * scale));
    canvas.height = Math.max(1, Math.round(img.height * scale));
    const ctx = canvas.getContext('2d');
    if (!ctx) return file;
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    const blob = await new Promise<Blob | null>(res => canvas.toBlob(res, 'image/jpeg', quality));
    if (!blob || blob.size >= file.size) return file;
    const baseName = file.name.replace(/\.[^.]+$/, '') || 'pcb';
    return new File([blob], `${baseName}.jpg`, { type: 'image/jpeg' });
  } catch {
    return file;
  }
}

/** Defensive mirror of the server's normalizePCBAnalysis, shared by BOTH the
 *  analyze and re-analyze handlers. The renderer calls .toFixed()/.replace()
 *  on these fields — every one must exist and be well-typed even when the
 *  payload came from an older server, a cache, or a sparse model response.
 *  (The re-analyze path missing this crashed with "undefined is not an
 *  object (evaluating 'a.smtPlacements')".) */
function normalizePCBPayloadForRender(an: Record<string, unknown>): void {
  const num = (v: unknown, d: number) => (Number.isFinite(Number(v)) ? Number(v) : d);
  const bom = (Array.isArray(an.bom) ? an.bom : []) as Array<Record<string, unknown>>;
  for (const l of bom) { l.qty = num(l.qty, 1); l.unitPriceGBP = num(l.unitPriceGBP, 0); l.lineConf = num(l.lineConf, 0.5); }
  an.bom = bom;
  const totalQty = bom.reduce((s, l) => s + (l.qty as number), 0);
  const bomTotal = bom.reduce((s, l) => s + (l.qty as number) * (l.unitPriceGBP as number), 0);
  const asm = (an.assembly && typeof an.assembly === 'object' ? an.assembly : {}) as Record<string, unknown>;
  an.assembly = {
    ...asm,
    smtPlacements: num(asm.smtPlacements, totalQty), throughHoleJoints: num(asm.throughHoleJoints, 0),
    manualJoints: num(asm.manualJoints, 0), bgaCount: num(asm.bgaCount, 0),
    complexity: typeof asm.complexity === 'string' ? asm.complexity : 'Medium',
    reflowSides: num(asm.reflowSides, 1),
    aoiRequired: typeof asm.aoiRequired === 'boolean' ? asm.aoiRequired : true,
    ictTimeSec: num(asm.ictTimeSec, 0),
  };
  const bstr = (v: unknown, d: string) => (typeof v === 'string' && v ? v : d);
  const bs = (an.boardSpec && typeof an.boardSpec === 'object' ? an.boardSpec : {}) as Record<string, unknown>;
  an.boardSpec = {
    ...bs,
    estimatedLayers: num(bs.estimatedLayers, 4), widthMm: num(bs.widthMm, 100), heightMm: num(bs.heightMm, 80),
    panelUtilisation: num(bs.panelUtilisation, 0.8), copperWeightOz: num(bs.copperWeightOz, 1),
    // string fields the renderer calls .replace() on — must never be undefined
    technologyType: bstr(bs.technologyType, 'standard_rigid'),
    qualityGrade: bstr(bs.qualityGrade, 'industrial'),
    surfaceFinish: bstr(bs.surfaceFinish, 'HASL'),
    solderMaskColour: bstr(bs.solderMaskColour, 'green'),
  };
  for (const l of bom) if (typeof l.componentType !== 'string' || !l.componentType) l.componentType = 'other';
  const ce = (an.costEstimates && typeof an.costEstimates === 'object' ? an.costEstimates : {}) as Record<string, unknown>;
  const fab = (ce.pcbFabGBP && typeof ce.pcbFabGBP === 'object' ? ce.pcbFabGBP : {}) as Record<string, unknown>;
  const fabMid = num(fab.mid, 2.5);
  an.costEstimates = {
    ...ce,
    pcbFabGBP: { min: num(fab.min, fabMid * 0.8), mid: fabMid, max: num(fab.max, fabMid * 1.3) },
    totalBOMCostGBP: num(ce.totalBOMCostGBP, Math.round(bomTotal * 100) / 100),
    smtAssemblyCostGBP: num(ce.smtAssemblyCostGBP, 0),
  };
  if (typeof an.partName !== 'string' || !an.partName) an.partName = 'PCB Assembly';
  if (typeof an.confidenceLevel !== 'string' || !an.confidenceLevel) an.confidenceLevel = 'Medium';
  for (const k of ['aiInsights', 'dfmIssues', 'highCostComponents', 'optimisationSuggestions', 'analysisLimitations']) {
    if (!Array.isArray(an[k])) an[k] = [];
  }
}

async function analyzePCBImages(): Promise<void> {
  const selectedFiles = pcbImageFiles.map((f, i) => f ? { file: f, label: ['Top side', 'Bottom side', 'Close-up 1', 'Close-up 2', 'Close-up 3'][i] } : null).filter((x): x is { file: File; label: string } => x !== null);
  if (!selectedFiles.length || pcbImageLoading) return;

  pcbImageLoading = true;

  const analyzeBtn = el<HTMLButtonElement>('pcb-img-analyze-btn');
  if (analyzeBtn) { analyzeBtn.disabled = true; analyzeBtn.textContent = `Analyzing ${selectedFiles.length} image${selectedFiles.length > 1 ? 's' : ''}…`; }

  const zone = el('pcb-img-zone');
  if (zone) zone.classList.add('pcb-img-zone--analyzing');
  ensurePcbStageTrack();

  const apiKey = (document.querySelector<HTMLInputElement>('#api-key-input'))?.value?.trim()
    ?? sessionStorage.getItem('cv_api_key') ?? '';

  const selectedCountry = (document.getElementById('pcb-mfg-country') as HTMLSelectElement)?.value ?? 'cn';
  const orderQty = (document.getElementById('pcb-order-qty') as HTMLInputElement)?.value ?? '100';

  const formData = new FormData();
  // Balanced 1600 px by default (keeps image tokens ~3× lower); full 2576 px
  // only when Deep analysis is on and reading tiny IC markings is worth the cost.
  const deepHiRes = (document.getElementById('pcb-deep-analysis') as HTMLInputElement | null)?.checked ?? false;
  const uploadMaxEdge = deepHiRes ? 2576 : 1600;
  const uploadFiles = await Promise.all(selectedFiles.map(x => downscaleImageForUpload(x.file, uploadMaxEdge)));
  uploadFiles.forEach(file => formData.append('pcbImages', file));
  formData.append('pcbImageLabels', JSON.stringify(selectedFiles.map(x => x.label)));

  // Retain every uploaded (downscaled) image so all export reports can embed them.
  try {
    pcbUploadedImages = await Promise.all(uploadFiles.map(async (file, i) => {
      const dataUrl = await new Promise<string>((resolve, reject) => {
        const rd = new FileReader();
        rd.onload = () => resolve(rd.result as string);
        rd.onerror = () => reject(rd.error);
        rd.readAsDataURL(file);
      });
      const dims = await new Promise<{ w: number; h: number }>((resolve) => {
        const im = new Image();
        im.onload = () => resolve({ w: im.naturalWidth || 1, h: im.naturalHeight || 1 });
        im.onerror = () => resolve({ w: 1, h: 1 });
        im.src = dataUrl;
      });
      return { label: selectedFiles[i].label, dataUrl, w: dims.w, h: dims.h };
    }));
  } catch { pcbUploadedImages = []; }
  formData.append('country', selectedCountry);
  formData.append('orderQty', orderQty);
  formData.append('deepAnalysis', String((document.getElementById('pcb-deep-analysis') as HTMLInputElement | null)?.checked ?? false));

  // Optional BOM/netlist file (Priority 2)
  const bomFileInput = document.getElementById('pcb-bom-input') as HTMLInputElement | null;
  const bomFile = bomFileInput?.files?.[0] ?? pcbBOMFile;
  if (bomFile) formData.append('bomFile', bomFile);

  // Store the primary (first) image as a data URL for board annotation (Feature 9)
  try {
    const primaryFile = selectedFiles[0].file;
    pcbImageDataURL = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = () => reject(reader.error);
      reader.readAsDataURL(primaryFile);
    });
  } catch { pcbImageDataURL = null; }

  try {
    // Use SSE streaming endpoint to show stage progress
    const streamResp = await fetch('/api/pcb/analyze-image-stream', {
      method: 'POST',
      headers: apiKey ? { 'x-api-key': apiKey } : {},
      body: formData,
    });
    if (!streamResp.ok || !streamResp.body) {
      const err = await streamResp.json().catch(() => ({ error: streamResp.statusText })) as { error: string };
      throw new Error(err.error ?? streamResp.statusText);
    }
    const reader = streamResp.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';
    type StreamResult = { success: boolean; analysis: PCBImageAnalysis; selectedCountry?: string; selectedCountryBreakdown?: PCBCountryBreakdown; countryComparison?: PCBCountryBreakdown[]; volumeCurves?: Record<string, VolumeCurvePoint[]>; complexityScore?: PCBComplexityScore; confidenceBand?: PCBConfidenceBand; volumeMultiplier?: number; sanityWarnings?: SanityWarning[]; npiBreakdown?: NPIBreakdown; livePriceHits?: number; asilLevel?: string; asilRationale?: string; asilSafetyFunctions?: string[]; automotiveNRE?: AutomotiveNRE; automotiveGradeEnforcedCount?: number; singleSourceWarnings?: SingleSourceWarning[]; conformalCoatingCost?: number; automotiveAssemblyCost?: AutomotiveAssemblyCost; automotiveFabAdjustment?: AutomotiveFabAdjustment; bomCompleteness?: BOMCompletenessResult; programPricing?: ProgramPricingResult };
    let data: StreamResult | null = null;
    let streamError: string | null = null;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n\n');
      buffer = lines.pop() ?? '';
      for (const chunk of lines) {
        const line = chunk.replace(/^data: /, '').trim();
        if (!line) continue;
        // Parse the SSE frame — a malformed chunk is ignored, but a well-formed
        // `error` event must surface (it was previously swallowed by this catch).
        let evt: Record<string, unknown> | null = null;
        try {
          evt = JSON.parse(line) as Record<string, unknown>;
        } catch (_parseErr) { continue; /* ignore parse errors on individual SSE chunks */ }
        if (evt.type === 'progress') {
          const pct = Number(evt.pct ?? 0);
          const label = String(evt.label ?? '');
          const stageN = Number(evt.stage ?? 0);
          if (analyzeBtn) analyzeBtn.textContent = `Analyzing… ${pct}%`;
          updatePcbStageTrack(stageN, label);
          if (zone) zone.title = `${pct}% — ${label}`;
        } else if (evt.type === 'error') {
          streamError = String(evt.message ?? 'Stream error');
        } else if (evt.type === 'complete') {
          data = evt as unknown as StreamResult;
        }
      }
    }
    if (streamError) throw new Error(streamError);
    if (!data || !data.analysis) throw new Error('Analysis result empty — the server closed the stream before finishing (possible timeout or crash during Stage 3). Try again, reduce to 1–2 images, or attach a BOM file.');
    normalizePCBPayloadForRender(data.analysis as unknown as Record<string, unknown>);
    // An empty BOM is a failed analysis, not a result. New servers never send
    // one (retry + 422), but an old cached payload still could — surface a
    // clear error instead of rendering a silently-empty BOM table.
    if ((data.analysis.bom ?? []).length === 0) {
      throw new Error('The AI returned no BOM lines for this board. Click Re-analyze to retry (empty results are no longer cached), add close-up photos with readable chip markings, or attach a BOM file.');
    }
    pcbImageResult = data.analysis;
    // Attach country data to analysis object for rendering
    if (pcbImageResult) {
      pcbImageResult._selectedCountry = data.selectedCountry ?? selectedCountry;
      pcbImageResult._selectedCountryBreakdown = data.selectedCountryBreakdown ?? undefined;
      pcbImageResult._countryComparison = data.countryComparison ?? [];
      pcbImageResult._volumeCurves = data.volumeCurves ?? undefined;
      if (data.complexityScore) pcbImageResult.complexityScore = data.complexityScore;
      if (data.confidenceBand) pcbImageResult._confidenceBand = data.confidenceBand;
      if (data.volumeMultiplier !== undefined) pcbImageResult._volumeMultiplier = data.volumeMultiplier;
      if (data.sanityWarnings) pcbImageResult._sanityWarnings = data.sanityWarnings;
      if (data.npiBreakdown) pcbImageResult._npiBreakdown = data.npiBreakdown;
      if (data.livePriceHits !== undefined) pcbImageResult._livePriceHits = data.livePriceHits;
      if (data.asilLevel) pcbImageResult._asilLevel = data.asilLevel;
      if (data.asilRationale) pcbImageResult._asilRationale = data.asilRationale;
      if (data.asilSafetyFunctions) pcbImageResult._asilSafetyFunctions = data.asilSafetyFunctions;
      if (data.automotiveNRE) pcbImageResult._automotiveNRE = data.automotiveNRE;
      if (data.automotiveGradeEnforcedCount !== undefined) pcbImageResult._automotiveGradeEnforcedCount = data.automotiveGradeEnforcedCount;
      if (data.singleSourceWarnings) pcbImageResult._singleSourceWarnings = data.singleSourceWarnings;
      if (data.conformalCoatingCost !== undefined) pcbImageResult._conformalCoatingCost = data.conformalCoatingCost;
      if (data.automotiveAssemblyCost) pcbImageResult._automotiveAssemblyCost = data.automotiveAssemblyCost;
      if (data.automotiveFabAdjustment) pcbImageResult._automotiveFabAdjustment = data.automotiveFabAdjustment;
      if (data.bomCompleteness) pcbImageResult._bomCompleteness = data.bomCompleteness;
      if (data.programPricing) pcbImageResult._programPricing = data.programPricing;
    }
    // Save previous result for revision comparison
    const prevJson = localStorage.getItem('pcb_last_analysis');
    if (prevJson && pcbImageResult) {
      try {
        const prev = JSON.parse(prevJson) as PCBImageAnalysis;
        pcbImageResult._previousVersion = prev;
      } catch { /* ignore */ }
    }
    if (pcbImageResult) {
      try { localStorage.setItem('pcb_last_analysis', JSON.stringify({ partName: pcbImageResult.partName, bom: pcbImageResult.bom, costEstimates: pcbImageResult.costEstimates, boardSpec: pcbImageResult.boardSpec })); } catch { /* ignore */ }
    }
    injectPCBImagePanel();
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    const resultsEl = el('pcb-img-results');
    if (resultsEl) resultsEl.innerHTML = `<div class="pcb-img-error">⚠ Analysis failed: ${msg}</div>`;
  } finally {
    pcbImageLoading = false;
    finishPcbStageTrack();
    const n = pcbImageFiles.filter(Boolean).length;
    if (analyzeBtn) { analyzeBtn.disabled = n === 0; analyzeBtn.textContent = 'Re-analyze'; }
    if (zone) zone.classList.remove('pcb-img-zone--analyzing');
  }
}


// ─── PCB analysis stage skeleton (5-stage pipeline progress) ─────────────────
const PCB_STAGES = [
  'Board classification & safety level',
  'OCR — reading printed markings',
  'Full vision BOM extraction',
  'Costing & country comparison',
  'Finalising result',
];

function ensurePcbStageTrack(): HTMLElement | null {
  let track = document.getElementById('pcb-stage-track');
  if (!track) {
    const zone = el('pcb-img-zone');
    if (!zone) return null;
    track = document.createElement('div');
    track.id = 'pcb-stage-track';
    zone.insertAdjacentElement('afterend', track);
  }
  track.innerHTML = PCB_STAGES.map((label, i) =>
    `<div class="pcb-stage" data-stage="${i + 1}"><span class="ps-dot"></span><span class="ps-label">${label}</span><span class="ps-bar"></span></div>`).join('');
  track.classList.add('live');
  return track;
}

function updatePcbStageTrack(stage: number, label: string): void {
  const track = document.getElementById('pcb-stage-track');
  if (!track) return;
  track.querySelectorAll<HTMLElement>('.pcb-stage').forEach(row => {
    const n = parseInt(row.dataset.stage ?? '0', 10);
    row.classList.toggle('done', n < stage || stage >= 5);
    row.classList.toggle('active', n === stage && stage < 5);
    if (n === stage && label) {
      const lbl = row.querySelector('.ps-label');
      if (lbl) lbl.textContent = label.replace(/^Stage \d+[ab]? — /, '');
    }
  });
}

function finishPcbStageTrack(): void {
  const track = document.getElementById('pcb-stage-track');
  if (track) { track.classList.remove('live'); track.innerHTML = ''; }
}

function injectPCBDemoCards(): void {
  const resultsEl = el('pcb-img-results');
  if (!resultsEl || pcbImageResult) return;
  resultsEl.innerHTML = buildPCBDemoSection();
}

(window as unknown as Record<string, unknown>).__loadPCBDemo = function(id: string): void {
  pcbImageResult = id === 'adas' ? PCB_DEMO_ADAS : id === 'bosch_radar' ? PCB_DEMO_BOSCH_RADAR : PCB_DEMO_ECU;
  injectPCBImagePanel();
  el('export-all-pdf-btn').style.display = '';
  el('pcb-img-results')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
};

function injectPCBImagePanel(): void {
  const resultsEl = el('pcb-img-results');
  if (!resultsEl || !pcbImageResult) return;
  resultsEl.innerHTML = buildPCBImagePanel(pcbImageResult);

  el('pcb-apply-fab-btn')?.addEventListener('click', () => applyPCBImageToFab());
  el('pcb-apply-pcba-btn')?.addEventListener('click', () => applyPCBImageToPCBA());
  el('pcb-save-lib-btn')?.addEventListener('click', () => savePCBResultToLibrary());

  // Targeted re-capture: drop new close-ups into the Close-up 1-3 slots (fall
  // back to replacing the last one when all are taken) and re-run the analysis.
  // The server caches by image hash, so a new photo always yields a fresh pass.
  const recapInput = el<HTMLInputElement>('pcb-recapture-input');
  el('pcb-recapture-add')?.addEventListener('click', () => recapInput?.click());
  recapInput?.addEventListener('change', () => {
    const files = Array.from(recapInput?.files ?? []);
    if (!files.length || !_pcbSetSlot) return;
    const placed: string[] = [];
    for (const f of files) {
      let idx = pcbImageFiles.findIndex((s, i) => i >= 2 && s === null);
      if (idx === -1) idx = 4;
      _pcbSetSlot(idx, f);
      placed.push(`Close-up ${idx - 1}`);
    }
    const status = el('pcb-recapture-status');
    if (status) status.textContent = `${placed.join(', ')} added — click Re-analyze`;
  });
  el('pcb-recapture-rerun')?.addEventListener('click', () => {
    if (!pcbImageFiles.some(Boolean)) { showToast('Add at least one photo first.', 'warning'); return; }
    void analyzePCBImages();
  });
  el('pcb-clear-btn')?.addEventListener('click', () => {
    pcbImageResult = null;
    pcbImageFiles = [null, null, null, null, null];
    pcbImageDataURL = null;
    pcbUploadedImages = [];
    if (_pcbVolumeChart) { _pcbVolumeChart.destroy(); _pcbVolumeChart = null; }
    injectPCBDemoCards();
  });

  // Feature wiring (Phase 1-2)
  el('pcb-export-csv-btn')?.addEventListener('click', () => { if (pcbImageResult) exportPCBAnalysisCSV(pcbImageResult); });
  el('pcb-export-excel-btn')?.addEventListener('click', () => { if (pcbImageResult) exportPCBAnalysisExcel(pcbImageResult); });
  el('pcb-export-pdf-btn')?.addEventListener('click', () => { if (pcbImageResult) exportPCBAnalysisPrint(pcbImageResult); });
  if (pcbImageResult) {
    wireScenarioBuilder(pcbImageResult);
    wireRFQTracker(pcbImageResult);
    wireBoardAnnotation(pcbImageResult);
    drawVolumeCurveChart(pcbImageResult);
  }

  // Enable live pricing on every identified part number in the BOM. The OCR
  // icMarkings list is frequently empty even when the BOM has real MPNs — gating
  // solely on it left the button permanently greyed. Union both, keep plausible MPNs.
  const bomMPNs = (pcbImageResult.bom ?? [])
    .map(it => (it.partNumber ?? '').trim())
    .filter(pn => pn.length >= 3 && /\d/.test(pn));
  const ocrMPNs = (pcbImageResult.ocrExtraction?.icMarkings ?? []).map(s => s.trim()).filter(Boolean);
  const priceableMPNs = Array.from(new Set([...bomMPNs, ...ocrMPNs]));
  const liveFetchBtn = document.getElementById('pcb-live-fetch-btn') as HTMLButtonElement | null;
  const liveStatusEl = document.getElementById('pcb-live-status');
  if (liveFetchBtn) {
    if (priceableMPNs.length > 0) {
      liveFetchBtn.disabled = false;
      liveFetchBtn.title = `Fetch live prices for ${priceableMPNs.length} part number${priceableMPNs.length === 1 ? '' : 's'}`;
      liveFetchBtn.onclick = () => void fetchLivePricingForBOM(priceableMPNs);   // onclick (not addEventListener) — no stacking across re-renders
      if (liveStatusEl && !liveStatusEl.textContent) {
        liveStatusEl.textContent = `${priceableMPNs.length} part number${priceableMPNs.length === 1 ? '' : 's'} ready — paste an API key and click Fetch Live Prices.`;
      }
    } else {
      liveFetchBtn.disabled = true;
      liveFetchBtn.onclick = null;
      if (liveStatusEl) liveStatusEl.textContent = 'No manufacturer part numbers were detected in the BOM to price.';
    }
  }

  // Edit toggle
  el('pcb-edit-toggle-btn')?.addEventListener('click', () => {
    if (pcbEditMode) {
      pcbEditMode = false;
    } else {
      // Save original values before entering edit mode (only first time)
      if (pcbImageResult && !pcbImageResult._originalAIValues) {
        pcbImageResult._originalAIValues = JSON.parse(JSON.stringify(pcbImageResult)) as PCBImageAnalysis;
      }
      pcbEditMode = true;
    }
    injectPCBImagePanel();
  });

  // Re-analyze with corrections
  el('pcb-reanalyze-btn')?.addEventListener('click', () => void reanalyzePCBWithCorrections());

  // Reset to AI values
  el('pcb-reset-ai-btn')?.addEventListener('click', () => {
    if (pcbImageResult?._originalAIValues) {
      const orig = pcbImageResult._originalAIValues;
      pcbImageResult = { ...orig };
      pcbEditMode = false;
      injectPCBImagePanel();
      showToast('Reset to original AI values', 'info');
    }
  });

  // Add BOM row
  el('pcb-clear-revision-btn')?.addEventListener('click', () => {
    if (pcbImageResult) { pcbImageResult._previousVersion = undefined; injectPCBImagePanel(); }
  });

  document.querySelectorAll<HTMLButtonElement>('.pcb-bom-pin-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx = parseInt(btn.dataset.bomIdx ?? '-1', 10);
      if (idx < 0 || !pcbImageResult) return;
      const item = pcbImageResult.bom[idx];
      if (!item) return;
      if (pcbPinnedPrices.has(idx)) {
        pcbPinnedPrices.delete(idx);
        showToast(`Price unpinned for ${item.refDes}`, 'info');
      } else {
        pcbPinnedPrices.set(idx, item.unitPriceGBP);
        showToast(`£${item.unitPriceGBP.toFixed(3)} pinned for ${item.refDes} — survives re-analyze`, 'info');
      }
      injectPCBImagePanel();
    });
  });

  el('pcb-bom-add-row-btn')?.addEventListener('click', () => {
    if (!pcbImageResult) return;
    pcbImageResult.bom.push({ refDes: '', componentType: 'passive_0402', description: 'New component', pkg: '', value: '', voltage: '', qty: 1, unitPriceGBP: 0.01, moq: 1, automotive: false, highCost: false });
    injectPCBImagePanel();
  });

  // BOM delete row buttons
  document.querySelectorAll<HTMLButtonElement>('.pcb-bom-delete-row').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx = parseInt(btn.dataset.bomIdx ?? '-1', 10);
      if (pcbImageResult && idx >= 0) {
        pcbImageResult.bom.splice(idx, 1);
        injectPCBImagePanel();
      }
    });
  });
}

async function fetchLivePricingForBOM(icMarkings: string[]): Promise<void> {
  const provider = (document.getElementById('pcb-live-provider') as HTMLSelectElement)?.value ?? 'octopart';
  const apiKey = (document.getElementById('pcb-live-api-key') as HTMLInputElement)?.value?.trim() ?? '';
  const statusEl = document.getElementById('pcb-live-status');
  const fetchBtn = document.getElementById('pcb-live-fetch-btn') as HTMLButtonElement | null;

  if (!apiKey) {
    if (statusEl) statusEl.textContent = '⚠ Please enter an API key first.';
    return;
  }
  if (fetchBtn) { fetchBtn.disabled = true; fetchBtn.textContent = '⏳ Fetching…'; }
  if (statusEl) statusEl.textContent = `Querying ${provider} for ${icMarkings.length} parts…`;

  try {
    const resp = await fetch('/api/pcb/live-pricing', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ partNumbers: icMarkings, provider, apiKey, qty: 100 }),
    });
    const data = await resp.json() as { success?: boolean; prices?: Array<{ mpn: string; unitPriceGBP: number; stockQty: number; distPartNumber: string; description: string }>; error?: string };
    if (!resp.ok || data.error) throw new Error(data.error ?? resp.statusText);

    const prices = data.prices ?? [];
    if (prices.length === 0) {
      // A valid request that returns nothing almost always means the key/token was
      // rejected (Octopart needs a Nexar OAuth access token, not a plain key) or the
      // MPNs weren't recognised — surface that instead of a misleading "success".
      const hint = provider === 'octopart' ? ' Octopart/Nexar needs a valid access token (not a plain API key).' : '';
      if (statusEl) statusEl.textContent = `⚠ 0/${icMarkings.length} priced — check your ${provider} API key/token is valid.${hint}`;
      showToast(`No live prices returned from ${provider} — verify your API key/token`, 'warning');
      return;
    }
    if (statusEl) statusEl.textContent = `✓ Live prices fetched for ${prices.length}/${icMarkings.length} parts.`;

    // Update BOM table rows with live prices
    if (pcbImageResult && prices.length > 0) {
      const priceMap = new Map(prices.map(p => [p.mpn.toUpperCase(), p]));
      pcbImageResult.bom = pcbImageResult.bom.map(item => {
        const live = item.partNumber ? priceMap.get(item.partNumber.toUpperCase()) : undefined;
        if (live) return { ...item, unitPriceGBP: live.unitPriceGBP, lineConf: 0.95, ocrExtracted: true };
        return item;
      });
      injectPCBImagePanel();
      showToast(`Live prices updated for ${prices.length} components from ${provider}`, 'info');
    }
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    if (statusEl) statusEl.textContent = `⚠ Error: ${msg.slice(0, 120)}`;
    showToast(`Live pricing failed: ${msg.slice(0, 80)}`, 'error');
  } finally {
    if (fetchBtn) { fetchBtn.disabled = false; fetchBtn.textContent = 'Fetch Live Prices'; }
  }
}

function collectPCBEditsFromDOM(): { correctedSpec: PCBImageAnalysis['boardSpec']; correctedAssembly: PCBImageAnalysis['assembly']; correctedBOM: PCBBOMItem[] } {
  const g = (id: string) => (document.getElementById(id) as HTMLInputElement | null);
  const gNum = (id: string, def: number) => parseFloat(g(id)?.value ?? '') || def;
  const gBool = (id: string) => (document.getElementById(id) as HTMLInputElement | null)?.checked ?? false;

  const r = pcbImageResult!;
  const correctedSpec: PCBImageAnalysis['boardSpec'] = {
    estimatedLayers:          Math.round(gNum('pcb-edit-layers', r.boardSpec.estimatedLayers)),
    widthMm:                  gNum('pcb-edit-width', r.boardSpec.widthMm),
    heightMm:                 gNum('pcb-edit-height', r.boardSpec.heightMm),
    surfaceFinish:            g('pcb-edit-surface')?.value ?? r.boardSpec.surfaceFinish,
    solderMaskColour:         r.boardSpec.solderMaskColour,
    silkscreenSides:          r.boardSpec.silkscreenSides,
    throughVias:              Math.round(gNum('pcb-edit-through-vias', r.boardSpec.throughVias)),
    blindVias:                Math.round(gNum('pcb-edit-blind-vias', r.boardSpec.blindVias)),
    buriedVias:               r.boardSpec.buriedVias,
    microVias:                Math.round(gNum('pcb-edit-micro-vias', r.boardSpec.microVias)),
    bgaDetected:              r.boardSpec.bgaDetected,
    minTraceSpaceMm:          r.boardSpec.minTraceSpaceMm,
    technologyType:           g('pcb-edit-tech')?.value ?? r.boardSpec.technologyType,
    hdiStructure:             g('pcb-edit-hdi')?.value ?? r.boardSpec.hdiStructure,
    impedanceControlRequired: gBool('pcb-edit-impedance'),
    copperWeightOz:           gNum('pcb-edit-copper-oz', r.boardSpec.copperWeightOz),
    qualityGrade:             g('pcb-edit-quality')?.value ?? r.boardSpec.qualityGrade,
    panelUtilisation:         r.boardSpec.panelUtilisation,
  };

  const correctedAssembly: PCBImageAnalysis['assembly'] = {
    smtPlacements:    Math.round(gNum('pcb-edit-smt', r.assembly.smtPlacements)),
    throughHoleJoints:Math.round(gNum('pcb-edit-th-joints', r.assembly.throughHoleJoints)),
    manualJoints:     Math.round(gNum('pcb-edit-manual-joints', r.assembly.manualJoints)),
    bgaCount:         Math.round(gNum('pcb-edit-bga-count', r.assembly.bgaCount)),
    complexity:       g('pcb-edit-complexity')?.value ?? r.assembly.complexity,
    reflowSides:      Math.round(gNum('pcb-edit-reflow-sides', r.assembly.reflowSides)),
    aoiRequired:      gBool('pcb-edit-aoi'),
    ictTimeSec:       gNum('pcb-edit-ict-time', r.assembly.ictTimeSec),
  };

  // Collect BOM edits from table
  const correctedBOM: PCBBOMItem[] = r.bom.map((item, i) => {
    const qtyInput = document.querySelector<HTMLInputElement>(`.pcb-edit-bom-qty[data-bom-idx="${i}"]`);
    const priceInput = document.querySelector<HTMLInputElement>(`.pcb-edit-bom-price[data-bom-idx="${i}"]`);
    return {
      ...item,
      qty: Math.round(parseFloat(qtyInput?.value ?? '') || item.qty),
      unitPriceGBP: parseFloat(priceInput?.value ?? '') || item.unitPriceGBP,
    };
  });

  return { correctedSpec, correctedAssembly, correctedBOM };
}

async function reanalyzePCBWithCorrections(): Promise<void> {
  if (!pcbImageResult || pcbImageLoading) return;
  const { correctedSpec, correctedAssembly, correctedBOM } = collectPCBEditsFromDOM();

  const reanalyzeBtn = el<HTMLButtonElement>('pcb-reanalyze-btn');
  if (reanalyzeBtn) { reanalyzeBtn.disabled = true; reanalyzeBtn.textContent = '⏳ Re-analyzing…'; }
  pcbImageLoading = true;

  const apiKey = (document.querySelector<HTMLInputElement>('#api-key-input'))?.value?.trim()
    ?? sessionStorage.getItem('cv_api_key') ?? '';

  const selectedCountry = (document.getElementById('pcb-mfg-country') as HTMLSelectElement)?.value ?? 'cn';
  const orderQty = (document.getElementById('pcb-order-qty') as HTMLInputElement)?.value ?? '100';

  const formData = new FormData();
  // Same balanced-resolution rule as the initial analysis: 1600 px default,
  // 2576 px only under Deep analysis (keeps image tokens ~3× lower otherwise).
  const deepHiRes = (document.getElementById('pcb-deep-analysis') as HTMLInputElement | null)?.checked ?? false;
  const activeFiles = pcbImageFiles.filter((f): f is File => f !== null);
  const uploadFiles = await Promise.all(activeFiles.map(f => downscaleImageForUpload(f, deepHiRes ? 2576 : 1600)));
  uploadFiles.forEach(f => formData.append('pcbImages', f));
  if (activeFiles.length > 0) {
    formData.append('pcbImageLabels', JSON.stringify(
      pcbImageFiles.map((f, i) => f ? ['Top side','Bottom side','Close-up 1','Close-up 2','Close-up 3'][i] : null).filter(Boolean)
    ));
  }
  formData.append('correctedSpec', JSON.stringify(correctedSpec));
  formData.append('correctedBOM', JSON.stringify(correctedBOM));
  formData.append('correctedAssembly', JSON.stringify(correctedAssembly));
  formData.append('domain', pcbImageResult.stage1Classification?.domain ?? 'general');
  formData.append('ocrMarkings', JSON.stringify(pcbImageResult.ocrExtraction?.icMarkings ?? []));
  formData.append('country', selectedCountry);
  formData.append('orderQty', orderQty);
  formData.append('deepAnalysis', String((document.getElementById('pcb-deep-analysis') as HTMLInputElement | null)?.checked ?? false));

  try {
    const resp = await fetch('/api/pcb/reanalyze', {
      method: 'POST',
      headers: apiKey ? { 'x-api-key': apiKey } : {},
      body: formData,
    });
    if (!resp.ok) {
      const err = await resp.json().catch(() => ({ error: resp.statusText })) as { error: string };
      throw new Error(err.error ?? resp.statusText);
    }
    const data = await resp.json() as {
      success: boolean;
      analysis: PCBImageAnalysis;
      selectedCountry?: string;
      selectedCountryBreakdown?: PCBCountryBreakdown;
      countryComparison?: PCBCountryBreakdown[];
      volumeCurves?: Record<string, VolumeCurvePoint[]>;
      complexityScore?: PCBComplexityScore;
      confidenceBand?: PCBConfidenceBand;
      volumeMultiplier?: number;
      sanityWarnings?: SanityWarning[];
      npiBreakdown?: NPIBreakdown;
      livePriceHits?: number;
      automotiveNRE?: AutomotiveNRE;
      automotiveGradeEnforcedCount?: number;
      singleSourceWarnings?: SingleSourceWarning[];
      conformalCoatingCost?: number;
      automotiveAssemblyCost?: AutomotiveAssemblyCost;
      automotiveFabAdjustment?: AutomotiveFabAdjustment;
      bomCompleteness?: BOMCompletenessResult;
      programPricing?: ProgramPricingResult;
    };

    // Compute cost deltas (new total - original total per country)
    const costDeltas: Record<string, number> = {};
    const origComparison = pcbImageResult._originalAIValues?._countryComparison ?? pcbImageResult._countryComparison ?? [];
    const origMap = new Map(origComparison.map(c => [c.countryId, c.totalPerBoard]));
    (data.countryComparison ?? []).forEach(c => {
      const orig = origMap.get(c.countryId);
      if (orig !== undefined) costDeltas[c.countryId] = c.totalPerBoard - orig;
    });

    const originalAIValues = pcbImageResult._originalAIValues ?? JSON.parse(JSON.stringify(pcbImageResult)) as PCBImageAnalysis;

    if (!data.analysis || typeof data.analysis !== 'object') throw new Error('Re-analysis returned an empty result — your original analysis is unchanged.');
    normalizePCBPayloadForRender(data.analysis as unknown as Record<string, unknown>);
    if ((data.analysis.bom ?? []).length === 0) {
      throw new Error('Re-analysis returned no BOM lines — your original analysis is unchanged. Try again or correct the BOM rows first.');
    }
    pcbImageResult = data.analysis;
    if (pcbImageResult) {
      pcbImageResult._selectedCountry = data.selectedCountry ?? selectedCountry;
      pcbImageResult._selectedCountryBreakdown = data.selectedCountryBreakdown ?? undefined;
      pcbImageResult._countryComparison = data.countryComparison ?? [];
      pcbImageResult._volumeCurves = data.volumeCurves ?? undefined;
      if (data.complexityScore) pcbImageResult.complexityScore = data.complexityScore;
      if (data.confidenceBand) pcbImageResult._confidenceBand = data.confidenceBand;
      if (data.volumeMultiplier !== undefined) pcbImageResult._volumeMultiplier = data.volumeMultiplier;
      if (data.sanityWarnings) pcbImageResult._sanityWarnings = data.sanityWarnings;
      if (data.npiBreakdown) pcbImageResult._npiBreakdown = data.npiBreakdown;
      if (data.livePriceHits !== undefined) pcbImageResult._livePriceHits = data.livePriceHits;
      if (data.automotiveNRE) pcbImageResult._automotiveNRE = data.automotiveNRE;
      if (data.automotiveGradeEnforcedCount !== undefined) pcbImageResult._automotiveGradeEnforcedCount = data.automotiveGradeEnforcedCount;
      if (data.singleSourceWarnings) pcbImageResult._singleSourceWarnings = data.singleSourceWarnings;
      if (data.conformalCoatingCost !== undefined) pcbImageResult._conformalCoatingCost = data.conformalCoatingCost;
      if (data.automotiveAssemblyCost) pcbImageResult._automotiveAssemblyCost = data.automotiveAssemblyCost;
      if (data.automotiveFabAdjustment) pcbImageResult._automotiveFabAdjustment = data.automotiveFabAdjustment;
      if (data.bomCompleteness) pcbImageResult._bomCompleteness = data.bomCompleteness;
      if (data.programPricing) pcbImageResult._programPricing = data.programPricing;
      pcbImageResult._originalAIValues = originalAIValues;
      pcbImageResult._isReanalyzed = true;
      pcbImageResult._costDeltas = costDeltas;
    }
    pcbEditMode = false;
    injectPCBImagePanel();
    showToast('Re-analysis complete — updated with corrected data', 'info');
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    showToast(`Re-analysis failed: ${msg.slice(0, 100)}`, 'error');
    if (reanalyzeBtn) { reanalyzeBtn.disabled = false; reanalyzeBtn.textContent = '♻ Re-analyze with Corrections'; }
  } finally {
    pcbImageLoading = false;
  }
}

function buildPCBImagePanel(r: PCBImageAnalysis): string {
  const b = r.boardSpec;
  const a = r.assembly;
  const c = r.costEstimates;
  const confClass = r.confidenceLevel === 'High' ? 'score-high' : r.confidenceLevel === 'Medium' ? 'score-med' : 'score-low';

  const totalBOMLines = r.bom.length;
  const totalPlacements = a.smtPlacements;
  const totalBOMCost = c.totalBOMCostGBP.toFixed(2);

  const singleSourceRefDesSet = new Set((r._singleSourceWarnings ?? []).map(w => w.refDes));
  const bomRows = r.bom.map((item, i) => `
    <tr class="${item.highCost ? 'pcb-bom-row--high-cost' : ''}" data-bom-idx="${i}">
      <td>${i + 1}</td>
      <td>${item.refDes}</td>
      <td>${item.description}</td>
      <td>${item.pkg}</td>
      <td>${item.value}</td>
      <td>${item.voltage}</td>
      <td>${item.partNumber ? `<span style="font-size:0.68rem;font-family:monospace;background:var(--border);padding:1px 4px;border-radius:3px">${item.partNumber}${item.ocrExtracted ? ' <span title="OCR extracted" style="color:var(--green)">&#10003;</span>' : ''}</span>` : ''}${(item.lineConf !== undefined && item.lineConf < 0.6) ? ' <span title="Low confidence" style="color:orange;font-size:0.65rem">&#9888;</span>' : ''}${item.unconfirmedHighValue ? ' <span title="High-value component: part number not confirmed by OCR — price may be inaccurate" style="background:#dc2626;color:#fff;font-size:0.58rem;padding:1px 4px;border-radius:3px;font-weight:700">UNCONFIRMED</span>' : ''}${singleSourceRefDesSet.has(item.refDes) ? ' <span title="Single-source risk: limited qualified alternatives" style="background:#7c3aed;color:#fff;font-size:0.58rem;padding:1px 4px;border-radius:3px;font-weight:700">SSR</span>' : ''}</td>
      <td>${pcbEditMode ? `<input class="pcb-edit-bom-qty" data-bom-idx="${i}" type="number" min="1" value="${item.qty}" style="width:50px"/>` : String(item.qty)}</td>
      <td>${pcbEditMode ? `<input class="pcb-edit-bom-price" data-bom-idx="${i}" type="number" min="0" step="0.001" value="${item.unitPriceGBP.toFixed(3)}" style="width:65px"/>` : `&#163;${item.unitPriceGBP.toFixed(3)}${pcbPinnedPrices.has(i) ? ' <span title="Price pinned — won\'t change on re-analyze" style="color:#f59e0b;font-size:0.65rem">📌</span>' : ''}`}</td>
      <td>&#163;${(item.qty * item.unitPriceGBP).toFixed(2)}</td>
      <td>${item.automotive ? '<span class="pcb-badge pcb-badge--auto">AEC</span>' : ''}${item.highCost ? '<span class="pcb-badge pcb-badge--cost">$$</span>' : ''}${item.livePriced ? `<span class="pcb-badge" style="background:#16a34a;color:#fff" title="Live-priced from distributor">LIVE</span>` : ''}${!pcbEditMode ? `<button class="pcb-bom-pin-btn btn btn-secondary btn-sm" data-bom-idx="${i}" title="${pcbPinnedPrices.has(i) ? 'Unpin price' : 'Pin price (survives re-analyze)'}" style="font-size:0.6rem;padding:1px 4px;margin-left:2px;${pcbPinnedPrices.has(i) ? 'background:#f59e0b;color:#fff;border-color:#f59e0b' : ''}">${pcbPinnedPrices.has(i) ? '📌' : '📍'}</button>` : `<button class="pcb-bom-delete-row btn btn-secondary btn-sm" data-bom-idx="${i}" style="font-size:0.6rem;padding:1px 4px;margin-left:2px">&#128465;</button>`}</td>
    </tr>`).join('');

  const insights = r.aiInsights.map(s => `<li>${s}</li>`).join('');
  const dfm = r.dfmIssues.map(s => `<li>⚠ ${s}</li>`).join('');
  const opts = r.optimisationSuggestions.map(s => `<li>💡 ${s}</li>`).join('');
  const limits = r.analysisLimitations.map(s => `<li>${s}</li>`).join('');
  const complexityScoreHtml = r.complexityScore ? `<div class="occt-stat"><div class="occt-stat-value">${r.complexityScore.score}/100</div><div class="occt-stat-label">Complexity (${r.complexityScore.label})</div></div>
        <div class="occt-stat"><div class="occt-stat-value">Class ${r.complexityScore.ipcClass}</div><div class="occt-stat-label">IPC class</div></div>` : '';

  return `
    <div class="pcb-analysis-panel" style="${pcbEditMode ? 'border:2px solid #f59e0b;' : ''}">
      <div class="pcb-analysis-header">
        <span style="font-size:1rem">🔬</span>
        <div style="flex:1">
          <strong>${r.partName}</strong>
          <span style="font-size:0.65rem;color:var(--text-muted);margin-left:8px">PCB Image Analysis</span>
        </div>
        <span class="occt-mfg-score ${confClass}">${r.confidenceLevel} Confidence</span>
        ${r.fromCache ? '<span title="This exact photo + quantity + country was analysed before — the identical result is returned, so the should-cost is repeatable run to run." style="background:var(--info-bg,#eff6ff);color:var(--info,#2563eb);border:1px solid var(--info-border,#bfdbfe);font-size:0.6rem;padding:2px 6px;border-radius:10px;margin-left:6px;font-weight:700">&#8635; Repeat analysis — identical result</span>' : ''}
        ${r._isReanalyzed ? '<span style="background:#16a34a;color:#fff;font-size:0.6rem;padding:2px 6px;border-radius:10px;margin-left:6px">&#10003; Recalculated</span>' : ''}
        <button class="btn btn-secondary btn-sm" id="pcb-edit-toggle-btn" style="font-size:0.65rem;padding:2px 8px">${pcbEditMode ? '&#10005; Cancel Edit' : '&#9999; Edit'}</button>
        <button class="btn btn-secondary btn-sm" id="pcb-clear-btn" style="font-size:0.65rem;padding:2px 8px">&#10005; Clear</button>
      </div>

      <div style="display:flex;gap:6px;margin-top:6px">
        <button class="btn btn-secondary btn-sm" id="pcb-export-csv-btn" style="font-size:0.65rem">&#11015; Export CSV</button>
        <button class="btn btn-secondary btn-sm" id="pcb-export-excel-btn" style="font-size:0.65rem" title="Excel workbook — BOM, country comparison and all uploaded board images embedded">&#11015; Export Excel</button>
        <button class="btn btn-secondary btn-sm" id="pcb-export-pdf-btn" style="font-size:0.65rem;display:flex;align-items:center;gap:3px"><svg viewBox="0 0 16 16" width="11" height="11" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 12H3a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1h7l3 3v6a1 1 0 0 1-1 1h-1"/><polyline points="4 9 4 16 12 16 12 9"/><line x1="8" y1="4" x2="8" y2="12"/><polyline points="5 9 8 12 11 9"/></svg> Export PDF</button>
      </div>

      ${pcbEditMode ? `<div id="pcb-edit-actions" style="display:flex;gap:8px;margin-top:6px;padding:8px;background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.3);border-radius:6px;align-items:center">
        <span style="font-size:0.72rem;color:#f59e0b;flex:1">&#9999; Edit mode — modify spec, assembly, or BOM then re-analyze</span>
        <button class="btn btn-primary btn-sm" id="pcb-reanalyze-btn" style="font-size:0.65rem">&#9851; Re-analyze with Corrections</button>
        <button class="btn btn-secondary btn-sm" id="pcb-reset-ai-btn" style="font-size:0.65rem" ${!r._originalAIValues ? 'disabled' : ''}>&#8634; Reset to AI values</button>
      </div>` : ''}

      ${pcbEditMode ? `<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-top:8px;padding:10px;background:var(--card-bg);border-radius:6px;border:1px solid var(--border)">
        <div style="grid-column:1/-1;font-size:0.72rem;font-weight:700;color:var(--text-secondary);margin-bottom:4px">Board Spec</div>
        <label style="font-size:0.68rem">Layers<br/><input type="number" id="pcb-edit-layers" min="1" value="${b.estimatedLayers}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Width (mm)<br/><input type="number" id="pcb-edit-width" min="0" value="${b.widthMm}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Height (mm)<br/><input type="number" id="pcb-edit-height" min="0" value="${b.heightMm}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Surface Finish<br/><select id="pcb-edit-surface"><option value="hasl" ${b.surfaceFinish==='hasl'?'selected':''}>HASL</option><option value="hasl_lf" ${b.surfaceFinish==='hasl_lf'?'selected':''}>HASL LF</option><option value="enig" ${b.surfaceFinish==='enig'?'selected':''}>ENIG</option><option value="osp" ${b.surfaceFinish==='osp'?'selected':''}>OSP</option><option value="enepig" ${b.surfaceFinish==='enepig'?'selected':''}>ENEPIG</option><option value="iteq" ${b.surfaceFinish==='iteq'?'selected':''}>ITEQ</option></select></label>
        <label style="font-size:0.68rem">Through Vias<br/><input type="number" id="pcb-edit-through-vias" min="0" value="${b.throughVias}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Blind Vias<br/><input type="number" id="pcb-edit-blind-vias" min="0" value="${b.blindVias}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Micro Vias<br/><input type="number" id="pcb-edit-micro-vias" min="0" value="${b.microVias}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Quality Grade<br/><select id="pcb-edit-quality"><option value="consumer" ${b.qualityGrade==='consumer'?'selected':''}>Consumer</option><option value="industrial" ${b.qualityGrade==='industrial'?'selected':''}>Industrial</option><option value="auto_grade2" ${b.qualityGrade==='auto_grade2'?'selected':''}>Auto Grade 2</option><option value="auto_grade1" ${b.qualityGrade==='auto_grade1'?'selected':''}>Auto Grade 1</option><option value="aerospace" ${b.qualityGrade==='aerospace'?'selected':''}>Aerospace</option></select></label>
        <label style="font-size:0.68rem">Technology<br/><select id="pcb-edit-tech"><option value="FR4_STD" ${b.technologyType==='FR4_STD'?'selected':''}>FR4 Std</option><option value="FR4_HTg" ${b.technologyType==='FR4_HTg'?'selected':''}>FR4 HTg</option><option value="HDI_RIGID" ${b.technologyType==='HDI_RIGID'?'selected':''}>HDI Rigid</option><option value="RIGID_FLEX" ${b.technologyType==='RIGID_FLEX'?'selected':''}>Rigid-Flex</option><option value="RF_MICRO" ${b.technologyType==='RF_MICRO'?'selected':''}>RF Micro</option></select></label>
        <label style="font-size:0.68rem">HDI Structure<br/><select id="pcb-edit-hdi"><option value="none" ${b.hdiStructure==='none'?'selected':''}>None</option><option value="1plus_n_plus1" ${b.hdiStructure==='1plus_n_plus1'?'selected':''}>1+N+1</option><option value="2plus_n_plus2" ${b.hdiStructure==='2plus_n_plus2'?'selected':''}>2+N+2</option><option value="any_layer" ${b.hdiStructure==='any_layer'?'selected':''}>Any Layer</option></select></label>
        <label style="font-size:0.68rem">Impedance Ctrl<br/><input type="checkbox" id="pcb-edit-impedance" ${b.impedanceControlRequired?'checked':''}/></label>
        <label style="font-size:0.68rem">Copper (oz)<br/><input type="number" id="pcb-edit-copper-oz" min="0" step="0.5" value="${b.copperWeightOz}" style="width:60px"/></label>
        <div style="grid-column:1/-1;font-size:0.72rem;font-weight:700;color:var(--text-secondary);margin-top:8px;margin-bottom:4px">Assembly</div>
        <label style="font-size:0.68rem">SMT Placements<br/><input type="number" id="pcb-edit-smt" min="0" value="${a.smtPlacements}" style="width:60px"/></label>
        <label style="font-size:0.68rem">TH Joints<br/><input type="number" id="pcb-edit-th-joints" min="0" value="${a.throughHoleJoints}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Manual Joints<br/><input type="number" id="pcb-edit-manual-joints" min="0" value="${a.manualJoints}" style="width:60px"/></label>
        <label style="font-size:0.68rem">BGA Count<br/><input type="number" id="pcb-edit-bga-count" min="0" value="${a.bgaCount}" style="width:60px"/></label>
        <label style="font-size:0.68rem">Complexity<br/><select id="pcb-edit-complexity"><option value="low" ${a.complexity==='low'?'selected':''}>Low</option><option value="medium" ${a.complexity==='medium'?'selected':''}>Medium</option><option value="high" ${a.complexity==='high'?'selected':''}>High</option><option value="very_high" ${a.complexity==='very_high'?'selected':''}>Very High</option></select></label>
        <label style="font-size:0.68rem">Reflow Sides<br/><input type="number" id="pcb-edit-reflow-sides" min="1" max="2" value="${a.reflowSides}" style="width:60px"/></label>
        <label style="font-size:0.68rem">AOI Required<br/><input type="checkbox" id="pcb-edit-aoi" ${a.aoiRequired?'checked':''}/></label>
        <label style="font-size:0.68rem">ICT Time (s)<br/><input type="number" id="pcb-edit-ict-time" min="0" value="${a.ictTimeSec}" style="width:60px"/></label>
      </div>` : `<div class="pcb-stat-grid">
        <div class="occt-stat"><div class="occt-stat-value">${b.estimatedLayers}</div><div class="occt-stat-label">Layers</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${b.widthMm}&#xD7;${b.heightMm}</div><div class="occt-stat-label">Board (mm)</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${b.technologyType.replace('_', ' ')}</div><div class="occt-stat-label">Technology</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${b.surfaceFinish.toUpperCase()}</div><div class="occt-stat-label">Surface finish</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${b.throughVias + b.blindVias + b.microVias}</div><div class="occt-stat-label">Total vias</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${b.qualityGrade.replace('_', ' ')}</div><div class="occt-stat-label">Quality grade</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${totalPlacements}</div><div class="occt-stat-label">SMT placements</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${a.throughHoleJoints}</div><div class="occt-stat-label">TH joints</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${a.complexity}</div><div class="occt-stat-label">Assembly complexity</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${a.reflowSides === 2 ? 'Double' : 'Single'}</div><div class="occt-stat-label">Reflow sides</div></div>
        <div class="occt-stat"><div class="occt-stat-value">&#163;${c.pcbFabGBP.min.toFixed(2)}–&#163;${c.pcbFabGBP.max.toFixed(2)}</div><div class="occt-stat-label">PCB fab est.</div></div>
        <div class="occt-stat"><div class="occt-stat-value">&#163;${totalBOMCost}</div><div class="occt-stat-label">BOM total${r._volumeMultiplier && r._volumeMultiplier !== 1.0 ? ` <span title="Volume-adjusted from 100K baseline (×${r._volumeMultiplier.toFixed(2)})" style="font-size:0.58rem;background:var(--accent);color:#fff;padding:1px 4px;border-radius:3px">VOL ×${r._volumeMultiplier.toFixed(2)}</span>` : ''}</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${r.stage1Classification?.domain?.replace(/_/g,' ') ?? 'general'}</div><div class="occt-stat-label">Board domain</div></div>
        <div class="occt-stat"><div class="occt-stat-value">${r.ocrExtraction?.icMarkings?.length ?? 0}</div><div class="occt-stat-label">ICs identified</div></div>
        ${r._asilLevel && r._asilLevel !== 'Unknown' ? `<div class="occt-stat"><div class="occt-stat-value" style="color:${r._asilLevel==='ASIL-D'?'#dc2626':r._asilLevel==='ASIL-C'?'#ea580c':r._asilLevel==='ASIL-B'?'#d97706':'#2563eb'}">${r._asilLevel}</div><div class="occt-stat-label">ISO 26262 ASIL</div></div>` : ''}
        ${r._conformalCoatingCost && r._conformalCoatingCost > 0 ? `<div class="occt-stat"><div class="occt-stat-value">&#163;${r._conformalCoatingCost.toFixed(0)}</div><div class="occt-stat-label">Conformal coat</div></div>` : ''}
        ${complexityScoreHtml}
      </div>`}

      ${r._confidenceBand ? (() => {
        const cb = r._confidenceBand!;
        const clr = (l: string) => l === 'High' ? '#16a34a' : l === 'Medium' ? '#d97706' : '#dc2626';
        const ucBadge = cb.unconfirmedHighValueCount > 0
          ? `<span style="background:#dc2626;color:#fff;font-size:0.6rem;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">⚠ ${cb.unconfirmedHighValueCount} UNCONFIRMED IC${cb.unconfirmedHighValueCount > 1 ? 's' : ''}</span>`
          : '';
        const volNote = cb.volumeMultiplier !== 1.0
          ? `<span style="font-size:0.65rem;color:var(--text-muted);margin-left:6px">Volume factor ×${cb.volumeMultiplier.toFixed(2)} applied to 100K baseline</span>`
          : '';
        return `<div style="margin-top:8px;padding:10px 12px;background:var(--card-bg);border:1px solid var(--border);border-radius:8px;font-size:0.72rem">
          <div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">
            <strong style="font-size:0.74rem">Cost Confidence Band</strong>
            <span style="background:${clr(cb.overallLabel)};color:#fff;font-size:0.6rem;padding:1px 6px;border-radius:10px;font-weight:700">${cb.overallLabel}</span>
            ${ucBadge}${volNote}
          </div>
          <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px">
            <div style="padding:8px;background:rgba(0,0,0,0.04);border-radius:6px">
              <div style="font-size:0.65rem;color:var(--text-muted);margin-bottom:4px">BOM Components <span style="background:${clr(cb.bomConfidenceLabel)};color:#fff;font-size:0.56rem;padding:0 4px;border-radius:8px">${cb.bomConfidenceLabel}</span></div>
              <div style="font-size:0.8rem;font-weight:700">&#163;${cb.bomCostMid.toFixed(2)}</div>
              <div style="font-size:0.62rem;color:var(--text-muted)">&#163;${cb.bomCostLow.toFixed(2)} – &#163;${cb.bomCostHigh.toFixed(2)}</div>
              <div style="font-size:0.6rem;color:var(--text-muted);margin-top:2px">${cb.ocrConfirmedCount} OCR confirmed · ${Math.round(cb.weightedBOMConfidence*100)}% avg conf</div>
              ${(() => {
                const ce = r.costEstimates as unknown as { confirmedBOMCostGBP?: number; unverifiedBOMCostGBP?: number };
                const nv = (r as unknown as { needsVerificationCount?: number; _needsVerificationCount?: number });
                const nvc = nv.needsVerificationCount ?? nv._needsVerificationCount ?? 0;
                if (ce && typeof ce.unverifiedBOMCostGBP === 'number' && ce.unverifiedBOMCostGBP > 0.01) {
                  return `<div style="font-size:0.58rem;margin-top:3px;line-height:1.3">`
                    + `<span style="color:#0e9f6e">&#10003; &#163;${(ce.confirmedBOMCostGBP ?? 0).toFixed(2)} confirmed</span>`
                    + ` · <span style="color:#b45309">&#163;${ce.unverifiedBOMCostGBP.toFixed(2)} to verify${nvc ? ` (${nvc})` : ''}</span></div>`;
                }
                return '';
              })()}
            </div>
            <div style="padding:8px;background:rgba(0,0,0,0.04);border-radius:6px">
              <div style="font-size:0.65rem;color:var(--text-muted);margin-bottom:4px">PCB Fabrication <span style="background:${clr(cb.fabConfidenceLabel)};color:#fff;font-size:0.56rem;padding:0 4px;border-radius:8px">${cb.fabConfidenceLabel}</span></div>
              <div style="font-size:0.8rem;font-weight:700">&#163;${cb.fabCostMid.toFixed(2)}</div>
              <div style="font-size:0.62rem;color:var(--text-muted)">&#163;${cb.fabCostLow.toFixed(2)} – &#163;${cb.fabCostHigh.toFixed(2)}</div>
            </div>
            <div style="padding:8px;background:rgba(0,0,0,0.04);border-radius:6px;border:1px solid var(--border)">
              <div style="font-size:0.65rem;color:var(--text-muted);margin-bottom:4px">Total Range <span style="background:${clr(cb.overallLabel)};color:#fff;font-size:0.56rem;padding:0 4px;border-radius:8px">${cb.overallLabel}</span></div>
              <div style="font-size:0.8rem;font-weight:700;color:var(--accent)">&#163;${cb.totalMid.toFixed(2)}</div>
              <div style="font-size:0.62rem;color:var(--text-muted)">&#163;${cb.totalLow.toFixed(2)} – &#163;${cb.totalHigh.toFixed(2)}</div>
            </div>
          </div>
        </div>`;
      })() : ''}

      ${(() => {
        // Learn-from-actuals: once ≥3 real PCBA quotes are logged, show the
        // bias-corrected estimate so the should-cost self-calibrates to reality.
        const cal = computeCalibration(getCalibrationRecords(), 'pcba');
        if (!cal.applied) return '';
        const est = pcbHeadlineTotal(r);
        const calibrated = applyCalibration(est, cal);
        const dir = cal.biasFactor < 1 ? 'lower' : 'higher';
        return `<div style="margin-top:6px;padding:8px 11px;background:rgba(47,95,224,0.06);border:1px solid rgba(47,95,224,0.25);border-radius:8px;font-size:0.68rem">
          <strong style="color:var(--accent)">Calibrated estimate: &#163;${calibrated.toFixed(2)}</strong>
          <span style="color:var(--text-muted)"> · learned &times;${cal.biasFactor} (${dir}) from ${cal.n} logged actuals · MAPE ${cal.mapePct}% &rarr; ${cal.calibratedMapePct}%</span>
        </div>`;
      })()}

      ${(() => {
        // Targeted re-capture loop: name the exact components whose markings the
        // AI could not read, and offer an inline close-up upload + re-analyze so
        // the user doesn't have to guess what to photograph.
        const uc = (r.bom ?? []).filter(b => b.unconfirmedHighValue);
        if (!uc.length) return '';
        const rows = uc.slice(0, 8).map(b => `
          <li style="margin:3px 0;line-height:1.45">
            <span style="font-family:var(--font-mono);font-weight:700;background:rgba(220,38,38,0.12);color:#dc2626;padding:0 5px;border-radius:4px">${escHtml(b.refDes || '?')}</span>
            <span style="color:var(--text-primary)">${escHtml(b.description || b.componentType || 'component')}</span>
            <span style="color:var(--text-muted)">${b.pkg ? `· ${escHtml(b.pkg)}` : ''}${b.lineTotalGBP ? ` · est. £${b.lineTotalGBP.toFixed(2)}/board` : ''}</span>
          </li>`).join('');
        return `<div id="pcb-recapture-panel" style="margin-top:8px;padding:11px 13px;background:rgba(220,38,38,0.05);border:1px solid rgba(220,38,38,0.3);border-left:3px solid #dc2626;border-radius:8px">
          <div style="font-size:0.76rem;font-weight:700;color:var(--text-primary)">🎯 Improve accuracy — ${uc.length} component${uc.length > 1 ? 's' : ''} need${uc.length > 1 ? '' : 's'} a close-up</div>
          <div style="font-size:0.68rem;color:var(--text-secondary);margin-top:3px;line-height:1.5">The AI priced these high-value parts without reading their markings. Take a close, glare-free photo where the printed part numbers are legible, add it below, and re-analyze — the second pass will identify and re-price them.</div>
          <ul style="margin:7px 0 0;padding-left:16px;font-size:0.7rem">${rows}</ul>
          ${uc.length > 8 ? `<div style="font-size:0.64rem;color:var(--text-muted);margin-top:2px">…and ${uc.length - 8} more (flagged UNCONFIRMED in the BOM table below)</div>` : ''}
          <div style="display:flex;gap:8px;margin-top:9px;flex-wrap:wrap;align-items:center">
            <input type="file" id="pcb-recapture-input" accept="image/jpeg,image/png,image/webp" multiple style="display:none"/>
            <button class="btn btn-secondary btn-sm" id="pcb-recapture-add" style="font-size:0.7rem">📷 Add close-up photo</button>
            <button class="btn btn-primary btn-sm" id="pcb-recapture-rerun" style="font-size:0.7rem">↻ Re-analyze with close-ups</button>
            <span id="pcb-recapture-status" style="font-size:0.66rem;color:var(--text-muted)"></span>
          </div>
        </div>`;
      })()}

      <div class="pcb-apply-row">
        <button class="btn btn-primary btn-sm" id="pcb-apply-fab-btn">⚡ Apply to PCB Fab Form</button>
        <button class="btn btn-primary btn-sm" id="pcb-apply-pcba-btn">⚡ Apply to PCBA BOM + Assembly</button>
        <button class="btn btn-secondary btn-sm" id="pcb-save-lib-btn" title="Save this PCB should-cost into the Parts Library so it appears in your dashboard and saved results">&#11014; Save to Library</button>
      </div>

      <div class="pcb-analysis-section">
        <div class="pcb-analysis-section-title">📋 Bill of Materials (${totalBOMLines} lines · ${totalPlacements} placements)</div>
        <div class="pcb-bom-wrap">
          <table class="pcb-bom-table">
            <thead><tr><th>#</th><th>Ref Des</th><th>Description</th><th>Pkg</th><th>Value</th><th>Voltage</th><th>Part No.</th><th>Qty</th><th>Unit &#163;</th><th>Ext &#163;</th><th>Flags${pcbEditMode ? '/Del' : ''}</th></tr></thead>
            <tbody>${bomRows}</tbody>
            <tfoot><tr><td colspan="9" style="text-align:right;font-weight:700">Total BOM Cost</td><td colspan="2" style="font-weight:700;color:var(--accent)">&#163;${totalBOMCost}</td></tr></tfoot>
          </table>
          ${pcbEditMode ? '<button class="btn btn-secondary btn-sm" id="pcb-bom-add-row-btn" style="margin-top:6px;font-size:0.65rem">&#65291; Add Row</button>' : ''}
        </div>
      </div>

      ${buildASILBadge(r)}
      ${buildCountryBreakdownSection(r)}
      ${buildCostDriverChart(r)}
      ${buildNPISection(r)}
      ${buildConfidenceRoadmap(r)}
      ${buildSanityWarningsBanner(r)}
      ${buildAutomotiveNRESection(r)}
      ${buildAutomotiveAssemblySection(r)}
      ${buildAutomotiveFabSection(r)}
      ${buildSingleSourceWarnings(r)}
      ${buildBOMCompletenessSection(r)}
      ${buildProgramPricingSection(r)}
      ${buildBenchmarkComparison(r)}
      ${buildRevisionComparison(r)}

      ${buildVolumeCurveSection(r)}

      ${buildRiskRadarSection(r)}

      ${buildScenarioBuilderSection(r)}

      ${buildBoardAnnotationSection()}

      ${buildRFQTrackerSection(r)}

      <div class="pcb-insights-grid">
        <div class="pcb-analysis-section">
          <div class="pcb-analysis-section-title">💡 AI Insights</div>
          <ul class="pcb-insight-list">${insights}</ul>
        </div>
        <div class="pcb-analysis-section">
          <div class="pcb-analysis-section-title">⚠ DFM / DFA Issues</div>
          <ul class="pcb-insight-list pcb-insight-list--warn">${dfm}</ul>
        </div>
        <div class="pcb-analysis-section">
          <div class="pcb-analysis-section-title">🔑 High-Cost Components</div>
          <ul class="pcb-insight-list pcb-insight-list--cost">${r.highCostComponents.map(s => `<li>${s}</li>`).join('')}</ul>
        </div>
        <div class="pcb-analysis-section">
          <div class="pcb-analysis-section-title">✂ Optimisation Opportunities</div>
          <ul class="pcb-insight-list pcb-insight-list--opt">${opts}</ul>
        </div>
      </div>

      <div class="pcb-analysis-section" style="margin-top:8px">
        <div class="pcb-analysis-section-title" style="color:var(--text-muted)">Analysis Limitations</div>
        <ul class="pcb-insight-list" style="color:var(--text-muted)">${limits}</ul>
      </div>
    </div>`;
}

function buildCostDriverChart(r: PCBImageAnalysis): string {
  if (!r.bom || r.bom.length === 0) return '';
  const groups = new Map<string, number>();
  for (const item of r.bom) {
    const key = item.componentType.replace(/_/g, ' ');
    groups.set(key, (groups.get(key) ?? 0) + item.qty * item.unitPriceGBP);
  }
  const sorted = [...groups.entries()].sort((a, b) => b[1] - a[1]).slice(0, 8);
  const total = sorted.reduce((s, [, v]) => s + v, 0);
  if (total === 0) return '';
  const bars = sorted.map(([label, val]) => {
    const pct = Math.max((val / total) * 100, 1);
    const colorMap: Record<string, string> = { 'ic bga': '#dc2626', 'ic tqfp': '#ea580c', 'ic qfn': '#d97706', 'ic soic': '#ca8a04', 'power module': '#7c3aed', 'connector smt': '#2563eb', 'through hole': '#0891b2', 'passive 0402': '#16a34a', 'passive 0603': '#15803d', 'passive 0805': '#166534' };
    const color = colorMap[label] ?? '#6b7280';
    return `<div style="display:flex;align-items:center;gap:6px;margin-bottom:3px">
      <div style="width:90px;font-size:0.62rem;text-align:right;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${label}</div>
      <div style="flex:1;background:var(--border);border-radius:3px;height:12px;overflow:hidden">
        <div style="width:${pct.toFixed(1)}%;background:${color};height:100%;border-radius:3px;transition:width 0.3s"></div>
      </div>
      <div style="width:50px;font-size:0.62rem;font-weight:600;color:var(--text)">£${val.toFixed(2)}</div>
      <div style="width:34px;font-size:0.60rem;color:var(--text-muted)">${pct.toFixed(0)}%</div>
    </div>`;
  }).join('');
  return `<div class="pcb-analysis-section">
    <div class="pcb-analysis-section-title">📊 Cost Driver Breakdown</div>
    <div style="padding:8px 4px">${bars}</div>
  </div>`;
}

function buildNPISection(r: PCBImageAnalysis): string {
  if (!r._npiBreakdown) return '';
  const n = r._npiBreakdown;
  return `<div class="pcb-analysis-section">
    <div class="pcb-analysis-section-title">NPI vs Production Cost</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;padding:8px 4px">
      <div style="padding:8px;background:rgba(220,38,38,0.07);border-radius:6px;border:1px solid rgba(220,38,38,0.2)">
        <div style="font-size:0.62rem;color:var(--text-muted);margin-bottom:4px">NPI / Prototype Run (50 units)</div>
        <div style="font-size:1rem;font-weight:700;color:#dc2626">£${n.unitCostNPI.toFixed(2)}</div>
        <div style="font-size:0.6rem;color:var(--text-muted)">per unit</div>
        <div style="font-size:0.6rem;color:var(--text-muted);margin-top:4px">includes £${n.setupPerUnit50.toFixed(2)}/unit NRE amortisation</div>
      </div>
      <div style="padding:8px;background:rgba(22,163,74,0.07);border-radius:6px;border:1px solid rgba(22,163,74,0.2)">
        <div style="font-size:0.62rem;color:var(--text-muted);margin-bottom:4px">Production (this volume)</div>
        <div style="font-size:1rem;font-weight:700;color:#16a34a">£${n.unitCostProd.toFixed(2)}</div>
        <div style="font-size:0.6rem;color:var(--text-muted)">per unit</div>
        <div style="font-size:0.6rem;color:var(--text-muted);margin-top:4px">${((n.unitCostNPI/n.unitCostProd-1)*100).toFixed(0)}% saving vs NPI rate</div>
      </div>
      <div style="padding:8px;background:var(--card-bg);border-radius:6px;border:1px solid var(--border)">
        <div style="font-size:0.62rem;color:var(--text-muted);margin-bottom:4px">One-time NRE Costs</div>
        <div style="font-size:1rem;font-weight:700">£${n.toolingTotal.toFixed(0)}</div>
        <div style="font-size:0.6rem;color:var(--text-muted)">Stencil £${n.stencilCost} + First article £${n.firstArticleCost}</div>
      </div>
    </div>
  </div>`;
}

function buildConfidenceRoadmap(r: PCBImageAnalysis): string {
  const cb = r._confidenceBand;
  if (!cb || cb.overallLabel === 'High') return '';
  const steps: string[] = [];
  if (!r._livePriceHits || r._livePriceHits === 0) steps.push('Attach a BOM file (.csv/.xml) — eliminates all AI guesswork on part numbers and pricing');
  if (cb.unconfirmedHighValueCount > 0) steps.push(`${cb.unconfirmedHighValueCount} high-value IC${cb.unconfirmedHighValueCount > 1 ? 's are' : ' is'} unconfirmed — upload a close-up image of those chips or edit their prices manually`);
  if (cb.fabConfidenceLabel === 'Low') steps.push('OCR quality was low — upload a higher-resolution image or a top-side close-up to improve fab spec extraction');
  if (cb.weightedBOMConfidence < 0.70) steps.push('Many BOM lines have low AI confidence — enter the Re-analyze flow and correct any misidentified components');
  if (r._volumeMultiplier && r._volumeMultiplier > 3) steps.push(`Volume is very low (${r._volumeMultiplier.toFixed(1)}× cost uplift vs 100K) — prices at this volume are distributor-dependent; request actual supplier quotes`);
  if (steps.length === 0) return '';
  return `<div class="pcb-analysis-section">
    <div class="pcb-analysis-section-title">How to Improve Confidence</div>
    <div style="padding:8px 4px">
      <ol style="margin:0;padding-left:18px;font-size:0.72rem;color:var(--text-secondary)">
        ${steps.map(s => `<li style="margin-bottom:6px">${s}</li>`).join('')}
      </ol>
    </div>
  </div>`;
}

function buildSanityWarningsBanner(r: PCBImageAnalysis): string {
  const warns = r._sanityWarnings;
  if (!warns || warns.length === 0) return '';
  const items = warns.map(w => `<div style="display:flex;gap:6px;align-items:flex-start;margin-bottom:4px">
    <span style="font-size:0.75rem">${w.severity === 'error' ? '🔴' : '🟡'}</span>
    <span style="font-size:0.68rem;color:var(--text-secondary)">${w.message}</span>
  </div>`).join('');
  return `<div style="margin-top:8px;padding:10px 12px;background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.3);border-radius:8px">
    <div style="font-size:0.72rem;font-weight:600;color:#d97706;margin-bottom:6px">⚠ AI Sanity Checks</div>
    ${items}
  </div>`;
}

function buildASILBadge(r: PCBImageAnalysis): string {
  const level = r._asilLevel;
  if (!level || level === 'Unknown') return '';
  const colors: Record<string, string> = {
    'QM': '#6b7280', 'ASIL-A': '#2563eb', 'ASIL-B': '#d97706', 'ASIL-C': '#ea580c', 'ASIL-D': '#dc2626',
  };
  const color = colors[level] ?? '#6b7280';
  const functions = r._asilSafetyFunctions ?? [];
  const fnList = functions.length > 0
    ? `<div style="margin-top:6px;font-size:0.62rem;color:var(--text-secondary)">Safety functions: ${functions.join(', ')}</div>`
    : '';
  const rationale = r._asilRationale ? `<div style="margin-top:4px;font-size:0.62rem;color:var(--text-muted);font-style:italic">${r._asilRationale}</div>` : '';
  return `<div style="margin-top:8px;padding:10px 12px;background:${color}18;border:1px solid ${color}55;border-radius:8px">
    <div style="display:flex;align-items:center;gap:8px">
      <span style="background:${color};color:#fff;font-size:0.72rem;font-weight:700;padding:2px 8px;border-radius:4px">${level}</span>
      <span style="font-size:0.72rem;font-weight:600;color:${color}">ISO 26262 Safety Integrity Level</span>
    </div>
    ${rationale}${fnList}
  </div>`;
}

function buildAutomotiveNRESection(r: PCBImageAnalysis): string {
  const nre = r._automotiveNRE;
  if (!nre || nre.totalNRE === 0) return '';
  const fmt = (n: number) => `£${n.toLocaleString('en-GB')}`;
  const enforced = r._automotiveGradeEnforcedCount ?? 0;
  const enforcedBadge = enforced > 0
    ? `<div style="margin-top:6px;padding:4px 8px;background:rgba(220,38,38,0.08);border:1px solid rgba(220,38,38,0.3);border-radius:4px;font-size:0.62rem;color:#dc2626">
        ⚠ ${enforced} component${enforced > 1 ? 's' : ''} had pricing enforced to AEC-Q automotive grade
      </div>`
    : '';
  const coating = r._conformalCoatingCost ?? 0;
  const coatingRow = coating > 0
    ? `<tr><td style="padding:3px 6px;font-size:0.68rem">Conformal coating</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(coating)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">Selective UV acrylic / polyurethane</td></tr>`
    : '';
  return `<div style="margin-top:8px;padding:10px 12px;background:rgba(234,88,12,0.06);border:1px solid rgba(234,88,12,0.25);border-radius:8px">
    <div style="font-size:0.72rem;font-weight:600;color:#ea580c;margin-bottom:8px">Automotive NRE Qualification Costs (${nre.asilLevel})</div>
    <table style="width:100%;border-collapse:collapse">
      <thead><tr>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Activity</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Estimated cost</th>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Scope</th>
      </tr></thead>
      <tbody>
        <tr><td style="padding:3px 6px;font-size:0.68rem">PPAP (Production Part Approval)</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(nre.ppapCost)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">18 PPAP elements, control plan</td></tr>
        <tr><td style="padding:3px 6px;font-size:0.68rem">FMEA (Failure Mode Analysis)</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(nre.fmeaCost)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">D-FMEA + P-FMEA per AIAG-VDA</td></tr>
        <tr><td style="padding:3px 6px;font-size:0.68rem">DVP&R (Validation & Reporting)</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(nre.dvprCost)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">Environmental, EMC, vibration tests</td></tr>
        ${nre.asilAuditCost > 0 ? `<tr><td style="padding:3px 6px;font-size:0.68rem">ISO 26262 Safety Audit</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(nre.asilAuditCost)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">ASIL classification, safety case review</td></tr>` : ''}
        ${coatingRow}
        <tr style="border-top:1px solid var(--border)"><td style="padding:4px 6px;font-size:0.72rem;font-weight:700">Total Automotive NRE</td><td style="padding:4px 6px;text-align:right;font-size:0.72rem;font-weight:700;color:#ea580c">${fmt(nre.totalNRE + coating)}</td><td></td></tr>
      </tbody>
    </table>
    ${enforcedBadge}
  </div>`;
}

function buildSingleSourceWarnings(r: PCBImageAnalysis): string {
  const warns = r._singleSourceWarnings;
  if (!warns || warns.length === 0) return '';
  const rows = warns.map(w => `<tr>
    <td style="padding:3px 6px;font-size:0.68rem;font-family:monospace">${w.refDes}</td>
    <td style="padding:3px 6px;font-size:0.62rem;color:var(--text-secondary)">${w.vendor}</td>
    <td style="padding:3px 6px;text-align:right;font-size:0.68rem">${(w.premium * 100).toFixed(0)}%</td>
    <td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">+£${w.premiumAmountGBP.toFixed(2)}</td>
  </tr>`).join('');
  return `<div style="margin-top:8px;padding:10px 12px;background:rgba(220,38,38,0.06);border:1px solid rgba(220,38,38,0.3);border-radius:8px">
    <div style="font-size:0.72rem;font-weight:600;color:#dc2626;margin-bottom:6px">⚠ Single-Source Risk Components (${warns.length})</div>
    <div style="font-size:0.62rem;color:var(--text-muted);margin-bottom:6px">These ICs have limited qualified alternatives. Supply risk premium applied to unit prices:</div>
    <table style="width:100%;border-collapse:collapse">
      <thead><tr>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Ref</th>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Sole vendor / rationale</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Premium</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Cost add</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
  </div>`;
}

function buildAutomotiveAssemblySection(r: PCBImageAnalysis): string {
  const ac = r._automotiveAssemblyCost;
  if (!ac || ac.totalAutomotiveAssemblyGBP === 0) return '';
  const fmt = (n: number) => `£${n.toFixed(2)}`;
  const rows = [
    { label: 'Base SMT assembly', val: ac.baseAssemblyGBP, note: 'IPC-A-610 Class 2 baseline' },
    { label: 'IATF 16949 line premium (+20%)', val: ac.iatfPremiumGBP, note: 'Certified automotive assembly line overhead' },
    ac.axiCostGBP > 0 ? { label: 'AXI X-ray inspection', val: ac.axiCostGBP, note: 'Mandatory for BGA solder verification' } : null,
    { label: 'Serialisation / traceability', val: ac.serialisationGBP, note: 'Laser marking + batch database entry' },
    ac.ipcClass3GBP > 0 ? { label: 'IPC-A-610 Class 3 re-inspect', val: ac.ipcClass3GBP, note: 'Tighter defect accept/reject criteria' } : null,
    ac.burnInGBP > 0 ? { label: 'Burn-in / HALT test', val: ac.burnInGBP, note: 'ASIL-mandated reliability screening' } : null,
  ].filter(Boolean) as Array<{ label: string; val: number; note: string }>;
  const tableRows = rows.map(row => `<tr><td style="padding:3px 6px;font-size:0.68rem">${row.label}</td><td style="padding:3px 6px;text-align:right;font-size:0.68rem;font-weight:600">${fmt(row.val)}</td><td style="padding:3px 6px;font-size:0.62rem;color:var(--text-muted)">${row.note}</td></tr>`).join('');
  return `<div style="margin-top:8px;padding:10px 12px;background:rgba(37,99,235,0.05);border:1px solid rgba(37,99,235,0.2);border-radius:8px">
    <div style="font-size:0.72rem;font-weight:600;color:#2563eb;margin-bottom:8px">Automotive Assembly Cost Model (IATF 16949) — +${ac.premiumPctOverStandard}% vs standard</div>
    <table style="width:100%;border-collapse:collapse">
      <thead><tr>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Cost element</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Per board</th>
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Rationale</th>
      </tr></thead>
      <tbody>${tableRows}
        <tr style="border-top:1px solid var(--border)"><td style="padding:4px 6px;font-size:0.72rem;font-weight:700">Total automotive assembly</td><td style="padding:4px 6px;text-align:right;font-size:0.72rem;font-weight:700;color:#2563eb">${fmt(ac.totalAutomotiveAssemblyGBP)}</td><td></td></tr>
      </tbody>
    </table>
  </div>`;
}

