function buildBOMCompletenessSection(r: PCBImageAnalysis): string {
  const bc = r._bomCompleteness;
  if (!bc) return '';
  const scoreColor = bc.completenessScore >= 80 ? '#16a34a' : bc.completenessScore >= 50 ? '#d97706' : '#dc2626';
  const scoreLabel = bc.completenessScore >= 80 ? 'Good' : bc.completenessScore >= 50 ? 'Partial' : 'Incomplete';
  if (bc.estimatedMissingPassiveCount === 0 && bc.completenessScore >= 80) return '';
  return `<div style="margin-top:8px;padding:10px 12px;background:rgba(0,0,0,0.03);border:1px solid var(--border);border-radius:8px">
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
      <div style="font-size:0.72rem;font-weight:600">BOM Completeness Estimate</div>
      <span style="background:${scoreColor};color:#fff;font-size:0.6rem;padding:1px 6px;border-radius:10px;font-weight:700">${bc.completenessScore}% — ${scoreLabel}</span>
    </div>
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-bottom:8px">
      <div style="text-align:center;padding:6px;background:rgba(0,0,0,0.04);border-radius:4px">
        <div style="font-size:0.8rem;font-weight:700">${bc.identifiedLineCount}</div>
        <div style="font-size:0.62rem;color:var(--text-muted)">BOM lines identified</div>
      </div>
      <div style="text-align:center;padding:6px;background:rgba(0,0,0,0.04);border-radius:4px">
        <div style="font-size:0.8rem;font-weight:700">${bc.identifiedICCount}</div>
        <div style="font-size:0.62rem;color:var(--text-muted)">ICs / active components</div>
      </div>
      <div style="text-align:center;padding:6px;background:rgba(220,38,38,0.08);border-radius:4px">
        <div style="font-size:0.8rem;font-weight:700;color:#dc2626">~${bc.estimatedMissingPassiveCount}</div>
        <div style="font-size:0.62rem;color:var(--text-muted)">Est. missing passives</div>
      </div>
    </div>
    ${bc.estimatedMissingPassiveCount > 0 ? `
    <div style="font-size:0.68rem;color:var(--text-secondary);margin-bottom:4px">Estimated missing passive breakdown:</div>
    <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:4px">
      <div style="font-size:0.62rem;padding:3px 6px;background:rgba(0,0,0,0.03);border-radius:3px">Decoupling caps: ~${bc.missingEstimateBreakdown.decouplingCaps}</div>
      <div style="font-size:0.62rem;padding:3px 6px;background:rgba(0,0,0,0.03);border-radius:3px">Pull-up/down resistors: ~${bc.missingEstimateBreakdown.pullResistors}</div>
      <div style="font-size:0.62rem;padding:3px 6px;background:rgba(0,0,0,0.03);border-radius:3px">Ferrite beads: ~${bc.missingEstimateBreakdown.ferriteBeads}</div>
      <div style="font-size:0.62rem;padding:3px 6px;background:rgba(0,0,0,0.03);border-radius:3px">ESD arrays: ~${bc.missingEstimateBreakdown.esdArrays}</div>
    </div>
    <div style="margin-top:6px;font-size:0.68rem;color:var(--text-secondary)">Estimated missing passive cost: <strong>£${bc.estimatedMissingCostGBP.toFixed(2)}</strong> (at AEC-Q grade prices)</div>
    ` : '<div style="font-size:0.68rem;color:#16a34a">Passive count looks consistent with identified IC count — BOM appears substantially complete.</div>'}
  </div>`;
}

function buildProgramPricingSection(r: PCBImageAnalysis): string {
  const pp = r._programPricing;
  if (!pp || pp.pricingTier === 'distributor_spot' || pp.savingsPct === 0) return '';
  const tierLabels: Record<string, string> = {
    blanket_order: 'Blanket Order Pricing',
    direct_contract: 'Direct Manufacturer Contract',
    tier1_contract: 'Tier-1 Automotive Contract',
    distributor_spot: 'Distributor Spot Price',
  };
  const tierColors: Record<string, string> = {
    blanket_order: '#d97706', direct_contract: '#2563eb', tier1_contract: '#16a34a', distributor_spot: '#6b7280',
  };
  const color = tierColors[pp.pricingTier] ?? '#6b7280';
  const label = tierLabels[pp.pricingTier] ?? pp.pricingTier;
  return `<div style="margin-top:8px;padding:10px 12px;background:${color}0d;border:1px solid ${color}40;border-radius:8px">
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
      <div style="font-size:0.72rem;font-weight:600;color:${color}">Program Pricing vs Spot — ${label}</div>
      <span style="background:${color};color:#fff;font-size:0.6rem;padding:1px 6px;border-radius:10px;font-weight:700">−${pp.savingsPct}%</span>
    </div>
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px">
      <div style="text-align:center;padding:8px;background:rgba(0,0,0,0.04);border-radius:4px">
        <div style="font-size:0.68rem;color:var(--text-muted);margin-bottom:2px">Distributor spot BOM</div>
        <div style="font-size:0.85rem;font-weight:700;text-decoration:line-through;color:var(--text-muted)">£${pp.spotBOMTotal.toFixed(2)}</div>
      </div>
      <div style="text-align:center;padding:8px;background:${color}15;border-radius:4px;border:1px solid ${color}30">
        <div style="font-size:0.68rem;color:${color};margin-bottom:2px">Program BOM (${Math.round(pp.annualProgramVolume/1000)}K/yr)</div>
        <div style="font-size:0.85rem;font-weight:700;color:${color}">£${pp.programBOMTotal.toFixed(2)}</div>
      </div>
      <div style="text-align:center;padding:8px;background:rgba(22,163,74,0.08);border-radius:4px">
        <div style="font-size:0.68rem;color:#16a34a;margin-bottom:2px">Saving per board</div>
        <div style="font-size:0.85rem;font-weight:700;color:#16a34a">−£${pp.savingsGBP.toFixed(2)}</div>
      </div>
    </div>
    <div style="margin-top:6px;font-size:0.62rem;color:var(--text-muted)">Assumes ~${Math.round(pp.annualProgramVolume/1000)}K annual program volume (${pp.multiplier.toFixed(2)}× spot multiplier). Actual contract terms vary.</div>
  </div>`;
}

function buildBenchmarkComparison(r: PCBImageAnalysis): string {
  const total = r.costEstimates.totalBOMCostGBP + r.costEstimates.pcbFabGBP.mid + r.costEstimates.smtAssemblyCostGBP;
  const areaCm2 = (r.boardSpec.widthMm * r.boardSpec.heightMm) / 100;
  const costPerCm2 = areaCm2 > 0 ? total / areaCm2 : 0;
  const costPerPlacement = r.assembly.smtPlacements > 0 ? total / r.assembly.smtPlacements : 0;
  // Reference benchmarks (from the 3 demo boards)
  const benchmarks = [
    { name: 'Automotive ECU', costPerCm2: 3.80, costPerPlacement: 0.78, domain: 'automotive_adas' },
    { name: 'ADAS Sensor', costPerCm2: 4.20, costPerPlacement: 0.92, domain: 'automotive_adas' },
    { name: 'RF/Radar Module', costPerCm2: 8.50, costPerPlacement: 1.85, domain: 'rf_microwave' },
    { name: 'Consumer IoT', costPerCm2: 1.20, costPerPlacement: 0.28, domain: 'consumer_iot' },
    { name: 'Industrial Control', costPerCm2: 2.80, costPerPlacement: 0.65, domain: 'industrial_control' },
  ];
  const domain = r.stage1Classification?.domain ?? 'general';
  const relevant = benchmarks.filter(b => b.domain === domain || domain === 'general').slice(0, 2);
  if (relevant.length === 0) return '';
  const rows = relevant.map(b => {
    const cm2Diff = costPerCm2 > 0 ? ((costPerCm2 / b.costPerCm2 - 1) * 100) : null;
    const placeDiff = costPerPlacement > 0 ? ((costPerPlacement / b.costPerPlacement - 1) * 100) : null;
    const sign = (v: number | null) => v == null ? '—' : (v > 0 ? `+${v.toFixed(0)}%` : `${v.toFixed(0)}%`);
    const color = (v: number | null) => v == null ? '' : v > 15 ? 'color:#dc2626' : v < -15 ? 'color:#16a34a' : 'color:#d97706';
    return `<tr>
      <td style="font-size:0.68rem;padding:3px 6px">${b.name}</td>
      <td style="font-size:0.68rem;padding:3px 6px;text-align:right">£${b.costPerCm2.toFixed(2)}/cm²</td>
      <td style="font-size:0.68rem;padding:3px 6px;text-align:right;${color(cm2Diff)}">${sign(cm2Diff)}</td>
      <td style="font-size:0.68rem;padding:3px 6px;text-align:right">£${b.costPerPlacement.toFixed(2)}/place</td>
      <td style="font-size:0.68rem;padding:3px 6px;text-align:right;${color(placeDiff)}">${sign(placeDiff)}</td>
    </tr>`;
  }).join('');
  return `<div class="pcb-analysis-section">
    <div class="pcb-analysis-section-title">📐 Benchmark Comparison</div>
    <div style="font-size:0.65rem;color:var(--text-muted);margin:4px 4px 6px">This board: £${costPerCm2.toFixed(2)}/cm² · £${costPerPlacement.toFixed(2)}/placement · vs industry benchmarks for ${domain.replace(/_/g,' ')}</div>
    <table style="width:100%;border-collapse:collapse;font-size:0.68rem">
      <thead><tr style="border-bottom:1px solid var(--border)">
        <th style="padding:3px 6px;text-align:left;font-size:0.62rem;color:var(--text-muted)">Benchmark</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Ref/cm²</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">vs this</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">Ref/place</th>
        <th style="padding:3px 6px;text-align:right;font-size:0.62rem;color:var(--text-muted)">vs this</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
  </div>`;
}

function buildRevisionComparison(r: PCBImageAnalysis): string {
  const prev = r._previousVersion;
  if (!prev) return '';
  const bomDelta = r.costEstimates.totalBOMCostGBP - prev.costEstimates.totalBOMCostGBP;
  const fabDelta = r.costEstimates.pcbFabGBP.mid - prev.costEstimates.pcbFabGBP.mid;
  const totalDelta = bomDelta + fabDelta;
  const sign = (v: number) => (v >= 0 ? `+£${v.toFixed(2)}` : `-£${Math.abs(v).toFixed(2)}`);
  const color = (v: number) => v > 0.5 ? '#dc2626' : v < -0.5 ? '#16a34a' : '#6b7280';
  // Compare BOM lines
  const prevBOMMap = new Map(prev.bom.map(l => [l.refDes, l]));
  const changes: string[] = [];
  for (const line of r.bom) {
    const p = prevBOMMap.get(line.refDes);
    if (!p) { changes.push(`<li style="color:#2563eb">+ ${line.refDes}: new (£${(line.qty*line.unitPriceGBP).toFixed(2)})</li>`); }
    else {
      const delta = line.qty * line.unitPriceGBP - p.qty * p.unitPriceGBP;
      if (Math.abs(delta) > 0.10) changes.push(`<li style="color:${delta>0?'#dc2626':'#16a34a'}">${line.refDes}: ${sign(delta)} (${delta>0?'more':'less'} expensive)</li>`);
    }
  }
  for (const p of prev.bom) {
    if (!r.bom.find(l => l.refDes === p.refDes)) changes.push(`<li style="color:#6b7280">- ${p.refDes}: removed</li>`);
  }
  return `<div class="pcb-analysis-section">
    <div class="pcb-analysis-section-title" style="display:flex;align-items:center;justify-content:space-between">
      <span>🔄 vs Previous Analysis</span>
      <button class="btn btn-secondary btn-sm" id="pcb-clear-revision-btn" style="font-size:0.60rem;padding:1px 6px">Clear</button>
    </div>
    <div style="display:flex;gap:12px;padding:8px 4px;font-size:0.70rem">
      <span>BOM: <strong style="color:${color(bomDelta)}">${sign(bomDelta)}</strong></span>
      <span>Fab: <strong style="color:${color(fabDelta)}">${sign(fabDelta)}</strong></span>
      <span>Total: <strong style="color:${color(totalDelta)}">${sign(totalDelta)}</strong></span>
    </div>
    ${changes.length > 0 ? `<ul style="margin:0;padding-left:18px;font-size:0.67rem;max-height:120px;overflow-y:auto">${changes.slice(0,20).join('')}</ul>` : '<div style="font-size:0.67rem;color:var(--text-muted);padding:0 4px">No significant BOM line changes</div>'}
  </div>`;
}

function buildCountryBreakdownSection(r: PCBImageAnalysis): string {
  const sel = r._selectedCountryBreakdown;
  const comparison = r._countryComparison ?? [];
  if (!sel && !comparison.length) return '';

  const selectedCountryId = r._selectedCountry ?? 'cn';

  // Selected country detail card
  const selectedCard = sel ? `
    <div style="margin-bottom:10px;padding:10px;background:rgba(79,142,247,0.07);border:1px solid rgba(79,142,247,0.25);border-radius:8px">
      <div style="font-weight:700;font-size:0.82rem;margin-bottom:6px">${sel.flag} ${sel.countryName} — Should Cost Breakdown</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:6px;font-size:0.75rem">
        <div><span style="color:var(--text-muted)">PCB Fab:</span> <strong>£${sel.pcbFabPerBoard.toFixed(2)}</strong></div>
        <div><span style="color:var(--text-muted)">Assembly:</span> <strong>£${sel.assemblyPerBoard.toFixed(2)}</strong></div>
        <div><span style="color:var(--text-muted)">Logistics:</span> <strong>£${sel.logisticsPerBoard.toFixed(2)}</strong></div>
        <div><span style="color:var(--text-muted)">BOM:</span> <strong>£${sel.bomCostPerBoard.toFixed(2)}</strong></div>
        <div><span style="color:var(--text-muted)">Lead time:</span> <strong>${sel.leadTimeWeeks}w</strong></div>
        <div><span style="color:var(--text-muted)">Quality:</span> <strong>${Math.round(sel.qualityIndex * 100)}%</strong></div>
      </div>
      <div style="margin-top:8px;padding:8px;background:var(--card-bg);border-radius:6px">
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">
          <span style="font-size:0.72rem;font-weight:700;color:var(--text-secondary)">Total per board:</span>
          <span style="font-size:1.1rem;font-weight:800;color:var(--accent)">£${sel.totalPerBoard.toFixed(2)}</span>
        </div>
        <div style="font-size:0.68rem;color:var(--text-muted)">Breakdown: PCB base £${sel.breakdown.pcbBase.toFixed(2)} + layers £${sel.breakdown.pcbLayers.toFixed(2)} + surface £${sel.breakdown.pcbSurface.toFixed(2)} + vias £${sel.breakdown.pcbVias.toFixed(2)} + HDI £${sel.breakdown.pcbHDI.toFixed(2)} + setup £${sel.breakdown.pcbSetup.toFixed(2)} | assembly £${sel.breakdown.smtAssembly.toFixed(2)} | test £${sel.breakdown.aoi.toFixed(2)} | logistics £${sel.breakdown.logistics.toFixed(2)} + duty £${sel.breakdown.importDuty.toFixed(2)}</div>
      </div>
      ${sel.panelInfo ? `<div style="margin-top:6px;padding:6px 8px;background:var(--card-bg);border-radius:6px;font-size:0.68rem;color:var(--text-muted)">📐 Panelisation: <strong style="color:var(--text-secondary)">${sel.panelInfo.boardsPerPanel}-up</strong> on ${sel.panelInfo.panelW}×${sel.panelInfo.panelH}mm panel · utilisation <strong style="color:var(--text-secondary)">${Math.round(sel.panelInfo.utilisation * 100)}%</strong> (waste amortised into PCB base cost)</div>` : ''}
      ${pcbNREEnabled && PCB_COUNTRY_META[selectedCountryId]?.nre ? `<div style="margin-top:6px;padding:6px 8px;background:var(--card-bg);border-radius:6px;font-size:0.68rem;color:var(--text-muted)">Automotive NRE (one-time/programme): PPAP £${PCB_COUNTRY_META[selectedCountryId].nre.ppapGBP.toLocaleString()} + FMEA £${PCB_COUNTRY_META[selectedCountryId].nre.fmeaGBP.toLocaleString()} + DVP&amp;R £${PCB_COUNTRY_META[selectedCountryId].nre.dvprGBP.toLocaleString()} + FAI £${PCB_COUNTRY_META[selectedCountryId].nre.firstArticleGBP.toLocaleString()} + IATF £${PCB_COUNTRY_META[selectedCountryId].nre.iatfAuditGBP.toLocaleString()} = <strong style="color:var(--text-secondary)">£${PCB_COUNTRY_META[selectedCountryId].nre.totalGBP.toLocaleString()}</strong></div>` : ''}
      <div style="margin-top:4px;font-size:0.68rem;color:var(--text-muted)">Best for: ${escHtml(sel.bestFor)}</div>
    </div>` : '';

  // Country comparison table
  const maxTotal = Math.max(...comparison.map(c => c.totalPerBoard), 0.01);
  const orderQtyVal = (document.getElementById('pcb-order-qty') as HTMLInputElement)?.value;
  const nreQty = parseInt(orderQtyVal ?? '', 10) || 5000;
  const compRows = comparison.map(c => {
    const isSelected = c.countryId === selectedCountryId;
    const barW = Math.round((c.totalPerBoard / maxTotal) * 100);
    const qualityStars = '★'.repeat(Math.round(c.qualityIndex * 5)) + '☆'.repeat(5 - Math.round(c.qualityIndex * 5));
    const meta = PCB_COUNTRY_META[c.countryId];
    const trend = meta?.trend;
    const trendCell = trend ? (() => {
      const arrow = trend.direction === 'rising' ? '↑' : trend.direction === 'falling' ? '↓' : '→';
      const colour = trend.direction === 'rising' ? '#ef4444' : trend.direction === 'falling' ? '#16a34a' : 'var(--text-muted)';
      const sign = trend.pctChange6m > 0 ? '+' : '';
      return `<td style="color:${colour};white-space:nowrap" title="${escHtml(trend.note)}">${arrow} ${sign}${trend.pctChange6m}%</td>`;
    })() : '<td>—</td>';
    const nreCell = pcbNREEnabled
      ? `<td style="white-space:nowrap" title="One-time programme NRE">£${((meta?.nre?.totalGBP ?? 0) / 1000).toFixed(1)}k</td>`
      : '';
    const delta = r._costDeltas?.[c.countryId];
    const deltaCell = delta !== undefined
      ? `<td style="font-size:0.68rem;white-space:nowrap;color:${delta > 0 ? '#ef4444' : delta < 0 ? '#16a34a' : 'var(--text-muted)'}">${delta > 0 ? '↑' : delta < 0 ? '↓' : '→'}£${Math.abs(delta).toFixed(2)}</td>`
      : (r._costDeltas ? '<td>—</td>' : '');
    return `<tr style="${isSelected ? 'background:rgba(79,142,247,0.10);font-weight:700' : ''}">
      <td style="white-space:nowrap">${c.flag} ${c.countryName.split(' (')[0]}</td>
      <td>£${c.pcbFabPerBoard.toFixed(2)}</td>
      <td>£${c.assemblyPerBoard.toFixed(2)}</td>
      <td>£${c.logisticsPerBoard.toFixed(2)}</td>
      <td style="color:var(--accent);font-weight:700">£${c.totalPerBoard.toFixed(2)}</td>
      ${deltaCell}
      <td>
        <div style="display:flex;align-items:center;gap:4px">
          <div style="flex:1;height:6px;background:var(--border);border-radius:3px;min-width:40px">
            <div style="height:100%;width:${barW}%;background:${isSelected ? 'var(--accent)' : 'var(--text-muted)'};border-radius:3px"></div>
          </div>
        </div>
      </td>
      <td style="white-space:nowrap">${c.leadTimeWeeks}w</td>
      ${trendCell}
      ${nreCell}
      <td style="font-size:0.65rem;color:#f59e0b" title="${Math.round(c.qualityIndex * 100)}% quality">${qualityStars}</td>
    </tr>`;
  }).join('');

  return comparison.length === 0 ? selectedCard : `
    ${selectedCard}
    <div class="pcb-analysis-section">
      <div class="pcb-analysis-section-title">🌍 Global Manufacturing Cost Comparison (${comparison.length} countries · 2026 data)</div>
      <div style="overflow-x:auto">
        <table class="pcb-bom-table" style="font-size:0.72rem;white-space:nowrap">
          <thead>
            <tr>
              <th>Country</th>
              <th>PCB Fab</th>
              <th>Assembly</th>
              <th>Logistics</th>
              <th>Total/Board</th>
              ${r._costDeltas ? '<th>&#916; vs orig</th>' : ''}
              <th style="min-width:60px">Cost bar</th>
              <th>Lead time</th>
              <th title="6-month should-cost trend">Trend</th>
              ${pcbNREEnabled ? '<th title="One-time automotive NRE per programme">NRE</th>' : ''}
              <th>Quality</th>
            </tr>
          </thead>
          <tbody>${compRows}</tbody>
        </table>
      </div>
      <div style="margin-top:4px;font-size:0.65rem;color:var(--text-muted)">
        Prices include PCB fabrication + SMT/THT assembly + logistics/import duty to UK. BOM component cost (£${(comparison[0]?.bomCostPerBoard ?? 0).toFixed(2)}) is the same for all countries. Data calibrated to Jan 2026 market rates.
        ${pcbNREEnabled ? `<br/>NRE costs are one-time per programme. At ${(nreQty / 1000).toFixed(nreQty % 1000 === 0 ? 0 : 1)}k units, ${selectedCountryId.toUpperCase()} NRE adds £${(((PCB_COUNTRY_META[selectedCountryId]?.nre?.totalGBP ?? 0) / nreQty)).toFixed(2)}/board.` : ''}
      </div>
    </div>`;
}

// ─── Feature: Volume sensitivity chart (Priority 3) ────────────────────────
function buildVolumeCurveSection(r: PCBImageAnalysis): string {
  if (!r._volumeCurves || Object.keys(r._volumeCurves).length === 0) return '';
  const curves = r._volumeCurves;
  const selId = r._selectedCountry ?? 'cn';
  const orderQty = parseInt((document.getElementById('pcb-order-qty') as HTMLInputElement)?.value ?? '5000', 10) || 5000;

  // Crossover insight: compare cheapest vs UK at the user's nearest volume break.
  const ids = Object.keys(curves);
  const cheapestId = ids.find(id => id !== 'gb' && id !== selId) ?? ids[0];
  const gbCurve = curves.gb ?? curves[ids[0]];
  const cheapCurve = curves[cheapestId] ?? gbCurve;
  const pointAt = (curve: VolumeCurvePoint[]): VolumeCurvePoint => {
    let best = curve[0];
    for (const p of curve) if (Math.abs(p.qty - orderQty) < Math.abs(best.qty - orderQty)) best = p;
    return best;
  };
  const cheapPt = pointAt(cheapCurve);
  const gbPt = pointAt(gbCurve);
  const saving = gbPt.totalPerBoard - cheapPt.totalPerBoard;
  const fullRun = saving * orderQty;
  const cheapName = PCB_COUNTRY_META[cheapestId] ? cheapestId.toUpperCase() : cheapestId.toUpperCase();
  const insight = saving > 0
    ? `At your volume (${orderQty.toLocaleString()}), ${cheapName} saves £${saving.toFixed(2)}/board vs UK (£${Math.round(fullRun).toLocaleString()} on the full run).`
    : `At your volume (${orderQty.toLocaleString()}), UK is within £${Math.abs(saving).toFixed(2)}/board of the cheapest option.`;

  return `
    <div class="pcb-analysis-section">
      <div class="pcb-analysis-section-title">📈 Volume Sensitivity — Cost per Board vs Order Quantity</div>
      <div style="position:relative;height:240px;background:var(--card-bg);border-radius:6px;padding:8px">
        <canvas id="pcb-volume-chart"></canvas>
      </div>
      <div style="margin-top:6px;font-size:0.68rem;color:var(--text-muted)">${escHtml(insight)}</div>
    </div>`;
}

function drawVolumeCurveChart(r: PCBImageAnalysis): void {
  const canvas = document.getElementById('pcb-volume-chart') as HTMLCanvasElement | null;
  if (!canvas || !r._volumeCurves) return;
  if (_pcbVolumeChart) { _pcbVolumeChart.destroy(); _pcbVolumeChart = null; }

  const curves = r._volumeCurves;
  const selId = r._selectedCountry ?? 'cn';
  const ids = Object.keys(curves);
  const cheapestId = ids.find(id => id !== 'gb' && id !== selId) ?? ids[0];
  const labels = (curves[ids[0]] ?? []).map(p => p.qty.toLocaleString());

  const nameOf = (id: string): string => {
    const c = r._countryComparison?.find(cc => cc.countryId === id);
    return c ? `${c.flag} ${c.countryName.split(' (')[0]}` : id.toUpperCase();
  };

  const datasets: Array<{ label: string; data: number[]; borderColor: string; backgroundColor: string; tension: number; pointRadius: number }> = [];
  const addLine = (id: string, colour: string) => {
    if (!curves[id]) return;
    datasets.push({
      label: nameOf(id),
      data: curves[id].map(p => p.totalPerBoard),
      borderColor: colour,
      backgroundColor: colour,
      tension: 0.25,
      pointRadius: 3,
    });
  };
  addLine(cheapestId, '#16a34a');
  if (selId !== cheapestId) addLine(selId, '#4f8ef7');
  if (selId !== 'gb' && cheapestId !== 'gb') addLine('gb', '#f59e0b');

  _pcbVolumeChart = new Chart(canvas, {
    type: 'line',
    data: { labels, datasets },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { labels: { boxWidth: 12, font: { size: 11 } } },
        tooltip: { callbacks: { label: (ctx) => `${ctx.dataset.label}: £${Number(ctx.parsed.y).toFixed(2)}/board` } },
      },
      scales: {
        x: { title: { display: true, text: 'Order quantity', font: { size: 10 } } },
        y: { title: { display: true, text: 'Cost per board (£)', font: { size: 10 } }, beginAtZero: false },
      },
    },
  });
}

// ─── Feature 6: Supply chain risk radar ────────────────────────────────────
function riskBar(v: number): string {
  const filled = Math.max(1, Math.min(5, Math.round(v * 5)));
  return '■'.repeat(filled) + '□'.repeat(5 - filled);
}
function buildRiskRadarSection(r: PCBImageAnalysis): string {
  const comparison = r._countryComparison ?? [];
  if (!comparison.length) return '';
  const selId = r._selectedCountry ?? 'cn';
  const autoCount = r.bom.filter(b => b.automotive).length;

  // Selected + top 3 cheapest alternatives (distinct)
  const ordered = [...comparison].sort((a, b) => a.totalPerBoard - b.totalPerBoard);
  const chosen: PCBCountryBreakdown[] = [];
  const sel = comparison.find(c => c.countryId === selId);
  if (sel) chosen.push(sel);
  for (const c of ordered) {
    if (chosen.length >= 4) break;
    if (!chosen.some(x => x.countryId === c.countryId)) chosen.push(c);
  }

  const rows = chosen.map(c => {
    const p = computeClientRiskProfile(c.countryId, autoCount);
    const colour = p.label === 'Low Risk' ? '#16a34a' : p.label === 'Medium Risk' ? '#f59e0b' : '#ef4444';
    return `<tr ${c.countryId === selId ? 'style="background:rgba(79,142,247,0.10);font-weight:700"' : ''}>
      <td style="white-space:nowrap">${c.flag} ${c.countryName.split(' (')[0]}</td>
      <td style="font-family:monospace" title="Geopolitical stability">${riskBar(p.dims.geopolitical)}</td>
      <td style="font-family:monospace" title="Logistics reliability">${riskBar(p.dims.logisticsReliability)}</td>
      <td style="font-family:monospace" title="Quality consistency">${riskBar(p.dims.qualityConsistency)}</td>
      <td style="font-family:monospace" title="Lead-time variance">${riskBar(p.dims.leadTimeVariance)}</td>
      <td style="color:${colour};font-weight:700;white-space:nowrap">${p.label}</td>
    </tr>`;
  }).join('');

  const autoParts = r.bom.filter(b => b.automotive && (b.componentType.startsWith('ic_') || b.highCost)).slice(0, 3).map(b => b.value || b.partNumber || b.refDes).filter(Boolean);
  const singleSourceLine = autoCount > 0
    ? `${autoCount} components are automotive-grade from potential single-source suppliers${autoParts.length ? ` (e.g. ${escHtml(autoParts.join(', '))})` : ''}.`
    : 'No automotive-grade single-source exposure detected in BOM.';

  return `
    <div class="pcb-analysis-section">
      <div class="pcb-analysis-section-title">🛡 Supply Chain Risk Radar</div>
      <div style="overflow-x:auto">
        <table class="pcb-bom-table" style="font-size:0.72rem;white-space:nowrap">
          <thead><tr><th>Country</th><th>Geopolitical</th><th>Logistics</th><th>Quality</th><th>Lead Time</th><th>Overall</th></tr></thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
      <div style="margin-top:6px;font-size:0.68rem;color:var(--text-muted)">⚠ Single-source risk: ${singleSourceLine}</div>
    </div>`;
}

// ─── Feature 10: What-if scenario builder ──────────────────────────────────
function buildScenarioBuilderSection(r: PCBImageAnalysis): string {
  const b = r.boardSpec;
  const selId = r._selectedCountry ?? 'cn';
  const curFinish = (b.surfaceFinish || 'enig').toLowerCase();
  const orderQty = parseInt((document.getElementById('pcb-order-qty') as HTMLInputElement)?.value ?? '5000', 10) || 5000;

  const finishOpt = (v: string, label: string) => `<option value="${v}"${curFinish === v ? ' selected' : ''}>${label}</option>`;
  const layerOpt = (v: number) => `<option value="${v}"${b.estimatedLayers === v ? ' selected' : ''}>${v}-layer</option>`;
  const countryOpt = (id: string, flag: string, name: string) => `<option value="${id}"${selId === id ? ' selected' : ''}>${flag} ${name}</option>`;

  return `
    <details class="pcb-analysis-section" style="margin-top:8px">
      <summary class="pcb-analysis-section-title" style="cursor:pointer;list-style:revert">🧪 What-If Scenario Builder</summary>
      <div style="margin-top:8px;display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:8px;font-size:0.72rem">
        <label style="display:flex;flex-direction:column;gap:3px">Surface finish
          <select id="pcb-scn-finish" style="font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)">
            ${finishOpt('hasl', 'HASL')}${finishOpt('hasl_lf', 'HASL-LF')}${finishOpt('enig', 'ENIG')}${finishOpt('osp', 'OSP')}${finishOpt('enepig', 'ENEPIG')}
          </select>
        </label>
        <label style="display:flex;flex-direction:column;gap:3px">Layer count
          <select id="pcb-scn-layers" style="font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)">
            ${[2,4,6,8,10,12].map(layerOpt).join('')}
          </select>
        </label>
        <label style="display:flex;flex-direction:column;gap:3px">Order quantity: <span id="pcb-scn-qty-label">${orderQty.toLocaleString()}</span>
          <input type="range" id="pcb-scn-qty" min="100" max="25000" step="100" value="${orderQty}"/>
        </label>
        <label style="display:flex;flex-direction:column;gap:3px">Country
          <select id="pcb-scn-country" style="font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)">
            ${countryOpt('cn','🇨🇳','China')}${countryOpt('vn','🇻🇳','Vietnam')}${countryOpt('in','🇮🇳','India')}${countryOpt('th','🇹🇭','Thailand')}${countryOpt('my','🇲🇾','Malaysia')}${countryOpt('tw','🇹🇼','Taiwan')}${countryOpt('kr','🇰🇷','South Korea')}${countryOpt('mx','🇲🇽','Mexico')}${countryOpt('cz','🇨🇿','Czechia')}${countryOpt('pl','🇵🇱','Poland')}${countryOpt('de','🇩🇪','Germany')}${countryOpt('gb','🇬🇧','UK')}${countryOpt('us','🇺🇸','USA')}${countryOpt('jp','🇯🇵','Japan')}
          </select>
        </label>
      </div>
      <div id="pcb-scn-result" style="margin-top:8px;padding:8px;background:var(--card-bg);border-radius:6px;font-size:0.72rem;color:var(--text-muted)">Adjust a parameter to see the cost delta vs the current baseline.</div>
    </details>`;
}

let _scnDebounce: ReturnType<typeof setTimeout> | null = null;
function wireScenarioBuilder(r: PCBImageAnalysis): void {
  const ids = ['pcb-scn-finish', 'pcb-scn-layers', 'pcb-scn-qty', 'pcb-scn-country'];
  const qtyLabel = document.getElementById('pcb-scn-qty-label');
  const resultEl = document.getElementById('pcb-scn-result');
  if (!resultEl) return;

  const baseTotal = r._selectedCountryBreakdown?.totalPerBoard ?? 0;

  const recompute = async () => {
    const finish = (document.getElementById('pcb-scn-finish') as HTMLSelectElement)?.value ?? 'enig';
    const layers = parseInt((document.getElementById('pcb-scn-layers') as HTMLSelectElement)?.value ?? '2', 10);
    const qty = parseInt((document.getElementById('pcb-scn-qty') as HTMLInputElement)?.value ?? '5000', 10);
    const country = (document.getElementById('pcb-scn-country') as HTMLSelectElement)?.value ?? 'cn';
    if (qtyLabel) qtyLabel.textContent = qty.toLocaleString();

    const b = r.boardSpec; const a = r.assembly;
    const payload = {
      widthMm: b.widthMm, heightMm: b.heightMm, layers, surfaceFinish: finish,
      throughVias: b.throughVias, blindVias: b.blindVias, microVias: b.microVias,
      hdiStructure: b.hdiStructure, impedanceControlled: b.impedanceControlRequired,
      smtPlacements: a.smtPlacements, throughHoleJoints: a.throughHoleJoints, manualJoints: a.manualJoints,
      bgaCount: a.bgaCount, aoiRequired: a.aoiRequired, ictTimeSec: a.ictTimeSec, conformalCoatAreaCm2: 0,
      totalBOMCostGBP: r.costEstimates.totalBOMCostGBP, orderQuantity: qty, country,
    };
    try {
      const resp = await fetch('/api/pcb/scenario', {
        method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload),
      });
      const data = await resp.json() as { success?: boolean; breakdown?: PCBCountryBreakdown; error?: string };
      if (!resp.ok || !data.breakdown) throw new Error(data.error ?? resp.statusText);
      const nt = data.breakdown.totalPerBoard;
      const delta = nt - baseTotal;
      const pct = baseTotal > 0 ? (delta / baseTotal) * 100 : 0;
      const totalRun = delta * qty;
      const sign = delta >= 0 ? '+' : '−';
      const colour = delta > 0 ? '#ef4444' : delta < 0 ? '#16a34a' : 'var(--text-muted)';
      resultEl.innerHTML = `New total: <strong style="color:var(--accent)">£${nt.toFixed(2)}/board</strong> · Delta vs baseline (£${baseTotal.toFixed(2)}): <strong style="color:${colour}">${sign}£${Math.abs(delta).toFixed(2)} (${sign}${Math.abs(pct).toFixed(1)}%)</strong>. At ${qty.toLocaleString()} units, that is ${sign}£${Math.abs(totalRun).toLocaleString(undefined, { maximumFractionDigits: 0 })} total.`;
    } catch (err) {
      resultEl.textContent = `⚠ Scenario error: ${(err instanceof Error ? err.message : String(err)).slice(0, 100)}`;
    }
  };

  for (const id of ids) {
    const elem = document.getElementById(id);
    elem?.addEventListener('input', () => {
      if (_scnDebounce) clearTimeout(_scnDebounce);
      _scnDebounce = setTimeout(() => void recompute(), 250);
    });
  }
}

// ─── Feature 4: RFQ tracker (localStorage) ─────────────────────────────────
interface RFQEntry {
  id: string; partName: string; date: string; country: string; emsName: string;
  quotedTotalPerBoard: number; estimatedTotalPerBoard: number; variancePct: number; notes: string;
}
const RFQ_KEY = 'pcb_rfq_log';
function loadRFQ(): RFQEntry[] {
  try { return JSON.parse(localStorage.getItem(RFQ_KEY) ?? '[]') as RFQEntry[]; } catch { return []; }
}
function saveRFQ(entries: RFQEntry[]): void {
  try { localStorage.setItem(RFQ_KEY, JSON.stringify(entries)); } catch { /* ignore quota */ }
}
function buildRFQTrackerSection(r: PCBImageAnalysis): string {
  const estimated = r._selectedCountryBreakdown?.totalPerBoard ?? 0;
  const countryName = r._selectedCountryBreakdown?.countryName.split(' (')[0] ?? (r._selectedCountry ?? 'cn').toUpperCase();
  return `
    <details class="pcb-analysis-section" style="margin-top:8px">
      <summary class="pcb-analysis-section-title" style="cursor:pointer;list-style:revert">📥 RFQ Tracker — Log &amp; Compare EMS Quotes</summary>
      <div style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap;align-items:flex-end;font-size:0.72rem">
        <label style="display:flex;flex-direction:column;gap:3px">EMS Name
          <input type="text" id="pcb-rfq-ems" placeholder="e.g. Jabil" style="font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)"/>
        </label>
        <label style="display:flex;flex-direction:column;gap:3px">Quoted £/board
          <input type="number" id="pcb-rfq-quoted" step="0.01" min="0" style="width:110px;font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)"/>
        </label>
        <label style="display:flex;flex-direction:column;gap:3px;flex:1;min-width:120px">Notes
          <input type="text" id="pcb-rfq-notes" placeholder="lead time, MOQ, terms…" style="font-size:0.72rem;padding:3px 6px;border:1px solid var(--border);border-radius:4px;background:var(--card-bg)"/>
        </label>
        <button class="btn btn-primary btn-sm" id="pcb-rfq-log-btn" style="font-size:0.68rem">Log Quote</button>
      </div>
      <div style="margin-top:4px;font-size:0.66rem;color:var(--text-muted)">Estimated baseline: ${countryName} £${estimated.toFixed(2)}/board</div>
      <div id="pcb-rfq-table-wrap" style="margin-top:8px"></div>
    </details>`;
}
function renderRFQTable(): void {
  const wrap = document.getElementById('pcb-rfq-table-wrap');
  if (!wrap) return;
  const entries = loadRFQ().slice(-10).reverse();
  if (!entries.length) { wrap.innerHTML = '<div style="font-size:0.68rem;color:var(--text-muted)">No quotes logged yet.</div>'; return; }
  const rows = entries.map(e => {
    const colour = e.variancePct > 0 ? '#ef4444' : e.variancePct < 0 ? '#16a34a' : 'var(--text-muted)';
    const sign = e.variancePct >= 0 ? '+' : '';
    return `<tr>
      <td style="white-space:nowrap">${new Date(e.date).toLocaleDateString()}</td>
      <td>${escHtml(e.emsName)}</td>
      <td>${escHtml(e.country)}</td>
      <td>£${e.quotedTotalPerBoard.toFixed(2)}</td>
      <td>£${e.estimatedTotalPerBoard.toFixed(2)}</td>
      <td style="color:${colour};font-weight:700">${sign}${e.variancePct.toFixed(1)}%</td>
      <td style="max-width:200px;white-space:normal">${escHtml(e.notes)}</td>
    </tr>`;
  }).join('');
  const avg = entries.reduce((s, e) => s + e.variancePct, 0) / entries.length;
  const avgSign = avg >= 0 ? 'above' : 'below';
  wrap.innerHTML = `
    <div style="overflow-x:auto">
      <table class="pcb-bom-table" style="font-size:0.72rem">
        <thead><tr><th>Date</th><th>EMS</th><th>Country</th><th>Quoted</th><th>Estimated</th><th>Variance %</th><th>Notes</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
    <div style="margin-top:4px;font-size:0.68rem;color:var(--text-muted)">Your quotes run <strong>${Math.abs(avg).toFixed(1)}% ${avgSign}</strong> estimates on average.</div>`;
}
function wireRFQTracker(r: PCBImageAnalysis): void {
  const btn = document.getElementById('pcb-rfq-log-btn');
  btn?.addEventListener('click', () => {
    const ems = (document.getElementById('pcb-rfq-ems') as HTMLInputElement)?.value?.trim() ?? '';
    const quoted = parseFloat((document.getElementById('pcb-rfq-quoted') as HTMLInputElement)?.value ?? '');
    const notes = (document.getElementById('pcb-rfq-notes') as HTMLInputElement)?.value?.trim() ?? '';
    if (!ems || !Number.isFinite(quoted) || quoted <= 0) {
      showToast('Enter an EMS name and a valid quoted price.', 'warning');
      return;
    }
    const estimated = r._selectedCountryBreakdown?.totalPerBoard ?? 0;
    const variancePct = estimated > 0 ? ((quoted - estimated) / estimated) * 100 : 0;
    const entries = loadRFQ();
    entries.push({
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      partName: r.partName,
      date: new Date().toISOString(),
      country: r._selectedCountryBreakdown?.countryName.split(' (')[0] ?? (r._selectedCountry ?? 'cn').toUpperCase(),
      emsName: ems, quotedTotalPerBoard: quoted, estimatedTotalPerBoard: estimated, variancePct, notes,
    });
    saveRFQ(entries);
    (document.getElementById('pcb-rfq-ems') as HTMLInputElement).value = '';
    (document.getElementById('pcb-rfq-quoted') as HTMLInputElement).value = '';
    (document.getElementById('pcb-rfq-notes') as HTMLInputElement).value = '';
    renderRFQTable();
  });
  renderRFQTable();
}

// ─── Feature 9: Board image annotation ─────────────────────────────────────
function buildBoardAnnotationSection(): string {
  if (!pcbImageDataURL) return '';
  return `
    <div class="pcb-analysis-section">
      <div class="pcb-analysis-section-title" style="display:flex;align-items:center;gap:8px">
        🖼 Annotated Board
        <button class="btn btn-secondary btn-sm" id="pcb-annot-toggle" style="font-size:0.62rem;margin-left:auto">Show Annotated Board</button>
      </div>
      <div id="pcb-annot-wrap" style="display:none;margin-top:6px;text-align:center">
        <canvas id="pcb-annotated-img" style="max-width:100%;border:1px solid var(--border);border-radius:6px"></canvas>
        <div style="margin-top:4px;font-size:0.64rem;color:var(--text-muted)">RefDes labels distributed across the board — <span style="color:#ef4444">red=high-cost</span>, <span style="color:#f59e0b">amber=automotive</span>, <span style="color:#4f8ef7">blue=standard</span>. Positions are approximate (grid layout).</div>
      </div>
    </div>`;
}
function wireBoardAnnotation(r: PCBImageAnalysis): void {
  const toggle = document.getElementById('pcb-annot-toggle');
  const wrap = document.getElementById('pcb-annot-wrap');
  if (!toggle || !wrap || !pcbImageDataURL) return;
  let drawn = false;
  toggle.addEventListener('click', () => {
    const visible = wrap.style.display !== 'none';
    wrap.style.display = visible ? 'none' : 'block';
    toggle.textContent = visible ? 'Show Annotated Board' : 'Hide Annotated Board';
    if (!visible && !drawn) { drawBoardAnnotation(r); drawn = true; }
  });
}
function drawBoardAnnotation(r: PCBImageAnalysis): void {
  const canvas = document.getElementById('pcb-annotated-img') as HTMLCanvasElement | null;
  if (!canvas || !pcbImageDataURL) return;
  const img = new Image();
  img.onload = () => {
    const maxW = 720;
    const scale = img.width > maxW ? maxW / img.width : 1;
    canvas.width = img.width * scale;
    canvas.height = img.height * scale;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    // Distribute BOM refdes labels in a grid overlay
    const items = r.bom.slice(0, 40);
    const cols = Math.ceil(Math.sqrt(items.length)) || 1;
    const rows = Math.ceil(items.length / cols) || 1;
    const cw = canvas.width / cols;
    const ch = canvas.height / rows;
    ctx.font = '11px system-ui, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    items.forEach((item, i) => {
      const cx = (i % cols) * cw + cw / 2;
      const cy = Math.floor(i / cols) * ch + ch / 2;
      const colour = item.highCost ? '#ef4444' : item.automotive ? '#f59e0b' : '#4f8ef7';
      const label = item.refDes.split(/[\s,]/)[0] || item.refDes;
      const w = ctx.measureText(label).width + 8;
      ctx.fillStyle = 'rgba(0,0,0,0.65)';
      ctx.fillRect(cx - w / 2, cy - 8, w, 16);
      ctx.fillStyle = colour;
      ctx.fillText(label, cx, cy);
    });
  };
  img.src = pcbImageDataURL;
}

// ─── Feature 8: Export to CSV / PDF ────────────────────────────────────────
function csvCell(v: unknown): string {
  const s = String(v ?? '');
  return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}
function exportPCBAnalysisCSV(r: PCBImageAnalysis): void {
  const lines: string[] = [];
  const dateStr = new Date().toISOString().slice(0, 10);
  lines.push('CostVision — AI Cost Intelligence');
  lines.push(`PCB Analysis Export,${csvCell(r.partName)},${dateStr}`);
  lines.push('');
  lines.push('=== BILL OF MATERIALS ===');
  lines.push('RefDes,Description,Package,Value,Voltage,PartNumber,Qty,Unit GBP,Ext GBP,Automotive,HighCost');
  for (const b of r.bom) {
    lines.push([b.refDes, b.description, b.pkg, b.value, b.voltage, b.partNumber ?? '', b.qty, b.unitPriceGBP.toFixed(4), (b.qty * b.unitPriceGBP).toFixed(2), b.automotive ? 'Y' : 'N', b.highCost ? 'Y' : 'N'].map(csvCell).join(','));
  }
  lines.push(`Total BOM Cost,,,,,,,,${r.costEstimates.totalBOMCostGBP.toFixed(2)}`);
  lines.push('');
  lines.push('=== COUNTRY COMPARISON ===');
  lines.push('Country,PCB Fab,Assembly,Logistics,BOM,Total/Board,Lead Weeks,Quality %,NRE Total GBP');
  for (const c of r._countryComparison ?? []) {
    const nreTot = PCB_COUNTRY_META[c.countryId]?.nre?.totalGBP ?? 0;
    lines.push([c.countryName, c.pcbFabPerBoard.toFixed(2), c.assemblyPerBoard.toFixed(2), c.logisticsPerBoard.toFixed(2), c.bomCostPerBoard.toFixed(2), c.totalPerBoard.toFixed(2), c.leadTimeWeeks, Math.round(c.qualityIndex * 100), nreTot].map(csvCell).join(','));
  }
  if (r._volumeCurves) {
    lines.push('');
    lines.push('=== VOLUME CURVES (Total GBP/board) ===');
    const ids = Object.keys(r._volumeCurves);
    const qtys = r._volumeCurves[ids[0]]?.map(p => p.qty) ?? [];
    lines.push(['Qty', ...ids.map(id => id.toUpperCase())].join(','));
    qtys.forEach((q, i) => {
      lines.push([q, ...ids.map(id => (r._volumeCurves![id][i]?.totalPerBoard ?? 0).toFixed(2))].join(','));
    });
  }
  if (pcbUploadedImages.length > 0) {
    lines.push('');
    lines.push('=== UPLOADED BOARD IMAGES ===');
    lines.push('View,Pixels (WxH)');
    for (const im of pcbUploadedImages) lines.push([im.label, `${im.w}x${im.h}`].map(csvCell).join(','));
    lines.push('Note: images are embedded in the Excel (.xls) and PDF exports (CSV is text-only).');
  }
  const blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `pcb-analysis-${r.partName.replace(/[^a-z0-9]+/gi, '-').slice(0, 40)}-${dateStr}.csv`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}
// Excel export — an HTML-table workbook (.xls) so the uploaded board photos can be
// embedded as pictures. SheetJS's community build cannot write images into .xlsx;
// the HTML-workbook format is the reliable, dependency-free way Excel / Google
// Sheets / LibreOffice all open with the images shown. Machine-readable data stays
// in the CSV export.
function exportPCBAnalysisExcel(r: PCBImageAnalysis): void {
  const dateStr = new Date().toISOString().slice(0, 10);
  const money = (n: number) => `£${n.toFixed(2)}`;
  const th = (t: string) => `<th style="background:#1e3a8a;color:#fff;border:1px solid #cbd5e1;padding:4px 8px;text-align:left">${escHtml(t)}</th>`;
  const td = (t: string | number, extra = '') => `<td style="border:1px solid #cbd5e1;padding:3px 8px;${extra}">${escHtml(String(t))}</td>`;

  const bomRows = r.bom.map(b => `<tr>${[
    td(b.refDes), td(b.description), td(b.pkg), td(b.value), td(b.partNumber ?? ''),
    td(b.qty), td(b.unitPriceGBP.toFixed(4)), td((b.qty * b.unitPriceGBP).toFixed(2)),
    td(b.automotive ? 'Y' : 'N'), td(b.highCost ? 'Y' : 'N'),
  ].join('')}</tr>`).join('');

  const countryRows = (r._countryComparison ?? []).map(c => `<tr>${[
    td(c.countryName), td(money(c.pcbFabPerBoard)), td(money(c.assemblyPerBoard)),
    td(money(c.logisticsPerBoard)), td(money(c.bomCostPerBoard)), td(money(c.totalPerBoard)),
    td(c.leadTimeWeeks), td(`${Math.round(c.qualityIndex * 100)}%`),
  ].join('')}</tr>`).join('');

  // Embedded board images — each in its own row so Excel sizes the cell to the picture.
  const imageRows = pcbUploadedImages.map(im => {
    const w = Math.min(420, im.w);
    const h = Math.round(w * (im.h / Math.max(1, im.w)));
    return `<tr>
      <td style="border:1px solid #cbd5e1;padding:6px;font-weight:bold;vertical-align:top">${escHtml(im.label)}</td>
      <td style="border:1px solid #cbd5e1;padding:6px"><img src="${im.dataUrl}" width="${w}" height="${h}"/></td>
    </tr>`;
  }).join('');

  const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
  <head><meta charset="utf-8"/><style>table{border-collapse:collapse;font-family:Arial,sans-serif;font-size:11px;margin-bottom:16px}h2{font-family:Arial;font-size:14px;color:#1e3a8a}</style></head>
  <body>
    <table style="border:none;margin-bottom:6px"><tr>
      <td style="border:none;background:#4f46e5;color:#ffffff;font-weight:bold;font-size:18px;font-family:Arial;padding:4px 10px;text-align:center">cv</td>
      <td style="border:none;color:#2563eb;font-weight:bold;font-size:22px;font-family:Arial;padding-left:10px">CostVision</td>
      <td style="border:none;color:#475569;font-size:10px;font-family:Arial;padding-left:10px;vertical-align:bottom">AI COST INTELLIGENCE</td>
    </tr></table>
    <h2>PCB Should-Cost Analysis — ${escHtml(r.partName)}</h2>
    <div style="font-size:11px;color:#475569">Exported ${dateStr} · Total BOM cost ${money(r.costEstimates.totalBOMCostGBP)}</div>
    <h2>Bill of Materials</h2>
    <table><tr>${['RefDes','Description','Package','Value','Part Number','Qty','Unit £','Ext £','Automotive','High-Cost'].map(th).join('')}</tr>${bomRows}
      <tr><td colspan="7" style="border:1px solid #cbd5e1;padding:3px 8px;font-weight:bold;text-align:right">Total BOM Cost</td>${td(r.costEstimates.totalBOMCostGBP.toFixed(2), 'font-weight:bold')}<td></td><td></td></tr>
    </table>
    ${countryRows ? `<h2>Country Comparison (per board)</h2><table><tr>${['Country','PCB Fab','Assembly','Logistics','BOM','Total/Board','Lead (wk)','Quality'].map(th).join('')}</tr>${countryRows}</table>` : ''}
    ${imageRows ? `<h2>Uploaded Board Images (${pcbUploadedImages.length})</h2><table>${imageRows}</table>` : '<p style="font-size:11px;color:#94a3b8">No board images were uploaded for this analysis.</p>'}
  </body></html>`;

  const blob = new Blob(['﻿', html], { type: 'application/vnd.ms-excel' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `pcb-analysis-${r.partName.replace(/[^a-z0-9]+/gi, '-').slice(0, 40)}-${dateStr}.xls`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

async function exportPCBAnalysisPrint(r: PCBImageAnalysis): Promise<void> {
  await ensurePdfLibs();
  type RGB = [number, number, number];
  const BLUE: RGB   = [37,  99,  235];
  const DARK: RGB   = [15,  23,  42];
  const GREY: RGB   = [100, 116, 139];
  const WHITE: RGB  = [255, 255, 255];
  const LIGHT: RGB  = [241, 245, 249];
  const RED_R: RGB  = [220, 38,  38];
  const AMB_R: RGB  = [180, 83,  9];
  const GRN_R: RGB  = [22,  163, 74];
  const CYAN: RGB   = [8,   145, 178];

  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  const margin = 14;
  const pageW = 210;
  const usable = pageW - margin * 2;
  let y = margin;
  const dateStr = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

  const checkPage = (need: number) => {
    if (y + need > 285) { doc.addPage(); y = margin; }
  };

  const sectionTitle = (title: string) => {
    checkPage(10);
    doc.setFillColor(...BLUE);
    doc.roundedRect(margin, y, usable, 7, 1.5, 1.5, 'F');
    doc.setFontSize(8.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...WHITE);
    doc.text(title, margin + 4, y + 5);
    doc.setFont('helvetica', 'normal'); doc.setTextColor(...DARK);
    y += 10;
  };

  const bulletList = (items: string[], colourFn?: (s: string) => RGB) => {
    items.forEach(s => {
      checkPage(6);
      const col = colourFn ? colourFn(s) : DARK;
      doc.setFontSize(7.5); doc.setTextColor(...col);
      const lines = doc.splitTextToSize(`• ${s}`, usable - 6);
      doc.text(lines as string[], margin + 6, y);
      y += lines.length * 4;
    });
    doc.setTextColor(...DARK);
    y += 2;
  };

  const addFooters = () => {
    const total = (doc as unknown as { internal: { getNumberOfPages(): number } }).internal.getNumberOfPages();
    for (let i = 1; i <= total; i++) {
      doc.setPage(i);
      doc.setDrawColor(...BLUE); doc.setLineWidth(0.4);
      doc.line(margin, 290, pageW - margin, 290);
      const lw = drawCostVisionLogo!(doc, margin, 290.7, 3.4);
      doc.setFontSize(6.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...GREY);
      doc.text(`PCB Image Analysis  ·  ${dateStr}`, margin + lw + 3, 294);
      doc.text(`Page ${i} of ${total}  ·  CONFIDENTIAL`, pageW - margin, 294, { align: 'right' });
    }
  };

  // ── COVER HEADER ────────────────────────────────────────────────────────────
  const headerH = 33;
  doc.setFillColor(...BLUE);
  doc.roundedRect(margin, y, usable, headerH, 3, 3, 'F');

  // Title — shrink-to-fit then ellipsis, so long board names never overflow the banner.
  doc.setFont('helvetica', 'bold'); doc.setTextColor(...WHITE);
  const titleMaxW = usable - 12;
  let titleSize = 15;
  doc.setFontSize(titleSize);
  while (doc.getTextWidth(r.partName) > titleMaxW && titleSize > 10.5) { titleSize -= 0.5; doc.setFontSize(titleSize); }
  let title = r.partName;
  if (doc.getTextWidth(title) > titleMaxW) {
    while (title.length > 8 && doc.getTextWidth(title + '...') > titleMaxW) title = title.slice(0, -1);
    title = title.replace(/\s+$/, '') + '...';
  }
  doc.text(title, margin + 6, y + 11);

  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(...WHITE);
  doc.text('PCB Image Analysis  ·  CostVision', margin + 6, y + 17);

  // Badge row — each chip sized to its own text so they never overlap.
  let bx = margin + 6;
  const by = y + 20.5;
  const chip = (label: string, bg: RGB, fg: RGB) => {
    doc.setFontSize(7); doc.setFont('helvetica', 'bold');
    const w = doc.getTextWidth(label) + 6;
    doc.setFillColor(...bg);
    doc.roundedRect(bx, by, w, 5.6, 1.2, 1.2, 'F');
    doc.setTextColor(...fg);
    doc.text(label, bx + 3, by + 3.9);
    bx += w + 3;
  };
  const confCol: RGB = r.confidenceLevel === 'High' ? GRN_R : r.confidenceLevel === 'Medium' ? AMB_R : RED_R;
  chip(`${r.confidenceLevel} Confidence`, confCol, WHITE);
  if (r.complexityScore) {
    const cx = r.complexityScore;
    chip(`Complexity ${cx.score}/100  ·  IPC Class ${cx.ipcClass}  ·  ${cx.label}`, LIGHT, BLUE);
  }

  doc.setFontSize(7); doc.setFont('helvetica', 'normal'); doc.setTextColor(...WHITE);
  doc.text(`Generated ${dateStr}  ·  Domain: ${r.stage1Classification?.domain?.replace(/_/g, ' ') ?? 'General'}`, margin + 6, y + headerH - 3);
  y += headerH + 5;

  // ── PRIMARY BOARD PHOTO (page 1) — so the reader instantly knows the board ──
  if (pcbUploadedImages.length > 0) {
    const im = pcbUploadedImages[0];
    try {
      const maxH = 58, maxW = usable * 0.62;
      let iw = maxH * (im.w / Math.max(1, im.h)), ih = maxH;
      if (iw > maxW) { iw = maxW; ih = maxW * (im.h / Math.max(1, im.w)); }
      const bxp = margin + (usable - iw) / 2;
      doc.setFillColor(...LIGHT);
      doc.roundedRect(margin, y, usable, ih + 11, 2, 2, 'F');
      doc.addImage(im.dataUrl, 'JPEG', bxp, y + 4, iw, ih, undefined, 'FAST');
      const extra = pcbUploadedImages.length > 1 ? `  (+${pcbUploadedImages.length - 1} more in the image gallery)` : '';
      doc.setFontSize(7); doc.setFont('helvetica', 'normal'); doc.setTextColor(...GREY);
      doc.text(`Analysed board — ${im.label}${extra}`, margin + usable / 2, y + ih + 8.5, { align: 'center' });
      doc.setTextColor(...DARK);
      y += ih + 15;
    } catch { /* skip an image that fails to embed */ }
  }

  // ── §1 BOARD SPECIFICATION ───────────────────────────────────────────────────
  const b = r.boardSpec;
  sectionTitle('§1  Board Specification');
  autoTable(doc, {
    startY: y,
    margin: { left: margin, right: margin },
    head: [['Parameter', 'Value', 'Parameter', 'Value']],
    body: [
      ['Layers', String(b.estimatedLayers), 'Technology', b.technologyType.replace(/_/g, ' ')],
      ['Dimensions', `${b.widthMm} × ${b.heightMm} mm`, 'HDI Structure', b.hdiStructure === 'none' ? 'None' : b.hdiStructure],
      ['Surface Finish', b.surfaceFinish.toUpperCase(), 'Impedance Control', b.impedanceControlRequired ? 'Yes' : 'No'],
      ['Solder Mask', b.solderMaskColour, 'Copper Weight', `${b.copperWeightOz} oz`],
      ['Through Vias', String(b.throughVias), 'Blind Vias', String(b.blindVias)],
      ['Micro Vias', String(b.microVias), 'Buried Vias', String(b.buriedVias)],
      ['Quality Grade', b.qualityGrade.replace(/_/g, ' '), 'Panel Utilisation', `${Math.round(b.panelUtilisation * 100)}%`],
      ['BGA Detected', b.bgaDetected ? 'Yes' : 'No', 'Min Trace/Space', `${b.minTraceSpaceMm} mm`],
      ['Silkscreen Sides', String(b.silkscreenSides), 'OCR ICs Found', String(r.ocrExtraction?.icMarkings?.length ?? 0)],
    ],
    styles: { fontSize: 7.5, cellPadding: 2 },
    headStyles: { fillColor: BLUE, textColor: WHITE, fontStyle: 'bold', fontSize: 7.5 },
    alternateRowStyles: { fillColor: LIGHT },
    theme: 'grid',
  });
  y = (doc as unknown as { lastAutoTable: { finalY: number } }).lastAutoTable.finalY + 5;

  // ── §2 ASSEMBLY OVERVIEW ─────────────────────────────────────────────────────
  const a = r.assembly;
  sectionTitle('§2  Assembly Overview');
  autoTable(doc, {
    startY: y,
    margin: { left: margin, right: margin },
    head: [['Parameter', 'Value', 'Parameter', 'Value']],
    body: [
      ['SMT Placements', String(a.smtPlacements), 'Through-Hole Joints', String(a.throughHoleJoints)],
      ['Manual Joints', String(a.manualJoints), 'BGA Count', String(a.bgaCount)],
      ['Assembly Complexity', a.complexity, 'Reflow Sides', a.reflowSides === 2 ? 'Double-sided' : 'Single-sided'],
      ['AOI Required', a.aoiRequired ? 'Yes' : 'No', 'ICT Time', `${a.ictTimeSec} s`],
    ],
    styles: { fontSize: 7.5, cellPadding: 2 },
    headStyles: { fillColor: BLUE, textColor: WHITE, fontStyle: 'bold', fontSize: 7.5 },
    alternateRowStyles: { fillColor: LIGHT },
    theme: 'grid',
  });
  y = (doc as unknown as { lastAutoTable: { finalY: number } }).lastAutoTable.finalY + 5;

  // ── §3 COST OVERVIEW ──────────────────────────────────────────────────────────
  const c = r.costEstimates;
  sectionTitle('§3  Cost Overview');
  autoTable(doc, {
    startY: y,
    margin: { left: margin, right: margin },
    head: [['Cost Element', 'Min (£)', 'Mid (£)', 'Max (£)']],
    body: [
      ['PCB Fabrication', c.pcbFabGBP.min.toFixed(2), c.pcbFabGBP.mid.toFixed(2), c.pcbFabGBP.max.toFixed(2)],
      ['BOM (components)', '—', c.totalBOMCostGBP.toFixed(2), '—'],
      ['SMT Assembly', '—', c.smtAssemblyCostGBP.toFixed(2), '—'],
      ['Total Estimate', (c.pcbFabGBP.min + c.totalBOMCostGBP + c.smtAssemblyCostGBP).toFixed(2),
       (c.pcbFabGBP.mid + c.totalBOMCostGBP + c.smtAssemblyCostGBP).toFixed(2),
       (c.pcbFabGBP.max + c.totalBOMCostGBP + c.smtAssemblyCostGBP).toFixed(2)],
    ],
    styles: { fontSize: 8, cellPadding: 2.5 },
    headStyles: { fillColor: BLUE, textColor: WHITE, fontStyle: 'bold' },
    alternateRowStyles: { fillColor: LIGHT },
    bodyStyles: { halign: 'right' },
    columnStyles: { 0: { halign: 'left', fontStyle: 'bold' } },
    theme: 'grid',
    didParseCell: (data: any) => {
      if (data.section === 'body' && data.row.index === 3) {
        data.cell.styles.fillColor = [220, 242, 255];
        data.cell.styles.fontStyle = 'bold';
      }
    },
  });
  y = (doc as unknown as { lastAutoTable: { finalY: number } }).lastAutoTable.finalY + 5;

  // ── §4 GLOBAL MANUFACTURING COMPARISON ────────────────────────────────────────
  const comparisons = r._countryComparison ?? [];
  if (comparisons.length > 0) {
    sectionTitle('§4  Global Manufacturing Comparison');
    const sorted = [...comparisons].sort((a2, b2) => a2.totalPerBoard - b2.totalPerBoard);
    autoTable(doc, {
      startY: y,
      margin: { left: margin, right: margin },
      head: [['Country', 'PCB Fab', 'Assembly', 'BOM', 'Logistics', 'Total/Board', 'Lead Time', 'Quality']],
      body: sorted.map(ct => [
        ct.countryName,
        `£${ct.pcbFabPerBoard.toFixed(2)}`,
        `£${ct.assemblyPerBoard.toFixed(2)}`,
        `£${ct.bomCostPerBoard.toFixed(2)}`,
        `£${ct.logisticsPerBoard.toFixed(2)}`,
        `£${ct.totalPerBoard.toFixed(2)}`,
        `${ct.leadTimeWeeks}w`,
        ct.qualityIndex ? `${(ct.qualityIndex * 100).toFixed(0)}%` : '—',
      ]),
      styles: { fontSize: 7, cellPadding: 1.8 },
      headStyles: { fillColor: CYAN, textColor: WHITE, fontStyle: 'bold', fontSize: 7 },
      alternateRowStyles: { fillColor: LIGHT },
      columnStyles: {
        0: { cellWidth: 30 },
        5: { fontStyle: 'bold', textColor: BLUE },
      },
      theme: 'grid',
      didParseCell: (data: any) => {
        if (data.section === 'body' && data.row.index === 0 && data.column.index === 5) {
          data.cell.styles.fillColor = [220, 242, 220];
          data.cell.styles.fontStyle = 'bold';
        }
      },
    });
    y = (doc as unknown as { lastAutoTable: { finalY: number } }).lastAutoTable.finalY + 5;
  }

  // ── §5 BILL OF MATERIALS ──────────────────────────────────────────────────────
  sectionTitle(`§5  Bill of Materials  (${r.bom.length} lines · ${r.assembly.smtPlacements} placements)`);
  autoTable(doc, {
    startY: y,
    margin: { left: margin, right: margin },
    head: [['#', 'RefDes', 'Description', 'Pkg', 'Value', 'Qty', 'Unit £', 'Ext £', 'Flags']],
    body: r.bom.map((item, i) => [
      String(i + 1),
      item.refDes,
      item.description,
      item.pkg,
      item.value,
      String(item.qty),
      item.unitPriceGBP.toFixed(3),
      (item.qty * item.unitPriceGBP).toFixed(2),
      [item.automotive ? 'AEC' : '', item.highCost ? '$$' : '', item.ocrExtracted ? 'OCR' : ''].filter(Boolean).join(' '),
    ]),
    foot: [['', '', '', '', '', '', 'Total BOM', `£${r.costEstimates.totalBOMCostGBP.toFixed(2)}`, '']],
    styles: { fontSize: 6.5, cellPadding: 1.5 },
    headStyles: { fillColor: BLUE, textColor: WHITE, fontStyle: 'bold', fontSize: 7 },
    footStyles: { fillColor: LIGHT, fontStyle: 'bold', fontSize: 7, textColor: DARK },
    alternateRowStyles: { fillColor: [250, 250, 252] },
    columnStyles: {
      0: { cellWidth: 6, halign: 'center' },
      1: { cellWidth: 14 },
      5: { halign: 'right' },
      6: { halign: 'right' },
      7: { halign: 'right', fontStyle: 'bold' },
      8: { cellWidth: 16 },
    },
    theme: 'grid',
    didParseCell: (data: any) => {
      if (data.section === 'body') {
        const item = r.bom[data.row.index];
        if (item?.highCost) data.cell.styles.fillColor = [255, 248, 220];
      }
    },
  });
  y = (doc as unknown as { lastAutoTable: { finalY: number } }).lastAutoTable.finalY + 5;

  // ── §6 HIGH COST COMPONENTS ────────────────────────────────────────────────────
  if (r.highCostComponents.length > 0) {
    sectionTitle('§6  High Cost Components');
    bulletList(r.highCostComponents, () => AMB_R);
  }

  // ── §7 AI INSIGHTS ─────────────────────────────────────────────────────────────
  sectionTitle('§7  AI Insights');
  bulletList(r.aiInsights);

  // ── §8 DFM ISSUES ─────────────────────────────────────────────────────────────
  if (r.dfmIssues.length > 0) {
    sectionTitle('§8  DFM Issues');
    bulletList(r.dfmIssues, s => {
      const l = s.toLowerCase();
      return l.includes('critical') || l.includes('error') ? RED_R : l.includes('warn') ? AMB_R : DARK;
    });
  }

  // ── §9 OPTIMISATION SUGGESTIONS ───────────────────────────────────────────────
  if (r.optimisationSuggestions.length > 0) {
    sectionTitle('§9  Optimisation Suggestions');
    bulletList(r.optimisationSuggestions, () => GRN_R);
  }

  // ── §10 ANALYSIS LIMITATIONS ──────────────────────────────────────────────────
  if (r.analysisLimitations.length > 0) {
    sectionTitle('§10  Analysis Limitations');
    bulletList(r.analysisLimitations, () => GREY);
  }

  // ── §11 UPLOADED BOARD IMAGES ─────────────────────────────────────────────────
  if (pcbUploadedImages.length > 0) {
    sectionTitle(`§11  Uploaded Board Images (${pcbUploadedImages.length})`);
    const gap = 5;
    const colW = (usable - gap) / 2;      // two images per row
    const maxCellH = 75;                  // cap image height (mm)
    for (let i = 0; i < pcbUploadedImages.length; i += 2) {
      const row = pcbUploadedImages.slice(i, i + 2);
      // Height of the tallest image in this row (drives page-break + label placement).
      const rowH = Math.min(maxCellH, Math.max(...row.map(im => colW * (im.h / Math.max(1, im.w)))));
      checkPage(rowH + 8);
      row.forEach((im, j) => {
        const x = margin + j * (colW + gap);
        let dw = colW;
        let dh = colW * (im.h / Math.max(1, im.w));
        if (dh > maxCellH) { dh = maxCellH; dw = maxCellH * (im.w / Math.max(1, im.h)); }
        try {
          doc.addImage(im.dataUrl, 'JPEG', x, y, dw, dh, undefined, 'FAST');
        } catch { /* skip an image that fails to embed */ }
        doc.setFontSize(7); doc.setTextColor(...GREY);
        doc.text(im.label, x, y + rowH + 4);
        doc.setTextColor(...DARK);
      });
      y += rowH + 8;
    }
  }

  addFooters();
  const fname = `pcb-analysis-${r.partName.replace(/[^a-z0-9]/gi, '-').toLowerCase()}-${new Date().toISOString().slice(0, 10)}.pdf`;
  doc.save(fname);
}

/**
 * Persist the PCB Image-to-Cost result into the Parts Library — the same store
 * every other commodity's "Save to Library" writes to — so the PCB should-cost
 * is retained in the system and appears in the dashboard / saved results.
 * (The BOM line items can additionally be pushed into a working costing via
 * "Apply to PCBA BOM + Assembly".)
 */
function savePCBResultToLibrary(): void {
  const r = pcbImageResult;
  if (!r) { showToast('Run a PCB analysis first', 'warning'); return; }
  const co = r.costEstimates;
  const total = co.totalBOMCostGBP + co.pcbFabGBP.mid + co.smtAssemblyCostGBP;
  const existing = getPartsLibrary();
  // Avoid an accidental duplicate of the exact same board+total saved moments ago.
  if (existing.some(x => x.commodity === 'pcba' && x.partName === r.partName && Math.abs(x.totalCost - total) < 0.005)) {
    showToast('This PCB result is already in your Parts Library', 'info');
    return;
  }
  existing.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    savedAt: Date.now(),
    projectName: '', partNumber: '', customer: '', vehicleProgramme: '', system: '',
    notes: `Imported from PCB Image-to-Cost — ${r.bom.length} BOM lines, ${r.assembly.smtPlacements} SMT placements`,
    partName: r.partName,
    commodity: 'pcba',
    totalCost: total,
    currency: 'GBP',
    region: (r._selectedCountry ?? 'cn').toUpperCase(),
    confidence: r.confidenceLevel ?? 'Medium',
    breakdown: {
      rawMaterial: co.totalBOMCostGBP,      // components (BOM)
      process: co.pcbFabGBP.mid,            // bare-board fabrication
      labour: co.smtAssemblyCostGBP,        // SMT + assembly
      tooling: 0, overhead: 0, packaging: 0, logistics: 0, margin: 0,
    },
  });
  savePartsLibrary(existing);
  showToast(`Saved "${r.partName}" to Parts Library (£${total.toFixed(2)}/board)`, 'info');
}

/**
 * Save the current calculated result to the Parts Library from the main action
 * row (works for every commodity, incl. a PCB BOM applied to the costing form).
 * Reuses the optional project/customer fields from the Library tab if present.
 */
function saveLastResultToLibrary(): void {
  if (!lastResult) { showToast('Run Calculate first, then save', 'warning'); return; }
  const partName = (document.getElementById('part-name') as HTMLInputElement)?.value || lastResult.partName || 'Part';
  const existing = getPartsLibrary();
  if (existing.some(r => r.partName === partName && r.commodity === activeCommodity && Math.abs(r.totalCost - lastResult!.total) < 0.005)) {
    showToast('This costing is already in your Parts Library', 'info');
    return;
  }
  const bkd = lastResult.breakdown;
  existing.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    savedAt: Date.now(),
    projectName: (document.getElementById('lib-project') as HTMLInputElement)?.value ?? '',
    partNumber:  (document.getElementById('lib-partno') as HTMLInputElement)?.value ?? '',
    customer:    (document.getElementById('lib-customer') as HTMLInputElement)?.value ?? '',
    vehicleProgramme: (document.getElementById('lib-vehicle-prog') as HTMLInputElement)?.value ?? '',
    system:      (document.getElementById('lib-system') as HTMLInputElement)?.value ?? '',
    notes:       (document.getElementById('lib-notes') as HTMLInputElement)?.value ?? '',
    partName,
    commodity:   activeCommodity,
    totalCost:   lastResult.total,
    currency:    _displayCurrency,
    region:      (document.getElementById('mfg-region-selector') as HTMLSelectElement)?.value ?? 'UK',
    confidence:  'Medium',
    breakdown:   bkd ? { rawMaterial: bkd.rawMaterial, process: bkd.process, labour: bkd.labour, tooling: bkd.tooling, overhead: bkd.overhead, packaging: bkd.packaging, logistics: bkd.logistics, margin: bkd.margin } : undefined,
  });
  savePartsLibrary(existing);
  showToast(`Saved "${partName}" to Parts Library`, 'info');
  if (document.getElementById('results-upload')) renderUploadPanel();
}

function applyPCBImageToFab(): void {
  if (!pcbImageResult) return;
  const b = pcbImageResult.boardSpec;

  const setF = (id: string, val: string | number) => {
    const el2 = document.getElementById(id) as HTMLInputElement | HTMLSelectElement | null;
    if (!el2) return;
    el2.value = String(val);
    el2.classList.add('ai-filled');
    el2.addEventListener('input', () => el2.classList.remove('ai-filled'), { once: true });
  };
  // Safe select setter: only assigns if the value is a valid <option>; logs a warning otherwise
  const setSelectSafe = (id: string, val: string, fallback: string) => {
    const sel = document.getElementById(id) as HTMLSelectElement | null;
    if (!sel) return;
    const valid = Array.from(sel.options).some(o => o.value === val);
    sel.value = valid ? val : fallback;
    sel.classList.add('ai-filled');
    if (!valid) console.warn(`[PCB→Fab] "${val}" is not a valid option for #${id} — defaulted to "${fallback}"`);
    sel.addEventListener('input', () => sel.classList.remove('ai-filled'), { once: true });
  };
  const setCheck = (id: string, val: boolean) => {
    const el2 = document.getElementById(id) as HTMLInputElement | null;
    if (el2) { el2.checked = val; el2.classList.add('ai-filled'); }
  };

  // Map Vision free-text HDI strings → engine enum
  const HDI_MAP: Record<string, string> = {
    'none': 'none',
    '1+n+1': '1plus_n_plus1',
    '1plus_n_plus1': '1plus_n_plus1',
    '2+n+2': '2plus_n_plus2',
    '2plus_n_plus2': '2plus_n_plus2',
    'any_layer': 'any_layer',
    'elic': 'any_layer',
    'any layer': 'any_layer',
  };
  const rawHdi = (b.hdiStructure ?? '').toLowerCase().replace(/\s+/g, ' ').trim();
  const mappedHdi = HDI_MAP[rawHdi] ?? (rawHdi.includes('2') ? '2plus_n_plus2' : rawHdi.includes('any') ? 'any_layer' : rawHdi.includes('1') ? '1plus_n_plus1' : 'none');

  // Map Vision surface finish values → engine enum (hard_gold → enepig as nearest equivalent)
  const FINISH_MAP: Record<string, string> = {
    'hasl': 'hasl',
    'hasl_lf': 'hasl_lf',
    'enig': 'enig',
    'osp': 'osp',
    'enepig': 'enepig',
    'iteq': 'iteq',
    'hard_gold': 'enepig',
    'hard gold': 'enepig',
    'immersion gold': 'enig',
    'immersion silver': 'hasl_lf',
  };
  const rawFinish = (b.surfaceFinish ?? '').toLowerCase().trim();
  const mappedFinish = FINISH_MAP[rawFinish] ?? 'enig';

  // Map Vision solder mask colour → form option values (lowercase, normalise)
  const MASK_MAP: Record<string, string> = {
    'green': 'green', 'black': 'black', 'white': 'white', 'red': 'red', 'blue': 'blue',
    'enig green': 'green', 'hasl green': 'green', 'yellow': 'green',
  };
  const rawMask = (b.solderMaskColour ?? '').toLowerCase().trim();
  const mappedMask = MASK_MAP[rawMask] ?? 'green';

  // Snap Vision's minTraceSpaceMm to nearest valid select option
  const VALID_TRACES = ['0.075', '0.10', '0.15', '0.20'];
  const nearestTrace = VALID_TRACES.reduce((prev, cur) =>
    Math.abs(parseFloat(cur) - b.minTraceSpaceMm) < Math.abs(parseFloat(prev) - b.minTraceSpaceMm) ? cur : prev
  );

  setSelectSafe('pcbf-technology', b.technologyType, 'HDI_RIGID');
  setSelectSafe('pcbf-quality', b.qualityGrade, 'auto_grade1');
  setF('pcbf-layers', String(b.estimatedLayers));
  setF('pcbf-board-w', b.widthMm);
  setF('pcbf-board-h', b.heightMm);
  setF('pcbf-panel-util', b.panelUtilisation);
  setSelectSafe('pcbf-cu', String(b.copperWeightOz), '1');
  setSelectSafe('pcbf-outer-cu', String(b.copperWeightOz), '1');
  setSelectSafe('pcbf-via-type', b.microVias > 0 ? 'microvia_hdi' : 'through_only', 'through_only');
  setSelectSafe('pcbf-hdi-structure', mappedHdi, 'none');
  setF('pcbf-vias', b.throughVias);
  setF('pcbf-blind-vias', b.blindVias);
  setF('pcbf-buried-vias', b.buriedVias);
  setF('pcbf-uvias', b.microVias);
  setSelectSafe('pcbf-trace', nearestTrace, '0.10');
  setSelectSafe('pcbf-finish', mappedFinish, 'enig');
  setSelectSafe('pcbf-solder-mask', mappedMask, 'green');
  setF('pcbf-silkscreen', String(b.silkscreenSides));
  setCheck('pcbf-impedance', b.impedanceControlRequired);
  setCheck('pcbf-bga', b.bgaDetected);

  // Infer Tg from technology
  const tgMap: Record<string, string> = { FR4_STD: '130', FR4_HTg: '150', HDI_RIGID: '170', RF_MICRO: '170' };
  setF('pcbf-tg', tgMap[b.technologyType] ?? '150');

  const partNameEl = el<HTMLInputElement>('part-name');
  if (partNameEl && pcbImageResult.partName) {
    partNameEl.value = pcbImageResult.partName;
    partNameEl.classList.add('ai-filled');
  }

  switchCommodity('pcb_fab');
}

function applyPCBImageToPCBA(): void {
  if (!pcbImageResult) return;
  const r = pcbImageResult;
  const a = r.assembly;

  const setF = (id: string, val: string | number) => {
    const el2 = document.getElementById(id) as HTMLInputElement | HTMLSelectElement | null;
    if (!el2) return;
    el2.value = String(val);
    el2.classList.add('ai-filled');
    el2.addEventListener('input', () => el2.classList.remove('ai-filled'), { once: true });
  };

  // Ensure we're on PCBA
  if (activeCommodity !== 'pcba') switchCommodity('pcba');

  setTimeout(() => {
    // Assembly parameters
    setF('pcba-complexity', a.complexity);
    setF('pcba-quality', r.boardSpec.qualityGrade);
    setF('pcba-smt-sides', String(a.reflowSides));
    setF('pcba-th-count', a.throughHoleJoints);
    setF('pcba-man-count', a.manualJoints);
    setF('pcba-bga-count', a.bgaCount);
    if (a.ictTimeSec > 0) setF('pcba-ict-time', a.ictTimeSec);

    // PCB cost from fab estimate mid
    setF('pcba-pcb-cost', r.costEstimates.pcbFabGBP.mid.toFixed(2));

    // Auto-set X-ray if BGAs detected
    if (a.bgaCount > 0) {
      const xrayEl = el<HTMLSelectElement>('pcba-xray-mach');
      if (xrayEl) {
        const xrayOpt = Array.from(xrayEl.options).find(o => o.value.includes('xray'));
        if (xrayOpt) xrayEl.value = xrayOpt.value;
      }
      const ictEl = el<HTMLSelectElement>('pcba-ict-mach');
      if (ictEl) {
        const ictOpt = Array.from(ictEl.options).find(o => o.value.includes('ict-auto'));
        if (ictOpt) ictEl.value = ictOpt.value;
      }
    }

    // Populate BOM table from image analysis
    const bomBody = el('bom-body');
    if (bomBody && r.bom.length > 0) {
      bomBody.innerHTML = '';
      bomCount = 0;
      for (const item of r.bom) {
        const validTypes: ComponentType[] = [
          'passive_0402','passive_0603','passive_0805',
          'crystal_osc','power_module','transformer','led','relay_switch','fuse_tvs',
          'ic_soic','ic_qfn','ic_bga','ic_tqfp',
          'connector_smt','through_hole','manual_solder',
        ];
        const isKnownType = validTypes.includes(item.componentType as ComponentType);
        const ct = isKnownType
          ? (item.componentType as ComponentType)
          : 'passive_0402';
        const descSuffix = !isKnownType
          ? ` ⚠ type "${item.componentType}" unrecognised — defaulted to 0402`
          : '';
        addBOMRow({
          refDes: item.refDes,
          componentType: ct,
          description: `${item.description}${item.pkg ? ` [${item.pkg}]` : ''}${item.value ? ` ${item.value}` : ''}${descSuffix}`,
          qty: item.qty,
          unitPriceGBP: item.unitPriceGBP,
          moq: item.moq,
        });
      }
    }

    const partNameEl = el<HTMLInputElement>('part-name');
    if (partNameEl && r.partName) {
      partNameEl.value = r.partName;
      partNameEl.classList.add('ai-filled');
    }
  }, 150);
}

function buildOCCTPanel(geo: OCCTGeometry | null, source: string): string {
  if (!geo || geo.status !== 'success') return '';

  const bb = geo.boundingBox!;
  const vol = geo.volume!;
  const sa = geo.surfaceArea!;
  const w = geo.weights!;
  const f = geo.features!;
  const faces = geo.faces!;

  const totalFaces = faces.total || 1;
  const faceEntries = Object.entries(faces.byType).sort(([, a], [, b]) => b - a);

  const barSegments = faceEntries.map(([k, v]) => {
    const pct = (v / totalFaces * 100).toFixed(1);
    const colour = FACE_COLOURS[k] ?? FACE_COLOURS.OTHER;
    return `<div class="occt-face-segment" style="width:${pct}%;background:${colour}" title="${k}: ${v} (${pct}%)"></div>`;
  }).join('');

  const legend = faceEntries.slice(0, 6).map(([k, v]) => {
    const colour = FACE_COLOURS[k] ?? FACE_COLOURS.OTHER;
    return `<span><span class="occt-legend-dot" style="background:${colour}"></span>${k} ${v}</span>`;
  }).join('');

  const mfgScore = geo.manufacturabilityScore;
  const mfgScoreClass = mfgScore === undefined ? '' : mfgScore >= 75 ? 'score-high' : mfgScore >= 50 ? 'score-med' : 'score-low';
  const warningBanners = [
    geo.assemblyWarning ? `<div class="occt-warning occt-warning--red">⚠ Assembly detected: ${geo.assemblyWarning} — costs shown per component</div>` : '',
    geo.unitWarning    ? `<div class="occt-warning occt-warning--orange">⚠ ${geo.unitWarning}</div>` : '',
  ].join('');

  return `
    <div class="occt-panel">
      ${warningBanners}
      <div class="occt-panel-header">
        Geometry — Open CASCADE Kernel
        <span class="occt-source-badge ${source === 'occt' ? 'occt' : 'text'}">Precise</span>
        ${mfgScore !== undefined ? `<span class="occt-mfg-score ${mfgScoreClass}" title="Geometry-derived manufacturability score">MFG ${mfgScore}/100</span>` : ''}
      </div>
      <div class="occt-stat-grid">
        <div class="occt-stat">
          <div class="occt-stat-value">${bb.xMm}×${bb.yMm}×${bb.zMm}</div>
          <div class="occt-stat-label">Bounding box (mm)</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${vol.cm3.toFixed(2)} cm³</div>
          <div class="occt-stat-label">True volume</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${sa.cm2.toFixed(0)} cm²</div>
          <div class="occt-stat-label">True surface area</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${(geo.fillRatio! * 100).toFixed(1)}%</div>
          <div class="occt-stat-label">Fill ratio</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.wallThickness ? geo.wallThickness.meanMm.toFixed(2) + ' mm' : '—'}</div>
          <div class="occt-stat-label">Mean wall thickness${geo.wallThickness ? ` (${geo.wallThickness.method === 'ray_cast' ? 'ray-cast' : 'formula'})` : ''}</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.wallThickness ? `${geo.wallThickness.minMm.toFixed(1)}–${geo.wallThickness.maxMm.toFixed(1)} mm` : '—'}</div>
          <div class="occt-stat-label">Wall thickness range</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.draftAnalysis ? (geo.draftAnalysis.undercutFaceCount > 0 ? `⚠ ${geo.draftAnalysis.undercutFaceCount}` : '0') : '—'}</div>
          <div class="occt-stat-label">Undercut faces</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.draftAnalysis ? `${geo.draftAnalysis.minPositiveDraftDeg?.toFixed(1) ?? '?'}°–${geo.draftAnalysis.maxPositiveDraftDeg?.toFixed(1) ?? '?'}°` : '—'}</div>
          <div class="occt-stat-label">Draft angle range</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.setupAnalysis ? geo.setupAnalysis.estimatedSetupCount : '—'}</div>
          <div class="occt-stat-label">Est. CNC setups</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${geo.cncCycleTimeEstimate ? geo.cncCycleTimeEstimate.estimatedTotalHrs.toFixed(3) + ' hr' : '—'}</div>
          <div class="occt-stat-label">CNC cycle estimate</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${w.aluminiumKg.toFixed(3)} kg</div>
          <div class="occt-stat-label">Al weight (2.70 g/cm³)</div>
        </div>
        <div class="occt-stat">
          <div class="occt-stat-value">${w.steelKg.toFixed(3)} kg</div>
          <div class="occt-stat-label">Steel weight (7.85 g/cm³)</div>
        </div>
      </div>
      <div style="font-size:0.7rem;color:var(--text-muted);margin-bottom:4px">
        Face topology — ${faces.total} faces total
        ${f.estimatedHoleCount > 0 ? `· ${f.estimatedHoleCount} holes [${f.holeRadiiMm.slice(0,5).join(', ')} mm]` : ''}
        ${f.bossShaftRadiiMm.length > 0 ? `· bosses [${f.bossShaftRadiiMm.join(', ')} mm]` : ''}
        ${f.threadFeaturesDetected ? '· <strong>threads detected</strong>' : ''}
        ${geo.draftAnalysis?.undercutFaceCount ? `· <span style="color:#ef4444"><strong>${geo.draftAnalysis.undercutFaceCount} undercuts</strong></span>` : ''}
      </div>
      <div class="occt-face-bar">${barSegments}</div>
      <div class="occt-face-legend">${legend}</div>
      ${buildFeatureOpsTable(geo)}
    </div>`;
}

/** Exact geometry → operations table: every hole/boss with Ø, depth, through/blind
 *  and the operation it implies. This is measured kernel data, not AI estimation. */
function buildFeatureOpsTable(geo: OCCTGeometry): string {
  const rows = geo.featureTable ?? [];
  if (!rows.length) return '';
  const totalOps = rows.filter(r => r.kind === 'hole').reduce((s, r) => s + r.count, 0);
  return `
    <div style="margin-top:10px">
      <div style="font-size:0.78rem;font-weight:700">🔩 Geometry Feature Table <span style="font-weight:400;color:var(--text-muted)">(exact, from B-rep — ${totalOps} hole operations)</span></div>
      <table class="data-table" style="margin-top:6px;font-size:0.74rem;font-variant-numeric:tabular-nums">
        <thead><tr><th>Feature</th><th>Ø (mm)</th><th>Depth (mm)</th><th>Type</th><th>Qty</th><th>→ Operation</th></tr></thead>
        <tbody>
          ${rows.map(r => `<tr>
            <td>${r.kind === 'hole' ? '◎ Hole' : r.kind === 'boss' ? '⬤ Boss' : r.kind === 'face' ? '▭ Face' : r.kind === 'pocket' ? '⬒ Pocket' : '▬ Slot'}</td>
            <td>${r.kind === 'hole' || r.kind === 'boss' ? r.diaMm.toFixed(2) : (r.areaMm2 ? Math.round(r.areaMm2) + ' mm²' : '—')}</td>
            <td>${r.depthMm > 0 ? r.depthMm.toFixed(1) : '—'}</td>
            <td>${r.kind === 'hole' ? (r.through ? 'through' : 'blind') : '—'}</td>
            <td>${r.count}</td>
            <td>${featureToOperation(r)}</td>
          </tr>`).join('')}
        </tbody>
      </table>
    </div>`;
}

// ─── Feature-based secondary machining (casting / forging etc.) ───────────────
// Prices the CNC machining a near-net cast/forged part still needs at its
// functional features (bores, drilled holes, turned bosses) and folds that cost
// into the total — the accuracy gap that pure weight-based costing misses.
// `prefix` is the form id root: 'cast' | 'forge'.

/** Empty container the CAD-apply step populates from the geometry feature table. */
function renderMachinedFeaturesPanel(prefix: string): string {
  return `
    <details id="${prefix}-mf-details" style="margin-top:8px" open>
      <summary style="font-weight:700;font-size:0.78rem;cursor:pointer;color:var(--accent)">🛠 Machined Features from Geometry <span style="font-weight:400;color:var(--text-muted)">— secondary machining on the near-net part</span></summary>
      <div id="${prefix}-mf-body" style="margin-top:6px">
        <div style="font-size:0.72rem;color:var(--text-muted)">Upload a CAD file (STEP/IGES) on this form to auto-detect machined features (bores, holes, bosses) and add their machining cost to the total.</div>
      </div>
    </details>`;
}

/** Fill the panel from cadOCCTGeometry.featureTable with per-feature toggles. */
/** True when the machining form's ops are anchored to the OCCT bottom-up cycle
 *  total (which already covers every feature). */
function machiningHasOcctCycleTotal(): boolean {
  return !!(cadOCCTGeometry?.cncCycleTimeEstimate?.estimatedTotalHrs);
}

/** True when the engineer has toggled feature machining to be the PRIMARY cost. */
function machiningFeaturePrimary(): boolean {
  return (document.getElementById('mach-mf-primary') as HTMLInputElement | null)?.checked ?? false;
}

/** Human explanation of the current machining feature-panel mode. */
function machiningFeatureModeText(primary: boolean): string {
  if (primary) return `<strong>Primary</strong> — feature machining is the cost basis; the operations table above is ignored.`;
  return machiningHasOcctCycleTotal()
    ? `<strong>Audit view</strong> — these features are already in the CNC cycle-time estimate above (OCCT bottom-up), so they are not added again.`
    : `<strong>Fallback</strong> — no OCCT cycle estimate for this upload, so the ticked features are added as machining cost.`;
}

function populateMachinedFeatures(prefix: string): void {
  const body = document.getElementById(`${prefix}-mf-body`);
  if (!body) return;
  const rows = cadOCCTGeometry?.featureTable ?? [];
  if (!rows.length) {
    body.innerHTML = `<div style="font-size:0.72rem;color:var(--text-muted)">No machinable features detected in the geometry (no bores, holes or bosses).</div>`;
    return;
  }
  const totalHoles = rows.filter(r => r.kind === 'hole').reduce((s, r) => s + r.count, 0);
  const nonHole = rows.filter(r => r.kind !== 'hole').reduce((s, r) => s + r.count, 0);
  const icon = (k: string) => k === 'hole' ? '◎ Hole' : k === 'boss' ? '⬤ Boss' : k === 'face' ? '▭ Face' : k === 'pocket' ? '⬒ Pocket' : k === 'slot' ? '▬ Slot' : k;
  const dims = (r: FeatureRow) => r.kind === 'hole'
    ? `Ø${r.diaMm.toFixed(1)} × ${r.depthMm.toFixed(0)} ${r.through ? '(thru)' : '(blind)'}`
    : r.kind === 'boss' ? `Ø${r.diaMm.toFixed(1)} × ${r.depthMm.toFixed(0)}`
    : `${Math.round(r.areaMm2 ?? 0)} mm²${r.depthMm > 0 ? ` × ${r.depthMm.toFixed(0)}` : ''}`;
  // On the machining form the panel has three modes (see machiningFeatureModeText):
  //  · Primary  — the engineer's toggle: feature machining REPLACES the ops table.
  //  · Audit    — OCCT cycle total already covers the features (not added again).
  //  · Fallback — no OCCT cycle estimate, so the ticked features are added.
  const machNote = prefix === 'mach'
    ? `<label style="display:flex;align-items:center;gap:6px;font-size:0.72rem;margin-bottom:4px;cursor:pointer">
         <input type="checkbox" id="mach-mf-primary"/> Cost machining from these features (<strong>primary</strong> — replaces the operations table)
       </label>
       <div id="mach-mf-mode" style="font-size:0.7rem;color:var(--text-muted);margin-bottom:6px">${machiningFeatureModeText(false)}</div>`
    : '';
  body.innerHTML = `
    ${machNote}
    <div style="font-size:0.72rem;color:var(--text-secondary);margin-bottom:6px">
      ${totalHoles} hole/bore feature(s)${nonHole ? ` + ${nonHole} boss/face/pocket` : ''} from the B-rep.
      Near-net: holes are ticked (bosses/faces/pockets may be as-cast — tick the machined ones).
      Switch <strong>Stock condition</strong> to “machined from solid” and every feature is auto-ticked (all cut from the billet).
    </div>
    <table class="data-table" style="font-size:0.72rem;font-variant-numeric:tabular-nums;width:100%">
      <thead><tr><th></th><th>Feature</th><th>Ø×depth / area</th><th>Qty</th><th>→ Operation</th></tr></thead>
      <tbody>
        ${rows.map((r, i) => `<tr>
          <td><input type="checkbox" class="${prefix}-mf-chk" data-idx="${i}" ${defaultInclude(r as FeatureRow, 'near_net') ? 'checked' : ''}/></td>
          <td>${icon(r.kind)}</td>
          <td>${dims(r as FeatureRow)}</td>
          <td>${r.count}</td>
          <td>${featureToOperation(r as FeatureRow)}</td>
        </tr>`).join('')}
      </tbody>
    </table>
    <div class="field-row" style="margin-top:6px">
      <div class="field-group"><label>Machine</label><select id="${prefix}-mf-mach" class="machine-select"></select></div>
      <div class="field-group"><label>Labour</label><select id="${prefix}-mf-lab" class="labour-select"></select></div>
    </div>
    <div class="field-row" style="margin-top:4px">
      <div class="field-group"><label>Stock condition</label><select id="${prefix}-mf-stock">
        <option value="near_net" selected>Near-net (cast/forged — holes cored in, no extra material)</option>
        <option value="solid_billet">Machined from solid (charge removed metal)</option>
      </select></div>
      <div class="field-group"><label>Finish</label><select id="${prefix}-mf-finish">
        <option value="1.0" selected>General machining ×1.0</option>
        <option value="1.3">Reamed / precision ×1.3</option>
        <option value="1.6">Ground / tight tol. ×1.6</option>
      </select></div>
    </div>
    <div class="field-row" style="margin-top:4px">
      <div class="field-group"><label>Machining fixtures + CNC programming NRE (₹)</label><input type="number" id="${prefix}-mf-tooling" min="0" step="1000" value="150000"/></div>
    </div>
    <div id="${prefix}-mf-readout" style="margin-top:6px;font-size:0.74rem;font-weight:600;color:var(--accent)"></div>`;
  populateSelects();
  // default machine/labour to a CNC cell
  const machSel = el<HTMLSelectElement>(`${prefix}-mf-mach`); if (machSel) machSel.value = resolveMachineIdForOp('mach-vmc3', 'CNC Milling');
  const labSel = el<HTMLSelectElement>(`${prefix}-mf-lab`); if (labSel) labSel.value = resolveLabourId('lab-uk-skilled');
  const refresh = () => updateMachinedFeaturesReadout(prefix);
  // Switching stock condition re-applies the smart default: machined-from-solid
  // ticks every feature (all cut from the billet); near-net reverts to holes-only.
  const stockSel = el<HTMLSelectElement>(`${prefix}-mf-stock`);
  stockSel?.addEventListener('change', () => {
    const stock = (stockSel.value || 'near_net') as StockCondition;
    rows.forEach((r, i) => {
      const box = body.querySelector(`.${prefix}-mf-chk[data-idx="${i}"]`) as HTMLInputElement | null;
      if (box) box.checked = defaultInclude(r as FeatureRow, stock);
    });
    refresh();
  });
  body.querySelectorAll(`.${prefix}-mf-chk, #${prefix}-mf-stock, #${prefix}-mf-finish`).forEach(elm => elm.addEventListener('change', refresh));
  // Machining: the "primary" toggle switches the cost basis to features; update the
  // live mode line so the engineer sees whether the ops table is being ignored.
  if (prefix === 'mach') {
    const primaryChk = document.getElementById('mach-mf-primary') as HTMLInputElement | null;
    const modeEl = document.getElementById('mach-mf-mode');
    primaryChk?.addEventListener('change', () => {
      if (modeEl) {
        const on = primaryChk.checked;
        modeEl.innerHTML = machiningFeatureModeText(on);
        modeEl.style.color = on ? 'var(--accent)' : 'var(--text-muted)';
      }
      refresh();
    });
  }
  refresh();
}

/** Read the panel and build secondary machining ops (null if none active). */
function collectSecondaryMachining(prefix: string): { ops: OperationInput[]; toolingCost: number; result: ReturnType<typeof computeFeatureMachining> } | null {
  const rows = (cadOCCTGeometry?.featureTable ?? []) as FeatureRow[];
  if (!rows.length) return null;
  const body = document.getElementById(`${prefix}-mf-body`);
  if (!body) return null;
  const includeFlags = rows.map((_, i) =>
    (body.querySelector(`.${prefix}-mf-chk[data-idx="${i}"]`) as HTMLInputElement | null)?.checked ?? false);
  const machineId = sel(`${prefix}-mf-mach`) || resolveMachineIdForOp('mach-vmc3', 'CNC Milling');
  const labourId = sel(`${prefix}-mf-lab`) || resolveLabourId('lab-uk-skilled');
  const stockCondition = (sel(`${prefix}-mf-stock`) || 'near_net') as StockCondition;
  const finishFactor = parseFloat(sel(`${prefix}-mf-finish`)) || 1.0;
  const result = computeFeatureMachining(rows, { machineId, labourId, includeFlags, stockCondition, finishFactor });
  if (result.featureCount === 0) return null;
  const toolingCost = num(`${prefix}-mf-tooling`);
  return { ops: result.operations, toolingCost, result };
}

/** Live "adds N min / ₹ machining" readout in the panel. */
function updateMachinedFeaturesReadout(prefix: string): void {
  const out = document.getElementById(`${prefix}-mf-readout`);
  if (!out) return;
  const c = collectSecondaryMachining(prefix);
  if (!c) { out.textContent = 'No features selected — no machining cost added.'; return; }
  const mins = (c.result.totalCycleHr * 60).toFixed(1);
  const matNote = c.result.materialRemovedKg > 0 ? ` · ${c.result.materialRemovedKg.toFixed(3)} kg metal removed` : ' · near-net (no extra material)';
  out.textContent = `⇒ Adds ${c.result.featureCount} machined feature(s): ${mins} min CNC time${matNote}. Included in the total on Calculate.`;
}

// Provenance classification for CAD-filled fields. Geometry-derived quantities
// (weights, dimensions, volumes) are MEASURED when the OCCT/STL engine parsed
// the file; everything the AI inferred (material, cycle times, tooling, rates)
// is ESTIMATED and worth reviewing. Centralised here so every fill site gets
// classified without per-call changes.
// Geometry-derived fields are MEASURED when a kernel parsed the file. `-wt`
// catches every commodity's weight field (cast-part-wt, cam-cast-wt/-finish-wt,
// forge-part-wt, mach-net-wt/-stock-wt) — previously only mach-* matched, so the
// casting/forging weight was miscounted as AI-estimated ("0 measured").
const CAD_MEASURED_ID = /(-wt\b|net-wt|stock-wt|weight|-vol\b|volume|length|width|height|-len\b|thk|thickness|dia\b|diameter|area)/i;
function classifyCADProvenance(id: string): 'measured' | 'estimated' {
  if (cadGeometrySource === 'text_parsing') return 'estimated'; // no measured geometry available
  return CAD_MEASURED_ID.test(id) ? 'measured' : 'estimated';
}

type CADMatFamily = MaterialFamily | 'other';

/** Coarse material family from a density (shared engine helper). */
function cadFamilyFromDensity(dens?: number): CADMatFamily {
  return familyFromDensity(dens);
}

/** The family the AI's cost actually assumes — density first, then material-id and
 *  commodity fallbacks so an unresolved id (e.g. mat-pa6) still classifies. */
function cadChosenFamily(r: CADAnalysisResult): CADMatFamily {
  const byDens = cadFamilyFromDensity(library.materials.find(m => m.id === r.costInputSuggestions.materialId)?.densityKgPerM3);
  if (byDens !== 'other') return byDens;
  const id = (r.costInputSuggestions.materialId || '').toLowerCase();
  if (/pa6|pa66|nylon|abs|polycarb|-pc\b|-pp\b|peek|pom|acetal|delrin|resin|plastic/.test(id)) return 'plastic';
  if (/-al|alsi|6061|7075|6082|lm25|adc12|a3\d0|silafont|aural|castasil/.test(id)) return 'aluminium';
  if (/steel|1045|4140|en8|42crmo|scm440|ss3|ss4|17-4/.test(id)) return 'steel';
  if (/gjl|gjs|gjv|iron|\badi\b/.test(id)) return 'cast iron';
  const comm = (r.costInputSuggestions.recommendedCommodity || '').toLowerCase();
  if (/mould|mold|thermoform|rubber|rotational/.test(comm)) return 'plastic';
  return 'other';
}

/** Material family named in the CAD filename, if any — a strong human hint the AI
 *  must not silently override (the "Aluminium_…" file classified as plastic bug). */
function cadFilenameMaterialFamily(): CADMatFamily | null {
  return familyFromFilename(cadFile?.name || '');
}

/** Grams for sub-kg parts, kg otherwise — small machined parts weigh grams. */
function fmtMass(kg: number): string { return kg < 1 ? `${(kg * 1000).toFixed(0)} g` : `${kg.toFixed(2)} kg`; }

/**
 * Material-ambiguity flag: CAD geometry fixes the SHAPE but not the material.
 * Two failure modes:
 *   1. Filename CONTRADICTION — the file is named for a material ("Aluminium…")
 *      but the analysis chose a different family (plastic). Strongest signal.
 *   2. Inferred-from-shape — no photo, no metadata, no filename hint: the same
 *      solid spans plastic → aluminium → steel (~8× by mass), so the chosen
 *      material and therefore the whole cost (process, tooling, price) are a guess.
 * Returns an HTML advisory string, or null when it doesn't apply.
 */
function cadMaterialAmbiguityAsk(r: CADAnalysisResult): string | null {
  if (cadGeometrySource === 'text_parsing') return null;   // geometry itself unmeasured — different problem
  const w = cadOCCTGeometry?.weights;
  if (!w || !(w.aluminiumKg > 0) || !(w.steelKg > 0)) return null;
  const chosen = cadChosenFamily(r);
  if (chosen === 'other') return null;
  const plasticKg = w.plasticKg ?? w.aluminiumKg * 0.4;
  const span = `<strong>Plastic ${fmtMass(plasticKg)} &middot; Aluminium ${fmtMass(w.aluminiumKg)} &middot; Steel ${fmtMass(w.steelKg)}</strong>`;

  // 1) Filename contradiction.
  const fileFam = cadFilenameMaterialFamily();
  if (fileFam && fileFam !== chosen) {
    return `&#9888; <strong>Filename says ${fileFam}, but the analysis chose ${chosen}</strong> — the file is named `
      + `"<em>${escHtml(cadFile?.name || '')}</em>" yet the cost assumes <strong>${chosen}</strong>, which drives a different process, tooling and price. `
      + `The same solid weighs ${span}. Pin <strong>${fileFam}</strong> in <em>Re-Analyse / Adjust</em> below, or add a part photo and re-analyse.`;
  }
  if (fileFam && fileFam === chosen) return null;          // filename confirms the choice — not ambiguous

  // 2) Inferred from shape alone.
  if (r.materialAnalysis?.fromMetadata) return null;       // alloy came from CAD metadata
  if (cadPartPhotoDataUrlPresent()) return null;           // engineer supplied a visual hint
  const chosenKg = chosen === 'plastic' ? plasticKg
    : chosen === 'aluminium' ? w.aluminiumKg
    : chosen === 'steel' ? w.steelKg
    : chosen === 'cast iron' ? (w.castIronKg ?? w.steelKg * 0.92)
    : w.steelKg;
  return `&#9878; <strong>Material inferred from shape alone</strong> — geometry can't tell plastic from metal, and the same solid weighs `
    + `${span}. This cost assumes <strong>${chosen} (${fmtMass(chosenKg)})</strong>; if the real material differs the process, tooling and cost change completely. `
    + `Add a part photo above and re-analyse, or pin the correct grade in <em>Re-Analyse / Adjust</em> below.`;
}

function markAIFilled(element: HTMLInputElement | HTMLSelectElement | null): void {
  if (!element) return;
  element.classList.add('ai-filled');
  const prov = classifyCADProvenance(element.id || '');
  element.setAttribute('data-prov', prov);
  element.title = prov === 'measured'
    ? 'Measured — derived from the CAD file geometry (OCCT/STL kernel)'
    : 'AI-estimated — suggested by the analysis; review before calculating';
  // Remove highlight after user edits (their value now — no longer AI provenance)
  element.addEventListener('input', () => { element.classList.remove('ai-filled'); element.removeAttribute('data-prov'); }, { once: true });
}

/** Banner summarising provenance after a CAD auto-fill: how much is measured vs estimated. */
function showCADProvenanceBanner(): void {
  document.getElementById('cad-prov-banner')?.remove();
  const panel = document.querySelector('.input-panel');
  if (!panel) return;
  const measured = panel.querySelectorAll('[data-prov="measured"]').length;
  const estimated = panel.querySelectorAll('[data-prov="estimated"]').length;
  if (measured + estimated === 0) return;
  const div = document.createElement('div');
  div.id = 'cad-prov-banner';
  div.style.cssText = 'margin:8px 0;padding:9px 12px;background:var(--info-bg,#eff6ff);border:1px solid var(--info-border,#bfdbfe);border-radius:8px;font-size:0.74rem;color:var(--text-secondary);display:flex;align-items:center;gap:8px;flex-wrap:wrap';
  div.innerHTML = `<strong style="color:var(--text-primary)">CAD auto-fill:</strong>` +
    `<span><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#16a34a;margin-right:4px"></span>${measured} measured (geometry)</span>` +
    `<span><span style="display:inline-block;width:9px;height:9px;border-radius:50%;background:#d97706;margin-right:4px"></span>${estimated} AI-estimated — review before calculating</span>` +
    `<button style="margin-left:auto;background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:0.9rem;line-height:1" title="Dismiss" onclick="this.parentElement.remove()">&#10005;</button>`;
  const anchor = document.getElementById('commodity-tabs');
  if (anchor?.parentElement) anchor.parentElement.insertBefore(div, anchor.nextSibling);
  else panel.prepend(div);
}

function cadPartPhotoDataUrlPresent(): boolean { return cadPartPhotoBase64.length > 0; }

function setMaterial(selectEl: HTMLSelectElement | null, materialId: string): void {
  if (!selectEl || !materialId) return;
  const opt = Array.from(selectEl.options).find(o => o.value === materialId);
  if (opt) { selectEl.value = opt.value; markAIFilled(selectEl); }
}

function setNumericField(id: string, value: number | null | undefined, decimals = 3): void {
  const el2 = el<HTMLInputElement>(id);
  // Skip non-finite values (the AI omits fields per response — a missing mouldLife
  // must not crash the whole apply/calculate with `undefined.toFixed`). The field
  // keeps its form default instead.
  if (el2 && Number.isFinite(value as number)) { el2.value = (value as number).toFixed(decimals); markAIFilled(el2); }
}

// ─── Inline CAD-to-fill (per-commodity uploader) ──────────────────────────────
// Geometry-relevant commodities get a small "Upload CAD" panel on their form that
// reuses the CAD-to-Cost OCCT pipeline and applyCADToForm() mapping.
const CAD_INLINE_COMMODITIES = new Set<CommodityType>([
  'machining', 'casting', 'cast_and_machine', 'forging', 'sheet_metal', 'sheet_metal_fab',
  'injection_moulding', 'blow_moulding', 'extrusion', 'thermoforming', 'rotational_moulding', 'rubber', 'composites',
]);

function inlineCADPanelHTML(): string {
  return `
    <details class="cad-inline-panel" style="margin:0 0 10px;border:1px dashed var(--border-strong);border-radius:8px;background:var(--surface-elevated)">
      <summary style="cursor:pointer;padding:8px 12px;font-size:0.8rem;font-weight:600;color:var(--accent);user-select:none">📐 Upload CAD to auto-fill this form <span style="font-weight:400;color:var(--text-secondary)">— STEP / IGES → real weight, size &amp; inputs</span></summary>
      <div style="padding:2px 12px 12px">
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <input type="file" id="cad-inline-input" accept=".step,.stp,.iges,.igs,.brep,.stl,.obj" style="font-size:0.72rem"/>
          <button class="btn btn-secondary btn-sm" id="cad-inline-btn" disabled style="font-size:0.72rem">Analyze &amp; Fill</button>
        </div>
        <div id="cad-inline-status" style="margin-top:6px;font-size:0.7rem;color:var(--text-secondary);line-height:1.45">Solid formats (STEP/IGES) give true volume &amp; weight; STL/OBJ meshes are approximate.</div>
        <div id="cad-inline-viewer-host" style="display:none;margin-top:8px"></div>
      </div>
    </details>`;
}

function wireInlineCAD(commodity: CommodityType): void {
  const input = el<HTMLInputElement>('cad-inline-input');
  const btn = el<HTMLButtonElement>('cad-inline-btn');
  const status = el('cad-inline-status');
  if (!input || !btn) return;
  let picked: File | null = null;
  input.addEventListener('change', () => {
    picked = input.files?.[0] ?? null;
    btn.disabled = !picked;
    if (status) status.textContent = picked ? `${picked.name} (${(picked.size / 1024).toFixed(0)} KB) — click Analyze & Fill` : '';
    if (picked && /\.(stl|stp|step|igs|iges)$/i.test(picked.name)) {
      void mountCADViewer('cad-inline-viewer-host', picked, true); // compact 3D viewer under the form
    }
  });
  btn.addEventListener('click', () => { if (picked) void analyzeCADInline(picked, commodity); });
}

async function analyzeCADInline(file: File, commodity: CommodityType): Promise<void> {
  const status = el('cad-inline-status');
  const btn = el<HTMLButtonElement>('cad-inline-btn');
  const setStatus = (t: string) => { if (status) status.textContent = t; };
  cadFile = file;
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Analyzing…'; }
  setStatus('Uploading & running the OCCT geometry engine… (can take ~20–60 s)');
  try {
    const annVol = el<HTMLInputElement>('annual-volume')?.value || '100000';
    const fd = new FormData();
    fd.append('cadFile', file);
    fd.append('commodity', commodity);   // tell the AI the target process so it suggests matching inputs
    fd.append('annualVolume', annVol);
    if (cadPartPhotoBase64) { fd.append('partPhotoBase64', cadPartPhotoBase64); fd.append('partPhotoMime', cadPartPhotoMime); }
    const apiKey = sessionStorage.getItem('cad-api-key') ?? '';
    const headers: HeadersInit = {};
    if (apiKey) headers['x-api-key'] = apiKey;
    const controller = new AbortController();
    const to = setTimeout(() => controller.abort(new DOMException('Timed out after 150 s', 'TimeoutError')), 150_000);
    const res = await fetch('/api/cad/analyze', { method: 'POST', headers, body: fd, signal: controller.signal });
    clearTimeout(to);
    const data = await res.json() as { success?: boolean; analysis?: CADAnalysisResult; occtGeometry?: OCCTGeometry | null; geometrySource?: 'occt' | 'text_parsing'; error?: string };
    if (!res.ok || !data.success || !data.analysis) throw new Error(data.error ?? `Server error ${res.status}`);
    cadAnalysisResult = data.analysis;
    cadOCCTGeometry = data.occtGeometry ?? null;
    cadGeometrySource = data.geometrySource ?? 'text_parsing';
    const g = data.analysis.geometry;
    applyCADToForm(commodity);   // re-renders this form and fills it from the geometry
    showToast(`CAD applied — ${data.geometrySource === 'occt' ? 'OCCT solid geometry' : 'text-parsed'}: ${g.estimatedVolumeCm3.toFixed(1)} cm³, net ${data.analysis.costInputSuggestions.netWeightKg.toFixed(3)} kg`, 'info');
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    setStatus(`⚠ ${msg.slice(0, 160)}`);
    showToast(`CAD analysis failed: ${msg.slice(0, 80)}`, 'error');
    if (btn) { btn.disabled = false; btn.textContent = 'Analyze & Fill'; }
  }
}

/** Map an AI-suggested machineId to a REAL rate-library machine. The model
 *  occasionally invents ids ("mach-5ax", "5-axis CNC") — an unknown id left
 *  the machine select empty and Calculate failed with "Machine '' not found
 *  in rate library". Resolve by keywords from the id + operation name. */
function resolveMachineIdForOp(rawId: string | undefined, opName: string): string {
  const ids = library.machines.map(m => m.id);
  if (rawId && ids.includes(rawId)) return rawId;
  const hay = `${rawId ?? ''} ${opName}`.toLowerCase();
  const pick = (...frags: string[]) => ids.find(id => frags.some(f => id.includes(f)));
  if (/5[\s-]?ax|5axis|umc|dmu/.test(hay)) return pick('vmc5', 'umc', 'dmu') ?? pick('vmc') ?? ids[0] ?? '';
  if (/lathe|turn/.test(hay)) return pick('lathe', 'qt200') ?? pick('vmc') ?? ids[0] ?? '';
  if (/drill|bore|ream|tap/.test(hay)) return pick('drill') ?? pick('vmc') ?? ids[0] ?? '';
  if (/grind|hone|lap/.test(hay)) return pick('grind') ?? pick('vmc') ?? ids[0] ?? '';
  if (/spot|mig|tig|weld|robot/.test(hay)) return pick('weld', 'robot', 'mig') ?? pick('vmc') ?? ids[0] ?? '';
  if (/bench|assembl|inspect|fixtur/.test(hay)) return pick('bench', 'assembly') ?? pick('vmc') ?? ids[0] ?? '';
  return pick('vmc3') ?? pick('vmc') ?? ids[0] ?? '';
}

/** Same guarantee for labourId — unknown ids fall back to the skilled rate. */
function resolveLabourId(rawId: string | undefined): string {
  const ids = library.labour.map(l => l.id);
  if (rawId && ids.includes(rawId)) return rawId;
  return ids.find(id => id.endsWith('-skilled')) ?? ids[0] ?? '';
}

// Assigning a non-existent option value to a <select> silently leaves it EMPTY
// (value '', selectedIndex -1) — the root cause of "Machine '' not found in
// rate library" at Calculate time. These setters/readers make that state
// unrepresentable: every path that writes or reads an op-card machine/labour
// select goes through resolution, so an invented AI id, a stale draft, or an
// old bundle can no longer produce an empty select.

function setMachineSelect(selectId: string, rawId: string | undefined, opName: string): void {
  const s = el<HTMLSelectElement>(selectId);
  if (!s) return;
  if (rawId) s.value = rawId;
  if (!s.value) s.value = resolveMachineIdForOp(rawId, opName);
  if (!s.value && s.options.length > 0) s.selectedIndex = 0;
}

function setLabourSelect(selectId: string, rawId: string | undefined): void {
  const s = el<HTMLSelectElement>(selectId);
  if (!s) return;
  if (rawId) s.value = rawId;
  if (!s.value) s.value = resolveLabourId(rawId);
  if (!s.value && s.options.length > 0) s.selectedIndex = 0;
}

let _lastHealToastAt = 0;
function _notifyRateHeal(kind: 'machine' | 'labour', selectId: string, healedTo: string): void {
  console.warn(`[rate-heal] ${kind} select #${selectId} was empty/unknown — auto-assigned '${healedTo}' from the rate library`);
  const now = Date.now();
  if (now - _lastHealToastAt > 4000) {
    _lastHealToastAt = now;
    showToast('An operation had a missing machine/labour rate — auto-assigned the closest match from the rate library', 'info');
  }
}

/** Read a machine <select> at Calculate time, healing empty/unknown values in
 *  place. Covers every entry path: AI apply, draft restore, stale bundle,
 *  manual edits, country/library switches. */
function selMachineHealed(selectId: string, opName: string): string {
  const s = el<HTMLSelectElement>(selectId);
  if (!s) return '';
  if (s.value && library.machines.some(m => m.id === s.value)) return s.value;
  const healed = resolveMachineIdForOp(s.value || undefined, opName);
  if (healed) { s.value = healed; _notifyRateHeal('machine', selectId, healed); }
  return healed;
}

function selLabourHealed(selectId: string): string {
  const s = el<HTMLSelectElement>(selectId);
  if (!s) return '';
  if (s.value && library.labour.some(l => l.id === s.value)) return s.value;
  const healed = resolveLabourId(s.value || undefined);
  if (healed) { s.value = healed; _notifyRateHeal('labour', selectId, healed); }
  return healed;
}

/** A sensible default grade id for a material family + commodity, used only when
 *  the AI returns the right commodity but leaves materialId blank. '' if none fits. */
function _fallbackMaterialIdForFamily(fam: MaterialFamily | null, commodity: CommodityType): string {
  if (!fam) return '';
  const cast = /cast|forg/.test(commodity);
  const map: Record<MaterialFamily, string> = cast
    ? { aluminium: 'mat-lm25', magnesium: 'mat-mag-am60', titanium: '', 'cast iron': 'mat-gjs500', steel: 'mat-steel1045', 'copper alloy': '', plastic: '' }
    : { aluminium: 'mat-al6061', magnesium: 'mat-mag-am60', titanium: 'mat-ti6al4v', 'cast iron': 'mat-steel1045', steel: 'mat-steel1045', 'copper alloy': 'mat-brass-cz121', plastic: 'mat-pa6' };
  const id = map[fam] || '';
  return id && library.materials.some(m => m.id === id) ? id : '';
}

/** Single source of truth: every commodity's tooling-amortisation input field.
 *  Used to sync amort to the user's annual volume for ALL commodities (a partial
 *  map + per-case hard-codes previously left several commodities amortising over
 *  a stale form default). Add a commodity here when it grows an amort field. */
const COMMODITY_AMORT_FIELD: Record<string, string> = {
  machining: 'mach-amort', casting: 'cast-amort', cast_and_machine: 'cam-amort',
  injection_moulding: 'imm-amort', forging: 'forge-amort', sheet_metal: 'sm-amort',
  sheet_metal_fab: 'smf-amort', extrusion: 'ext-amort', thermoforming: 'tf-amort',
  rotational_moulding: 'rm-amort', composites: 'comp-amort', blow_moulding: 'bm-amort',
  rubber: 'rub-amort', wiring_harness: 'harn-amort', painting: 'paint-amort',
  biw_assembly: 'biw-amort', pcb_fab: 'pcbf-amort', pcba: 'pcba-amort',
};

/** Plan-view projected footprint (cm²) — two largest bbox dims, measured OCCT
 *  bbox preferred, AI-analysis bbox as fallback. Drives press/clamp tonnage. */
function _projectedFootprintCm2(): number {
  const bb = cadOCCTGeometry?.boundingBox;
  const g = cadAnalysisResult?.geometry?.boundingBoxMm;
  const dims = bb ? [bb.xMm, bb.yMm, bb.zMm] : g ? [g.x, g.y, g.z] : null;
  if (!dims) return 0;
  const s = [...dims].sort((a, b) => b - a);
  return (s[0] * s[1]) / 100;
}

/** Size an HPDC machine select to the clamp/locking force for the part footprint.
 *  HPDC intensification pressure on the metal ~70 MPa (700 bar, Al); clamp force =
 *  total projected area × specific pressure — reuses the IM clamp-tonnage math. */
function sizeHPDCMachineFor(selId: string, cavities: number): void {
  const projAreaCm2 = _projectedFootprintCm2();
  if (projAreaCm2 <= 0) return;
  const hpdcTonnes = estimateClampingTonnage({
    projectedAreaCm2: projAreaCm2 * Math.max(1, cavities),
    cavityPressureMPa: 70,
    safetyfactor: 1.0,   // raw die-fill force; pickHPDCMachineId adds the machine margin
  });
  const id = sizeProcessMachine('casting', { hpdcTonnes });
  const sel2 = document.getElementById(selId) as HTMLSelectElement | null;
  if (id && sel2) {
    const m = Array.from(sel2.options).find(o => o.value === id);
    if (m) { sel2.value = m.value; markAIFilled(sel2); }
  }
}

function applyCADToForm(targetCommodity: CommodityType, autoCalculate = false): void {
  if (!cadAnalysisResult) return;
  _pendingCostingSource = 'cad'; // tag the next costing record for the accuracy harness
  const r = cadAnalysisResult;
  const c = r.costInputSuggestions;
  // The AI sometimes returns the right commodity but leaves materialId blank —
  // fall back to the filename-named material so the cost uses the correct grade.
  if (!c.materialId) {
    const fb = _fallbackMaterialIdForFamily(familyFromFilename(cadFile?.name || ''), targetCommodity);
    if (fb) c.materialId = fb;
  }
  // Longest bounding-box axis (mm) — used to derive an extrusion profile length.
  const bboxMaxMm = Math.max(r.geometry.boundingBoxMm.x, r.geometry.boundingBoxMm.y, r.geometry.boundingBoxMm.z);

  // Sync annual volume from CAD form to Universal Costs
  const cadAnnVol = (document.getElementById('cad-annual-volume') as HTMLInputElement | null)?.value;
  if (cadAnnVol) {
    const univVol = document.getElementById('annual-volume') as HTMLInputElement | null;
    if (univVol) { univVol.value = cadAnnVol; univVol.dispatchEvent(new Event('input')); }
  }

  switchCommodity(targetCommodity);

  setTimeout(() => {
    // Tooling amortisation must follow the user's stated volume — the per-
    // commodity amort fields default to 50k-500k, so leaving them untouched
    // makes the calculated tooling/part diverge from the suggested panel.
    if (cadAnnVol) {
      // Amortise tooling over the user's stated annual volume for EVERY commodity
      // that has an amort field (see COMMODITY_AMORT_FIELD — the single source of
      // truth). Per-case defaults below only apply when no annual volume is given.
      const amortId = COMMODITY_AMORT_FIELD[targetCommodity];
      const amortEl = amortId ? document.getElementById(amortId) as HTMLInputElement | null : null;
      if (amortEl) { amortEl.value = cadAnnVol; amortEl.dispatchEvent(new Event('input')); }
    }
    // Part name
    const partNameEl = el<HTMLInputElement>('part-name');
    if (partNameEl) {
      partNameEl.value = r.partName || cadFile?.name.replace(/\.[^.]+$/, '') || 'CAD Part';
      markAIFilled(partNameEl);
    }

    // Size-aware packaging from the shipping envelope + weight (the flat £0.15
    // default is wrong for a bulky bumper and for a 3 g part alike).
    {
      const pbb = cadOCCTGeometry?.boundingBox;
      const pkgEl = el<HTMLInputElement>('packaging');
      if (pbb && pkgEl) {
        const bboxVolCm3 = (pbb.xMm * pbb.yMm * pbb.zMm) / 1000;
        pkgEl.value = String(estimatePackagingPerPart(bboxVolCm3, c.netWeightKg || 0));
        pkgEl.dispatchEvent(new Event('input'));
      }
    }

    switch (targetCommodity) {
      case 'machining': {
        setMaterial(el<HTMLSelectElement>('mach-mat'), c.materialId);
        setNumericField('mach-net-wt', c.netWeightKg, 3);
        setNumericField('mach-stock-wt', c.netWeightKg * 1.4, 3);
        // Prefer OCCT bottom-up cycle time over Claude's AI estimate…
        let occtCycleHrs = cadOCCTGeometry?.cncCycleTimeEstimate?.estimatedTotalHrs ?? null;
        // …but cap it to a physical envelope: a tiny solid can't carry the cutting
        // time a naive estimate implies (a 3 g servo horn was billed ~50 min).
        {
          const bb = cadOCCTGeometry?.boundingBox;
          const pv = cadOCCTGeometry?.volume?.cm3;
          if (occtCycleHrs != null && bb && pv != null) {
            const stockCm3 = (bb.xMm * bb.yMm * bb.zMm) / 1000;
            const holes = cadOCCTGeometry?.features?.estimatedHoleCount ?? 0;
            const ms = (c.materialId || '').toLowerCase();
            const mf = /ti|titan/.test(ms) ? 2.5 : /steel|stainless|iron/.test(ms) ? 1.5 : /alum/.test(ms) ? 1.0 : 1.2;
            const ceilHr = (physicalRemovalCeilingMin(pv, stockCm3, cadOCCTGeometry?.surfaceArea?.cm2 ?? 0, mf) + holes * 0.4 * mf) / 60;
            if (occtCycleHrs > ceilHr) occtCycleHrs = ceilHr;
          }
        }
        const occtSetupCount = cadOCCTGeometry?.setupAnalysis?.estimatedSetupCount ?? null;
        const occtSetupMinsPerSetup = cadOCCTGeometry?.cncCycleTimeEstimate?.assumedSetupTimeMinsPerSetup ?? 45;
        // Operations
        const container = el('mach-ops-container');
        if (container && c.estimatedOperations.length > 0) {
          container.innerHTML = '';
          machOpCount = 0;
          // Geometry Feature Table → a dedicated MEASURED drilling op. The exact
          // hole list (Ø × depth × count from the B-rep) drives its cycle time;
          // the AI-estimated ops are then scaled to the REMAINING OCCT cycle time
          // so the grand total still matches the bottom-up geometry estimate.
          const drillPlan = drillingOpFromFeatures(cadOCCTGeometry?.featureTable, cadOCCTGeometry?.cncCycleTimeEstimate?.drillBoreTimeMins);
          const drillHrs = drillPlan?.cycleTimeHr ?? 0;
          // Scale AI cycle times proportionally if OCCT total differs from AI total
          const aiTotalHrs = c.estimatedOperations.reduce((s, op) => s + op.cycleTimeHr, 0);
          const targetHrs = occtCycleHrs !== null ? Math.max(occtCycleHrs - drillHrs, occtCycleHrs * 0.2) : null;
          const scaleFactor = (targetHrs !== null && aiTotalHrs > 0) ? targetHrs / aiTotalHrs : 1;
          for (const op of c.estimatedOperations) {
            addMachOp({
              name: op.name,
              type: 'milling_3ax',
              machineId: resolveMachineIdForOp(op.machineId, op.name),
              labourId: resolveLabourId(op.labourId),
              cycleTimeHr: op.cycleTimeHr * scaleFactor,
              partsPerCycle: 1,
              oee: op.oee,
              manning: op.manning,
              labourTimeHr: op.cycleTimeHr * scaleFactor,
              labourEfficiency: op.labourEfficiency,
            });
          }
          if (drillPlan) {
            const firstAI = c.estimatedOperations[0];
            addMachOp({
              name: drillPlan.name,
              type: 'drilling',
              machineId: resolveMachineIdForOp(firstAI?.machineId, drillPlan.name),
              labourId: resolveLabourId(firstAI?.labourId),
              cycleTimeHr: drillPlan.cycleTimeHr,
              partsPerCycle: 1,
              oee: firstAI?.oee ?? 0.85,
              manning: firstAI?.manning ?? 1,
              labourTimeHr: drillPlan.cycleTimeHr,
              labourEfficiency: firstAI?.labourEfficiency ?? 0.92,
            });
          }
        }
        // Override setup time with OCCT estimate if available
        if (occtSetupCount !== null) {
          const setupHrs = (occtSetupCount * occtSetupMinsPerSetup) / 60;
          setNumericField('mach-setup-time', setupHrs, 3);
        }
        // Machined-features panel: audit + fallback costing. A billet part is
        // machined from solid, so default the stock to solid-billet (every
        // feature auto-ticked). When the OCCT bottom-up cycle estimate is present
        // the ops above already cover these features, so the panel is audit-only;
        // on mesh/STL or text-fallback (no cycle estimate) it becomes the active
        // feature cost (see collectMachiningInput).
        populateMachinedFeatures('mach');
        {
          const stockEl = el<HTMLSelectElement>('mach-mf-stock');
          if (stockEl) { stockEl.value = 'solid_billet'; stockEl.dispatchEvent(new Event('change')); }
        }
        break;
      }

      case 'casting': {
        setMaterial(el<HTMLSelectElement>('cast-mat'), c.materialId);
        setNumericField('cast-part-wt', c.netWeightKg, 3);
        const cast = c.casting;
        const occtTC = cadOCCTGeometry?.toolingCostEstimates;
        const occtPS = cadOCCTGeometry?.processSpecificEstimates;
        if (cast) {
          const subtypeEl = el<HTMLSelectElement>('cast-subtype');
          if (subtypeEl) {
            subtypeEl.value = cast.subtype;
            markAIFilled(subtypeEl);
            subtypeEl.dispatchEvent(new Event('change'));
          }
          setNumericField('cast-yield', cast.yieldFraction, 2);
          if (cast.subtype === 'hpdc') {
            setNumericField('cast-hpdc-ct', cast.cycleTimeHpdcSec, 0);
            setNumericField('cast-hpdc-cav', cast.cavities, 0);
            setNumericField('cast-hpdc-die-cost', occtTC?.hpdcDieCostGBP ?? cast.dieMouldCostGBP, 0);
            setNumericField('cast-hpdc-die-life', cast.dieMouldLife, 0);
            sizeHPDCMachineFor('cast-hpdc-mach', cast.cavities || 1);
          } else if (cast.subtype === 'sand') {
            setNumericField('cast-sand-ct', occtPS?.sandCycleTimeHr ?? cast.cycleTimeSandGravHr, 4);
            setNumericField('cast-sand-pat-cost', occtTC?.sandPatternCostGBP ?? cast.dieMouldCostGBP, 0);
            setNumericField('cast-sand-pat-life', cast.dieMouldLife, 0);
          } else if (cast.subtype === 'gravity') {
            setNumericField('cast-grav-ct', cast.cycleTimeSandGravHr, 4);
            setNumericField('cast-grav-mould-cost', occtTC?.gravityMouldCostGBP ?? cast.dieMouldCostGBP, 0);
            setNumericField('cast-grav-mould-life', cast.dieMouldLife, 0);
          } else if (cast.subtype === 'investment') {
            setNumericField('cast-inv-ct', cast.cycleTimeSandGravHr, 4);
          }
        }
        populateMachinedFeatures('cast');
        break;
      }

      case 'cast_and_machine': {
        setMaterial(el<HTMLSelectElement>('cam-mat'), c.materialId);
        setNumericField('cam-cast-wt', c.netWeightKg * 1.15, 3);
        setNumericField('cam-finish-wt', c.netWeightKg, 3);
        // Casting section
        const castCAM = c.casting;
        const camTC = cadOCCTGeometry?.toolingCostEstimates;
        const camPS = cadOCCTGeometry?.processSpecificEstimates;
        if (castCAM) {
          const camSubEl = el<HTMLSelectElement>('cam-cast-subtype');
          if (camSubEl) {
            camSubEl.value = castCAM.subtype;
            markAIFilled(camSubEl);
            camSubEl.dispatchEvent(new Event('change'));
          }
          setNumericField('cam-cast-yield', castCAM.yieldFraction, 2);
          if (castCAM.subtype === 'hpdc') {
            setNumericField('cam-hpdc-ct', castCAM.cycleTimeHpdcSec, 0);
            setNumericField('cam-hpdc-cav', castCAM.cavities, 0);
            setNumericField('cam-hpdc-die-cost', camTC?.hpdcDieCostGBP ?? castCAM.dieMouldCostGBP, 0);
            setNumericField('cam-hpdc-die-life', castCAM.dieMouldLife, 0);
            sizeHPDCMachineFor('cam-hpdc-mach', castCAM.cavities || 1);
          } else if (castCAM.subtype === 'sand') {
            setNumericField('cam-sand-ct', camPS?.sandCycleTimeHr ?? castCAM.cycleTimeSandGravHr, 4);
            setNumericField('cam-sand-pat-cost', camTC?.sandPatternCostGBP ?? castCAM.dieMouldCostGBP, 0);
            setNumericField('cam-sand-pat-life', castCAM.dieMouldLife, 0);
          } else if (castCAM.subtype === 'gravity') {
            setNumericField('cam-grav-ct', castCAM.cycleTimeSandGravHr, 4);
            setNumericField('cam-grav-mould-cost', camTC?.gravityMouldCostGBP ?? castCAM.dieMouldCostGBP, 0);
            setNumericField('cam-grav-mould-life', castCAM.dieMouldLife, 0);
          } else if (castCAM.subtype === 'investment') {
            setNumericField('cam-inv-ct', castCAM.cycleTimeSandGravHr, 4);
          }
        }
        // Machining section — populate ops and setup time
        const camCycleHrs = cadOCCTGeometry?.cncCycleTimeEstimate?.estimatedTotalHrs ?? null;
        const camSetupCount = cadOCCTGeometry?.setupAnalysis?.estimatedSetupCount ?? null;
        const camSetupMins = cadOCCTGeometry?.cncCycleTimeEstimate?.assumedSetupTimeMinsPerSetup ?? 45;
        const camContainer = el('cam-mach-ops-container');
        if (camContainer && c.estimatedOperations.length > 0) {
          camContainer.innerHTML = '';
          camMachOpCount = 0;
          const aiTotalCAM = c.estimatedOperations.reduce((s, op) => s + op.cycleTimeHr, 0);
          // The OCCT total is a machined-FROM-SOLID estimate; the server has
          // already capped the AI ops to the near-net finish envelope. Never
          // scale back UP to from-solid — that re-creates the over-cost the
          // near-net machining guard exists to prevent.
          const scaleCAM = (camCycleHrs !== null && aiTotalCAM > 0) ? Math.min(1, camCycleHrs / aiTotalCAM) : 1;
          for (const op of c.estimatedOperations) {
            addCAMMachOp({
              name: op.name, type: 'milling_3ax',
              machineId: resolveMachineIdForOp(op.machineId, op.name),
              labourId: resolveLabourId(op.labourId),
              cycleTimeHr: op.cycleTimeHr * scaleCAM, partsPerCycle: 1,
              oee: op.oee, manning: op.manning,
              labourTimeHr: op.cycleTimeHr * scaleCAM, labourEfficiency: op.labourEfficiency,
            });
          }
        }
        if (camSetupCount !== null) {
          setNumericField('cam-mach-setup-time', (camSetupCount * camSetupMins) / 60, 3);
        } else {
          setNumericField('cam-mach-setup-time', c.estimatedSetupTimeHr, 3);
        }
        break;
      }

      case 'forging': {
        setMaterial(el<HTMLSelectElement>('forge-mat'), c.materialId);
        setNumericField('forge-part-wt', c.netWeightKg, 3);
        const forging = c.forging;
        const forgeTC = cadOCCTGeometry?.toolingCostEstimates;
        const forgePS = cadOCCTGeometry?.processSpecificEstimates;
        if (forging) {
          setNumericField('forge-flash', forging.flashKg, 3);
          setNumericField('forge-yield', forging.yieldFraction, 2);
          // Prefer OCCT geometry-derived stroke count over AI guess
          setNumericField('forge-strokes', forgePS?.forgeStrokes ?? forging.strokes, 0);
          setNumericField('forge-time-per-blow', forging.timePerBlowSec, 0);
          // Prefer OCCT parametric die cost over AI bracket estimate
          setNumericField('forge-die-cost', forgeTC?.forgeDieCostGBP ?? forging.dieCostGBP, 0);
          setNumericField('forge-die-life', forging.dieLife, 0);
        } else {
          // Fallback geometry-derived estimates
          setNumericField('forge-flash', c.netWeightKg * 0.1, 3);
          setNumericField('forge-yield', 0.9, 2);
          if (forgePS) setNumericField('forge-strokes', forgePS.forgeStrokes, 0);
          if (forgeTC) setNumericField('forge-die-cost', forgeTC.forgeDieCostGBP, 0);
        }
        // Material-specific heating energy (kWh/kg)
        const forgeHeatMap: Record<string, number> = {
          'mat-dc01': 0.35, 'mat-hss': 0.38, 'mat-stainless-316': 0.42, 'mat-ss304c': 0.42,
          'mat-al6061': 0.25, 'mat-al5052': 0.23, 'mat-brass-crz': 0.18,
        };
        setNumericField('forge-heat-energy', forgeHeatMap[c.materialId] ?? 0.40, 2);
        // Size the forging press to the die-fill force (F = Kt·σflow·A_projected),
        // not the small form default — the same "size the machine to the part" rule
        // as IM/EBM, now generalised via sizeProcessMachine.
        {
          const fbb = cadOCCTGeometry?.boundingBox;
          const fdims = (fbb
            ? [fbb.xMm, fbb.yMm, fbb.zMm]
            : [r.geometry.boundingBoxMm.x, r.geometry.boundingBoxMm.y, r.geometry.boundingBoxMm.z]
          ).sort((a, b) => b - a);   // fall back to AI-analysis bbox when OCCT absent
          const projAreaCm2 = (fdims[0] * fdims[1]) / 100;   // two largest dims → footprint mm²→cm²
          if (projAreaCm2 > 0) {
            const forgeTonnes = estimateForgingTonnage({
              projectedAreaCm2: projAreaCm2,
              alloyFamily: forgingAlloyFamilyFor(c.materialId),
              shapeComplexity: 'moderate',
            });
            const forgeId = sizeProcessMachine('forging', { forgeTonnes });
            const forgeMachEl = el<HTMLSelectElement>('forge-mach');
            if (forgeId && forgeMachEl) {
              const m = Array.from(forgeMachEl.options).find(o => o.value === forgeId);
              if (m) { forgeMachEl.value = m.value; markAIFilled(forgeMachEl); }
            }
          }
        }
        populateMachinedFeatures('forge');
        break;
      }

      case 'sheet_metal': {
        setMaterial(el<HTMLSelectElement>('sm-mat'), c.materialId);
        setNumericField('sm-net-wt', c.netWeightKg, 3);
        // Derive blank dims from OCCT bounding box (sorted: L ≥ W ≥ thickness)
        const smBB = cadOCCTGeometry?.boundingBox;
        let smBlankL = 0;
        let smBlankW = 0;
        if (smBB) {
          const dims = [smBB.xMm, smBB.yMm, smBB.zMm].sort((a, b) => b - a);
          smBlankL = dims[0] * 1.05;
          smBlankW = dims[1] * 1.05;
          setNumericField('sm-blank-l', smBlankL, 0);
          setNumericField('sm-blank-w', smBlankW, 0);
          const wallMin = cadOCCTGeometry?.wallThickness?.minMm;
          setNumericField('sm-thick', wallMin ?? dims[2], 1);
          // Perimeter ≈ 2×(L+W), strip width and pitch with typical scrap allowances
          setNumericField('sm-perim', 2 * (smBlankL + smBlankW), 0);
          setNumericField('sm-strip-w', smBlankW * 1.06, 0);
          setNumericField('sm-pitch', smBlankL * 1.04, 0);
        }
        // Material shear strength lookup
        const smShearMap: Record<string, number> = {
          'mat-dc01': 290, 'mat-hss': 420, 'mat-stainless-316': 520,
          'mat-al5052': 125, 'mat-al6061': 195, 'mat-brass-crz': 350, 'mat-ss304c': 510,
        };
        setNumericField('sm-shear', smShearMap[c.materialId] ?? 280, 0);
        const sm = c.sheetMetal;
        const smTC = cadOCCTGeometry?.toolingCostEstimates;
        if (sm) {
          if (!smBB) {
            setNumericField('sm-blank-l', sm.blankLengthMm, 0);
            setNumericField('sm-blank-w', sm.blankWidthMm, 0);
            setNumericField('sm-thick', sm.thicknessMm, 1);
            smBlankL = sm.blankLengthMm;
            smBlankW = sm.blankWidthMm;
            setNumericField('sm-perim', 2 * (smBlankL + smBlankW), 0);
            setNumericField('sm-strip-w', smBlankW * 1.06, 0);
            setNumericField('sm-pitch', smBlankL * 1.04, 0);
          }
          // Prefer OCCT parametric progressive die cost over AI bracket estimate
          setNumericField('sm-die-cost', smTC?.progressiveDieCostGBP ?? sm.dieCostGBP, 0);
          setNumericField('sm-die-life', sm.dieLife, 0);
          setNumericField('sm-num-ops', sm.numOps, 0);
        } else if (smTC) {
          setNumericField('sm-die-cost', smTC.progressiveDieCostGBP, 0);
        }
        // Size the stamping press to the blanking force (perimeter × thickness ×
        // shear), not the small form default — generalised via sizeProcessMachine.
        {
          const smPerim = num('sm-perim'), smThick = num('sm-thick'), smShear = num('sm-shear');
          if (smPerim > 0 && smThick > 0 && smShear > 0) {
            const stampTonnes = estimateTonnageTonnes({ perimeterMm: smPerim, thicknessMm: smThick, shearStrengthMPa: smShear });
            const pressId = sizeProcessMachine('sheet_metal', { stampTonnes });
            const smPressEl = el<HTMLSelectElement>('sm-press');
            if (pressId && smPressEl) {
              const m = Array.from(smPressEl.options).find(o => o.value === pressId);
              if (m) { smPressEl.value = m.value; markAIFilled(smPressEl); }
            }
          }
        }
        break;
      }

      case 'sheet_metal_fab': {
        setMaterial(el<HTMLSelectElement>('smf-mat'), c.materialId);
        setNumericField('smf-part-wt', c.netWeightKg, 3);
        // Bend count — prefer the GEOMETRY-MEASURED count (cylindrical bend faces
        // with in-plane axes) over the crude planar-face proxy. Phase 3.
        const smfBends = cadOCCTGeometry?.sheetMetal;
        if (smfBends && smfBends.bendCount > 0) {
          setNumericField('smf-bends', smfBends.bendCount, 0);
          if (smfBends.totalBendLengthMm > 0) {
            _smExtraWarnings.push(
              `Bends: ${smfBends.bendCount} press-brake bend(s) measured from geometry ` +
              `(${smfBends.totalBendLengthMm.toFixed(0)} mm total bend length, ${smfBends.thicknessMm.toFixed(1)} mm sheet). Adjust if the flat pattern differs.`
            );
          }
        } else {
          // Fallback: planar-face proxy (2 faces per 90° bend minus the flat base)
          const smfPlanar = cadOCCTGeometry?.features?.planarFaceCount ?? 0;
          if (smfPlanar > 2) setNumericField('smf-bends', Math.max(1, Math.round((smfPlanar - 2) / 2)), 0);
        }
        // Tolerance from wall thickness (5% of mean wall, min 0.1mm)
        const smfWallMean = cadOCCTGeometry?.wallThickness?.meanMm;
        if (smfWallMean) {
          setNumericField('smf-tolerance', Math.max(0.1, smfWallMean * 0.05), 2);
        }
        // Laser blanking cycle time — feed rate derived from material + thickness
        // (a 6 mm stainless part cuts ~3× slower than 1 mm mild steel; a flat feed
        //  under-costs thick/stainless blanks). Cut length ≈ perimeter + hole edges.
        const smfBB = cadOCCTGeometry?.boundingBox;
        if (smfBB) {
          const fbDims = [smfBB.xMm, smfBB.yMm, smfBB.zMm].sort((a, b) => b - a);
          const perimMm = 2 * (fbDims[0] * 1.05 + fbDims[1] * 1.05);
          const holeCount = cadOCCTGeometry?.features?.estimatedHoleCount ?? 0;
          const family = inferFabMaterialFamily(c.materialId);
          const thick = smfWallMean && smfWallMean > 0 ? smfWallMean : Math.max(0.5, fbDims[2]);
          const blankCt = Math.max(15, Math.round(estimateBlankingCycleSec({
            method: 'laser', materialFamily: family, thicknessMm: thick,
            cutLengthMm: perimMm + holeCount * 30, pierceCount: holeCount + 1,
          })));
          setNumericField('smf-blank-ct', blankCt, 0);
        }
        const smFab = c.sheetMetal;
        if (smFab) {
          setNumericField('smf-tooling', smFab.dieCostGBP, 0);
        }
        break;
      }

      case 'injection_moulding': {
        setMaterial(el<HTMLSelectElement>('imm-mat'), c.materialId);
        setNumericField('imm-part-wt', c.netWeightKg, 4);
        // OCCT-derived: projected area and wall thickness
        const immBB = cadOCCTGeometry?.boundingBox;
        const immWall = cadOCCTGeometry?.wallThickness?.meanMm;
        if (immBB) {
          const projCm2 = (immBB.xMm * immBB.yMm) / 100;
          setNumericField('imm-area', projCm2, 1);
        }
        if (immWall) {
          setNumericField('imm-wall', immWall, 1);
        }
        const im = c.injectionMoulding;
        const immTC = cadOCCTGeometry?.toolingCostEstimates;
        if (im) {
          setNumericField('imm-cav', im.cavities, 0);
          if (!immBB) setNumericField('imm-area', im.projectedAreaCm2, 1);
          if (!immWall) setNumericField('imm-wall', im.wallThicknessMm, 1);
          // Prefer OCCT parametric mould cost over AI bracket estimate
          setNumericField('imm-mould-cost', immTC?.imMouldCostGBP ?? im.mouldCostGBP, 0);
          setNumericField('imm-mould-life', im.mouldLife, 0);
          setNumericField('imm-runner-wt', im.runnerWeightKg, 4);
        } else if (immTC) {
          setNumericField('imm-mould-cost', immTC.imMouldCostGBP, 0);
        }
        // Material-specific cooling factor and cavity pressure (key cycle time drivers)
        const immCoolMap: Record<string, number> = {
          'mat-pp': 3.16, 'mat-pa6': 2.20, 'mat-pc': 4.50,
        };
        const immPressMap: Record<string, number> = {
          'mat-pp': 35, 'mat-pa6': 55, 'mat-pc': 65,
        };
        const immCavPress = immPressMap[c.materialId] ?? 50;
        setNumericField('imm-cool-f', immCoolMap[c.materialId] ?? 3.0, 2);
        setNumericField('imm-cav-press', immCavPress, 0);
        // Size the press to the required clamp tonnage (projected area × cavity
        // pressure) — a bumper needs ~3900 T, not the small default press that
        // made the moulding cost ~10× too low.
        {
          const projForTon = immBB ? (immBB.xMm * immBB.yMm) / 100 : (im?.projectedAreaCm2 ?? 0);
          if (projForTon > 0) {
            const tonnes = estimateClampingTonnage({ projectedAreaCm2: projForTon, cavityPressureMPa: immCavPress });
            const pressId = pickIMMPressId(tonnes);
            const machEl = el<HTMLSelectElement>('imm-mach');
            if (machEl) { machEl.value = resolveMachineIdForOp(pressId, 'Injection Moulding'); }
          }
        }
        // Cycle time sub-components from wall thickness
        const wallForCycle = immWall ?? im?.wallThicknessMm ?? 2.5;
        setNumericField('imm-fill', Math.max(1.5, parseFloat((wallForCycle * 0.5).toFixed(1))), 1);
        setNumericField('imm-pack', Math.max(2.0, parseFloat((wallForCycle * 0.8).toFixed(1))), 1);
        setNumericField('imm-eject', 2, 0);
        break;
      }

      case 'extrusion': {
        // No AI extrusion sub-object — derive the profile from geometry: material,
        // length = longest bbox axis, linear weight = net weight ÷ length, wall from OCCT.
        setMaterial(el<HTMLSelectElement>('ext-mat'), c.materialId);
        const extLenM = Math.max(0.05, bboxMaxMm / 1000);
        setNumericField('ext-length', extLenM, 3);
        if (c.netWeightKg > 0) setNumericField('ext-kg-per-m', c.netWeightKg / extLenM, 4);
        const extWall = cadOCCTGeometry?.wallThickness?.meanMm;
        if (extWall && extWall > 0) setNumericField('ext-wall', extWall, 1);
        break;
      }

      case 'blow_moulding': {
        const bm = c.blowMoulding;
        const bmWall = cadOCCTGeometry?.wallThickness?.meanMm;
        const bmSub = bm?.subtype;
        // Pinch-off flash scales with part size — a large accumulator-head parison
        // (tank) sheds far more than a small bottle. Floor the AI value accordingly.
        const bmFlashFrac = c.netWeightKg > 3 ? 0.22 : 0.12;
        const bmGrossKg = c.netWeightKg * (1 + bmFlashFrac);
        // Multi-layer barrier (coex) wall: the AI *classifies* it (fuel tank /
        // AdBlue duct → HDPE/tie/EVOH/tie/HDPE). Fallback when the flag is absent
        // (old cache / air-gapped): a large HDPE accumulator-head EBM shot is a
        // barrier tank in practice. The engine then prices the real coex grade.
        const bmBarrier = bm?.barrierMultilayer
          ?? (bmSub !== 'ibm' && bmSub !== 'sbm' && bmGrossKg >= 6 && /hdpe|lldpe|pe-bm/i.test(c.materialId));
        setMaterial(el<HTMLSelectElement>('bm-mat'), barrierMaterialId(c.materialId, !!bmBarrier));
        setNumericField('bm-part-wt', c.netWeightKg, 4);
        if (bm) {
          setNumericField('bm-flash-wt', Math.max(bm.flashWeightKg ?? 0, c.netWeightKg * bmFlashFrac), 4);
          setNumericField('bm-wall', bm.wallThicknessMm ?? bmWall ?? 2.0, 1);
          setNumericField('bm-cav', bm.cavities, 0);
          setNumericField('bm-mould-cost', bm.mouldCostGBP, 0);
          setNumericField('bm-mould-life', bm.mouldLife, 0);
          setNumericField('bm-blow-t', bm.blowTimeSec, 0);
          setNumericField('bm-open-close', bm.openCloseSec, 0);
        } else if (bmWall) {
          setNumericField('bm-wall', bmWall, 1);
          setNumericField('bm-flash-wt', c.netWeightKg * bmFlashFrac, 4);
        }
        // Size the machine to the shot weight (part + flash). EBM picks by size;
        // IBM/SBM by subtype. Ids are `blow-ebm-*` (the old `bm-ebm` prefix never
        // matched, so a fuel tank stayed on the small 1–5 L bottle default).
        {
          const bmMachId = bmSub === 'ibm' ? 'blow-ibm-linear' : bmSub === 'sbm' ? 'blow-sbm-2stage' : pickEBMMachineId(bmGrossKg);
          const bmMachEl = el<HTMLSelectElement>('bm-mach');
          if (bmMachEl) {
            const match = Array.from(bmMachEl.options).find(o => o.value === bmMachId) ?? Array.from(bmMachEl.options).find(o => o.value.startsWith('blow-ebm'));
            if (match) { bmMachEl.value = match.value; markAIFilled(bmMachEl); }
          }
        }
        // Cooling time factor: HDPE/LDPE ~3.5, PP ~3.16, PET ~3.0
        const bmCoolMap: Record<string, number> = { 'mat-pp': 3.16, 'mat-pc': 4.5 };
        setNumericField('bm-cool-f', bmCoolMap[c.materialId] ?? 3.5, 2);
        if (!cadAnnVol) setNumericField('bm-amort', 100000, 0);   // fallback default only when no annual volume
        break;
      }

      case 'thermoforming': {
        const tf = c.thermoforming;
        setMaterial(el<HTMLSelectElement>('tf-mat'), c.materialId);
        setNumericField('tf-part-wt', c.netWeightKg, 4);
        if (tf) {
          setNumericField('tf-sheet-wt', tf.sheetWeightKg, 4);
          setNumericField('tf-tool-cost', tf.toolCostGBP, 0);
          setNumericField('tf-heat', tf.heatTimeSec, 0);
          setNumericField('tf-form', tf.formTimeSec, 0);
          setNumericField('tf-trim', tf.trimTimeSec, 0);
          const tfMethodEl = el<HTMLSelectElement>('tf-method');
          if (tfMethodEl && tf.method) {
            const methodMap: Record<string, string> = { vacuum: 'vacuum', pressure: 'pressure', twin_sheet: 'twin_sheet' };
            const mv = methodMap[tf.method];
            if (mv && Array.from(tfMethodEl.options).some(o => o.value === mv)) {
              tfMethodEl.value = mv; markAIFilled(tfMethodEl);
            }
          }
        } else {
          // Derive from geometry: plastic weight from OCCT
          const tfPlastic = cadOCCTGeometry?.weights?.plasticKg ?? c.netWeightKg;
          setNumericField('tf-sheet-wt', tfPlastic * 1.35, 4);
        }
        if (!cadAnnVol) setNumericField('tf-amort', 50000, 0);   // fallback default only when no annual volume
        break;
      }

      case 'rotational_moulding': {
        const rm = c.rotationalMoulding;
        setMaterial(el<HTMLSelectElement>('rm-mat'), c.materialId);
        setNumericField('rm-part-wt', c.netWeightKg, 4);
        if (rm) {
          setNumericField('rm-num-arms', rm.numArms, 0);
          setNumericField('rm-parts-per-arm', rm.partsPerArm, 0);
          setNumericField('rm-heat', rm.heatTimeSec, 0);
          setNumericField('rm-cool', rm.coolTimeSec, 0);
          setNumericField('rm-mould-cost', rm.mouldCostGBP, 0);
          setNumericField('rm-mould-life', rm.mouldLife, 0);
        } else {
          // Rule-of-thumb defaults by part weight
          const rmHeat = Math.max(900, Math.round(c.netWeightKg * 180 + 900));
          setNumericField('rm-heat', rmHeat, 0);
          setNumericField('rm-cool', Math.round(rmHeat * 0.7), 0);
          setNumericField('rm-num-arms', 3, 0);
          setNumericField('rm-parts-per-arm', c.netWeightKg > 5 ? 1 : 2, 0);
        }
        if (!cadAnnVol) setNumericField('rm-amort', 20000, 0);   // fallback default only when no annual volume
        break;
      }

      case 'rubber': {
        const rub = c.rubber;
        setMaterial(el<HTMLSelectElement>('rub-mat'), c.materialId);
        setNumericField('rub-part-wt', c.netWeightKg, 4);
        if (rub) {
          setNumericField('rub-flash-wt', rub.flashWeightKg, 4);
          setNumericField('rub-cavities', rub.cavities, 0);
          setNumericField('rub-cycle-sec', rub.cycleTimeSec, 0);
          setNumericField('rub-mould-cost', rub.mouldCostGBP, 0);
          setNumericField('rub-mould-life', rub.mouldLife, 0);
          const rubProcEl = el<HTMLSelectElement>('rub-process');
          if (rubProcEl && rub.process) {
            if (Array.from(rubProcEl.options).some(o => o.value === rub.process)) {
              rubProcEl.value = rub.process; markAIFilled(rubProcEl);
            }
          }
        } else {
          setNumericField('rub-flash-wt', c.netWeightKg * 0.08, 4);
          setNumericField('rub-cycle-sec', 180, 0);
          setNumericField('rub-cavities', 2, 0);
        }
        if (!cadAnnVol) setNumericField('rub-amort', 50000, 0);   // fallback default only when no annual volume
        break;
      }

      case 'composites': {
        const comp = c.composites;
        setNumericField('comp-part-wt', c.netWeightKg, 4);
        const compSA = cadOCCTGeometry?.surfaceArea?.cm2 ?? null;
        if (comp) {
          setNumericField('comp-fibre-frac', comp.fibreFraction, 2);
          setNumericField('comp-waste-frac', comp.wasteFraction, 2);
          setNumericField('comp-area', comp.areaCm2 ?? compSA ?? 0, 0);
          setNumericField('comp-plies', comp.plies, 0);
          setNumericField('comp-tool-cost', comp.toolCostGBP, 0);
          setNumericField('comp-tool-life', comp.toolLife, 0);
          setNumericField('comp-cure-time', comp.cureTimeSec, 0);
          const compProcEl = el<HTMLSelectElement>('comp-process');
          if (compProcEl && comp.process) {
            const procMap: Record<string, string> = {
              hand_layup: 'hand_layup', prepreg_autoclave: 'prepreg_autoclave',
              rtm: 'rtm', infusion: 'infusion', smc: 'smc', wet_layup: 'wet_layup',
            };
            const pv = procMap[comp.process];
            if (pv && Array.from(compProcEl.options).some(o => o.value === pv)) {
              compProcEl.value = pv; markAIFilled(compProcEl);
            }
          }
        } else if (compSA) {
          setNumericField('comp-area', compSA, 0);
          setNumericField('comp-plies', 4, 0);
          setNumericField('comp-fibre-frac', 0.45, 2);
          setNumericField('comp-waste-frac', 0.20, 2);
        }
        if (!cadAnnVol) setNumericField('comp-amort', 10000, 0);   // fallback default only when no annual volume
        break;
      }

      case 'wiring_harness': {
        // Wiring harness has no geometry-driven sub-object; populate sensible defaults
        setNumericField('harn-asm-time', c.estimatedCycleTimeHr * 3600, 0);
        if (!cadAnnVol) setNumericField('harn-amort', 10000, 0);   // fallback default only when no annual volume
        break;
      }
    }

    // Surface provenance: how much of this form is measured geometry vs AI guess.
    showCADProvenanceBanner();

    // Keep the 3D model on screen: the CAD form (with its viewer) was just
    // swapped for this commodity form, so remount a compact viewer in the
    // persistent host that survives the swap.
    if (cadFile) void showPersistentCADViewer(cadFile);

    if (autoCalculate) {
      compute();
    }
  }, 150);
}

// ─── Commodity switching ──────────────────────────────────────────────────────

function switchCommodity(type: CommodityType): void {
  breadcrumb(`commodity:${type}`);
  activeCommodity = type;
  document.querySelectorAll<HTMLElement>('.ctab').forEach(t => {
    t.classList.toggle('active', t.dataset.commodity === type);
  });

  // Reset calc button label for non-assembly modes
  const calcBtn = el('calc-btn');
  if (type !== 'assembly') calcBtn.textContent = 'Calculate';

  // Restore the default-visible controls before the per-commodity switch below
  // re-hides them. The AI Agent and Automotive Software panels set these to
  // display:none; without this reset that state leaked into every subsequent
  // standard commodity — hiding Calculate so the results tabs (Breakdown /
  // AI Insights / DFM-DFA) could never appear.
  calcBtn.style.display = '';
  const universalCostsEl = document.getElementById('universal-costs');
  if (universalCostsEl) universalCostsEl.style.display = '';

  // Show/hide part-name for non-assembly modes
  const partNameWrap = el('part-name').closest<HTMLElement>('div[style]');
  if (partNameWrap) partNameWrap.style.display = type === 'assembly' ? 'none' : '';

  // Show/hide country bar (hidden for AI Agent only)
  const countryBar = document.getElementById('wf-country-bar');
  if (countryBar) countryBar.style.display = (type as string) === 'ai_agent' ? 'none' : '';

  const area = el('commodity-form-area');
  disposeAllCADViewers(); // the innerHTML swap below destroys any mounted viewer's DOM
  hidePersistentCADViewer(); // hidden by default; applyCADToForm re-shows it after a CAD apply
  machOpCount = 0; coatCount = 0; joinCount = 0; stationCount = 0; bomCount = 0; camMachOpCount = 0; asmLineCount = 0;

  switch (type) {
    case 'machining':
      area.innerHTML = renderMachiningForm();
      area.insertAdjacentHTML('beforeend', renderMachinedFeaturesPanel('mach'));
      populateSelects();
      el('add-mach-op-btn')?.addEventListener('click', () => addMachOp());
      addMachOp({ name: 'CNC Turning', type: 'turning', machineId: 'mach-lathe-cnc', labourId: 'lab-uk-skilled', cycleTimeHr: 0.05, partsPerCycle: 1, oee: 0.85, manning: 1, labourTimeHr: 0.05, labourEfficiency: 0.92 });
      break;

    case 'sheet_metal_fab': {
      area.innerHTML = renderSheetMetalFabForm();
      populateSelects();
      wireSheetMetalFabAdvisor();
      setTimeout(() => {
        // ── Material — filter to sheet metal categories only ──────────────────
        const smfMatCats = new Set([
          'Mild Steel Sheet', 'Galvanised Steel Sheet', 'Electrogalvanised Steel Sheet',
          'AHSS Sheet', 'High Strength Steel Sheet', 'Ultra-High Strength Steel',
          'Aluminium Sheet', 'Stainless Steel Sheet', 'Copper & Brass Sheet',
        ]);
        const matEl = el<HTMLSelectElement>('smf-mat');
        if (matEl) {
          const smfMats = library.materials.filter(m => smfMatCats.has(m.category));
          matEl.innerHTML = smfMats.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.grade)} — £${m.pricePerKg.toFixed(2)}/kg</option>`).join('');
          if (Array.from(matEl.options).some(o => o.value === 'mat-dc01')) matEl.value = 'mat-dc01';
        }
        // ── Blanking machine — filter to laser/plasma/waterjet/punch/shear ────
        const blankMachIds = new Set([
          'laser-trumpf-3030', 'laser-trumpf-5030', 'laser-amada-ensis-3015', 'laser-bystronic-3015',
          'plasma-hypertherm-xpr300', 'plasma-kjellberg-hifocus280',
          'waterjet-flow-mach500', 'waterjet-omax-80x',
          'punch-amada-emz3610', 'punch-trumpf-5000',
          'shear-hydraulic-3m', 'shear-guillotine-6mm',
        ]);
        const blankMachEl = el<HTMLSelectElement>('smf-blank-mach');
        if (blankMachEl) {
          const blankMachs = library.machines.filter(m => blankMachIds.has(m.id));
          blankMachEl.innerHTML = blankMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('');
        }
        // ── Brake machine — filter to press brake machines ────────────────────
        const brakeMachIds = new Set([
          'brake-amada-hfe100', 'brake-amada-hfe170', 'brake-trumpf-trubend3100',
          'brake-lvd-ppeb135', 'brake-trumpf-5230',
        ]);
        const brakeMachEl = el<HTMLSelectElement>('smf-brake-mach');
        if (brakeMachEl) {
          const brakeMachs = library.machines.filter(m => brakeMachIds.has(m.id));
          brakeMachEl.innerHTML = brakeMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('');
        }
        // ── Spot weld machine — pedestal + robotic ────────────────────────────
        const swMachEl = el<HTMLSelectElement>('smf-sw-mach');
        if (swMachEl) {
          const swMachs = library.machines.filter(m => ['spotweld-gun-manual','robot-spotweld-kuka'].includes(m.id));
          swMachEl.innerHTML = `<option value="">None</option>${swMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('')}`;
        }
        // ── MIG machine — manual station + robotic cell ───────────────────────
        const migMachEl = el<HTMLSelectElement>('smf-mig-mach');
        if (migMachEl) {
          const migMachs = library.machines.filter(m => ['mig-welder-manual','robot-mig-cell'].includes(m.id));
          migMachEl.innerHTML = `<option value="">None</option>${migMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('')}`;
        }
        // ── TIG machine ───────────────────────────────────────────────────────
        const tigMachEl = el<HTMLSelectElement>('smf-tig-mach');
        if (tigMachEl) {
          const tigM = library.machines.find(m => m.id === 'tig-welder-manual');
          tigMachEl.innerHTML = `<option value="">None</option>${tigM ? `<option value="${tigM.id}">${escHtml(tigM.machineClass)} — £${tigM.computedRatePerHr.toFixed(2)}/hr</option>` : ''}`;
        }
        // ── Labour defaults ───────────────────────────────────────────────────
        for (const id of ['smf-blank-lab', 'smf-brake-lab']) {
          const labEl = el<HTMLSelectElement>(id);
          if (labEl) { const opt = Array.from(labEl.options).find(o => o.value === 'lab-uk-semiskilled'); if (opt) labEl.value = 'lab-uk-semiskilled'; }
        }
        for (const id of ['smf-sw-lab', 'smf-mig-lab', 'smf-tig-lab']) {
          const labEl = el<HTMLSelectElement>(id);
          if (labEl) { const opt = Array.from(labEl.options).find(o => o.value === 'lab-uk-skilled'); if (opt) labEl.value = 'lab-uk-skilled'; }
        }
        wireSheetMetalBlankingChange();
      }, 0);
      break;
    }

    case 'sheet_metal':
      area.innerHTML = renderSheetMetalForm();
      populateSelects();
      wireStampingAdvisor();
      // Set default select values after populating
      setTimeout(() => {
        const pressEl = el<HTMLSelectElement>('sm-press');
        if (pressEl) { const opt = Array.from(pressEl.options).find(o => o.value.includes('press-100t')); if (opt) pressEl.value = opt.value; }
        const labEl = el<HTMLSelectElement>('sm-lab');
        if (labEl) { const opt = Array.from(labEl.options).find(o => o.value.includes('semiskilled')); if (opt) labEl.value = opt.value; }
      }, 0);
      break;

    case 'injection_moulding':
      area.innerHTML = renderInjectionForm();
      populateSelects();
      setTimeout(() => {
        const machEl = el<HTMLSelectElement>('imm-mach');
        if (machEl) { const opt = Array.from(machEl.options).find(o => o.value.includes('imm-200t')); if (opt) machEl.value = opt.value; }
        const matEl = el<HTMLSelectElement>('imm-mat');
        if (matEl) {
          const opt = Array.from(matEl.options).find(o => o.value.includes('mat-pp')); if (opt) matEl.value = opt.value;
          // M7: auto-fill the cool factor from the resin, and keep it in sync on change.
          syncImmCoolFactor();
          matEl.addEventListener('change', syncImmCoolFactor);
        }
      }, 0);
      break;

    case 'casting':
      area.innerHTML = renderCastingForm();
      area.insertAdjacentHTML('beforeend', renderMachinedFeaturesPanel('cast'));
      populateSelects();
      el('cast-subtype')?.addEventListener('change', updateCastingSubtype);
      updateCastingSubtype();
      setTimeout(() => {
        const matEl = el<HTMLSelectElement>('cast-mat');
        if (matEl) { const opt = Array.from(matEl.options).find(o => o.value.includes('mat-adc12')); if (opt) matEl.value = opt.value; }
        const machEl = el<HTMLSelectElement>('cast-hpdc-mach');
        if (machEl) { const opt = Array.from(machEl.options).find(o => o.value.includes('hpdc-800t')); if (opt) machEl.value = opt.value; }
      }, 0);
      break;

    case 'forging':
      area.innerHTML = renderForgingForm();
      area.insertAdjacentHTML('beforeend', renderMachinedFeaturesPanel('forge'));
      populateSelects();
      wireForgingAdvisor();
      setTimeout(() => {
        const matEl = el<HTMLSelectElement>('forge-mat');
        if (matEl) { const opt = Array.from(matEl.options).find(o => o.value.includes('mat-steel1020')); if (opt) matEl.value = opt.value; }
        const machEl = el<HTMLSelectElement>('forge-mach');
        if (machEl) { const opt = Array.from(machEl.options).find(o => o.value.includes('forge-press-500t')); if (opt) machEl.value = opt.value; }
      }, 0);
      break;

    case 'painting':
      area.innerHTML = renderPaintingForm();
      populateSelects();
      el('add-coat-btn')?.addEventListener('click', () => addCoatRow());
      setTimeout(() => {
        const lineEl = el<HTMLSelectElement>('paint-line');
        if (lineEl) { const opt = Array.from(lineEl.options).find(o => o.value.includes('paint-line')); if (opt) lineEl.value = opt.value; }
      }, 0);
      addCoatRow({ coatType: 'e_coat',   materialId: 'mat-paint-ecoat',    dftMicrons: 20, solidsPct: 0.20, transferEfficiency: 0.95, paintDensityKgPerL: 1.3,  pricePerL: 4.55 });
      addCoatRow({ coatType: 'basecoat', materialId: 'mat-paint-basecoat', dftMicrons: 15, solidsPct: 0.35, transferEfficiency: 0.70, paintDensityKgPerL: 1.25, pricePerL: 10.25 });
      break;

    case 'biw_assembly':
      area.innerHTML = renderBIWForm();
      populateSelects();
      el('add-join-btn')?.addEventListener('click', () => addJoinRow());
      el('add-station-btn')?.addEventListener('click', () => addBIWStation());
      addJoinRow({ type: 'spot_weld', count: 120, costPerJoint: 0.05 });
      addJoinRow({ type: 'adhesive_m', count: 0.8, costPerJoint: 1.20 });
      addBIWStation({ stationName: 'Framing Station', machineId: 'robot-weld-station', labourId: 'lab-uk-skilled', cycleTimeHr: 1/60, oee: 0.85, manning: 1, labourEfficiency: 0.92 });
      break;

    case 'pcb_fab':
      area.innerHTML = renderPCBFabForm();
      populateSelects();
      wirePCBImageZone();
      if (pcbImageResult) injectPCBImagePanel(); else injectPCBDemoCards();
      break;

    case 'pcba':
      area.innerHTML = renderPCBAForm();
      populateSelects();
      wirePCBImageZone();
      if (pcbImageResult) injectPCBImagePanel(); else injectPCBDemoCards();
      el('add-bom-btn')?.addEventListener('click', () => addBOMRow());
      el('bom-csv-input')?.addEventListener('change', importBOMFromCSV);
      setTimeout(() => {
        const smtEl = el<HTMLSelectElement>('pcba-smt-mach');
        if (smtEl) { const opt = Array.from(smtEl.options).find(o => o.value.includes('smt-line')); if (opt) smtEl.value = opt.value; }
      }, 0);
      addBOMRow({ refDes: 'R1-R10', componentType: 'passive_0402', description: '10k 0402', qty: 10, unitPriceGBP: 0.008, moq: 1000 });
      addBOMRow({ refDes: 'U1',     componentType: 'ic_qfn',        description: 'MCU QFN',   qty: 1,  unitPriceGBP: 2.80,  moq: 10 });
      break;

    case 'cast_and_machine':
      area.innerHTML = renderCastAndMachineForm();
      populateSelects();
      el('cam-cast-subtype')?.addEventListener('change', updateCAMCastSubtype);
      el('cam-complexity')?.addEventListener('change', updateCAMRecommendation);
      el('add-cam-mach-op-btn')?.addEventListener('click', () => addCAMMachOp());
      updateCAMCastSubtype();
      updateCAMRecommendation();
      camMachOpCount = 0;
      setTimeout(() => {
        const matEl = el<HTMLSelectElement>('cam-mat');
        if (matEl) { const opt = Array.from(matEl.options).find(o => o.value.includes('mat-adc12')); if (opt) matEl.value = opt.value; }
        const machEl = el<HTMLSelectElement>('cam-hpdc-mach');
        if (machEl) { const opt = Array.from(machEl.options).find(o => o.value.includes('hpdc-800t')); if (opt) machEl.value = opt.value; }
        const setupMachEl = el<HTMLSelectElement>('cam-mach-setup-mach');
        if (setupMachEl) { const opt = Array.from(setupMachEl.options).find(o => o.value.includes('mach-haas-vf2')); if (opt) setupMachEl.value = opt.value; }
      }, 0);
      addCAMMachOp({ name: 'Face Mill', type: 'milling_3ax', machineId: 'mach-haas-vf2', labourId: 'lab-uk-skilled', cycleTimeHr: 0.05, partsPerCycle: 1, oee: 0.85, manning: 1, labourTimeHr: 0.05, labourEfficiency: 0.92 });
      break;

    case 'blow_moulding':
      area.innerHTML = renderBlowMouldingForm();
      populateSelects();
      setTimeout(() => {
        // Filter material select to blow-moulding-relevant materials only
        const matEl = el<HTMLSelectElement>('bm-mat');
        if (matEl) {
          const bmMatIds = new Set(['mat-hdpe', 'mat-ldpe', 'mat-pet-bg']);
          const bmMats = library.materials.filter(m => m.category === 'Blow Moulding' || bmMatIds.has(m.id));
          matEl.innerHTML = bmMats.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.grade)} — £${m.pricePerKg.toFixed(2)}/kg</option>`).join('');
          if (Array.from(matEl.options).some(o => o.value === 'mat-hdpe')) matEl.value = 'mat-hdpe';
        }
        // Filter machine select to blow-moulding machines only
        const bmMachIds = new Set(['blow-ebm-100l','blow-ebm-500l','blow-ebm-2head','blow-ebm-coex3','blow-ebm-coex5','blow-ebm-large','blow-ibm-rotary','blow-ibm-linear','blow-sbm-1stage','blow-sbm-2stage','blow-deflash-trimmer']);
        const machEl = el<HTMLSelectElement>('bm-mach');
        if (machEl) {
          const bmMachs = library.machines.filter(m => bmMachIds.has(m.id));
          machEl.innerHTML = bmMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('');
        }
        // Deflash machine select — only the deflash trimmer
        const deflashEl = el<HTMLSelectElement>('bm-deflash-mach');
        if (deflashEl) {
          const deflashMach = library.machines.find(m => m.id === 'blow-deflash-trimmer');
          deflashEl.innerHTML = `<option value="">None</option>${deflashMach ? `<option value="${deflashMach.id}">${escHtml(deflashMach.machineClass)} — £${deflashMach.computedRatePerHr.toFixed(2)}/hr</option>` : ''}`;
        }
        // Labour default to semiskilled
        const labEl = el<HTMLSelectElement>('bm-lab');
        if (labEl) { const opt = Array.from(labEl.options).find(o => o.value === 'lab-uk-blow') ?? Array.from(labEl.options).find(o => o.value === 'lab-uk-semiskilled'); if (opt) labEl.value = opt.value; }
        wireBlowMouldingProcessChange();
        wireBlowDFM();
      }, 0);
      break;

    case 'extrusion':
      area.innerHTML = renderExtrusionForm();
      populateSelects();
      setTimeout(() => {
        // Filter the material picker to polymer/extrusion families (not metals/castings/forgings).
        const allowMat = new Set(['Extrusion', 'Thermoplastic', 'Blow Moulding', 'Thermoplastic Elastomer', 'High-Performance Thermoplastic', 'Rubber']);
        const matEl = el<HTMLSelectElement>('ext-mat');
        if (matEl) {
          const catOf = (id: string) => library.materials.find(m => m.id === id)?.category ?? '';
          Array.from(matEl.options).forEach(o => { if (!allowMat.has(catOf(o.value))) o.remove(); });
          const pref = Array.from(matEl.options).find(o => o.value === 'mat-pe100-pipe') || Array.from(matEl.options).find(o => o.value.includes('mat-hdpe'));
          if (pref) matEl.value = pref.value;
        }
        // Populate the additive/masterbatch picker.
        const addEl = el<HTMLSelectElement>('ext-additive');
        if (addEl) {
          const adds = library.materials.filter(m => m.category === 'Additive / Masterbatch');
          addEl.innerHTML = '<option value="">None</option>' + adds.map(a => `<option value="${a.id}">${a.grade} — ${_currFmt(a.pricePerKg)}/kg</option>`).join('');
        }
        const machEl = el<HTMLSelectElement>('ext-mach');
        if (machEl) { const opt = Array.from(machEl.options).find(o => o.value.includes('extruder-pipe-line')); if (opt) machEl.value = opt.value; }
        wireExtrusionAdvisor();
      }, 0);
      break;

    case 'thermoforming':
      area.innerHTML = renderThermoformingForm();
      populateSelects();
      setTimeout(() => {
        // Filter the material picker to formable sheet grades (not metals/castings/forgings).
        const allowMat = new Set(['Thermoforming Sheet', 'Thermoplastic', 'Extrusion', 'High-Performance Thermoplastic']);
        const matEl = el<HTMLSelectElement>('tf-mat');
        if (matEl) {
          const catOf = (id: string) => library.materials.find(m => m.id === id)?.category ?? '';
          Array.from(matEl.options).forEach(o => { if (!allowMat.has(catOf(o.value))) o.remove(); });
          const pref = Array.from(matEl.options).find(o => o.value === 'mat-hips-tf') || Array.from(matEl.options).find(o => o.value.includes('mat-hips'));
          if (pref) matEl.value = pref.value;
        }
        // Populate the additive/masterbatch picker.
        const addEl = el<HTMLSelectElement>('tf-additive');
        if (addEl) {
          const adds = library.materials.filter(m => m.category === 'Additive / Masterbatch');
          addEl.innerHTML = '<option value="">None</option>' + adds.map(a => `<option value="${a.id}">${a.grade} — ${_currFmt(a.pricePerKg)}/kg</option>`).join('');
        }
        // Filter the machine picker to thermoformers only.
        const machEl = el<HTMLSelectElement>('tf-mach');
        if (machEl) {
          const tfMachs = library.machines.filter(m => m.id.startsWith('thermoform'));
          if (tfMachs.length) machEl.innerHTML = tfMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — ${_currFmt(m.computedRatePerHr)}/hr</option>`).join('');
          const opt = Array.from(machEl.options).find(o => o.value.includes('thermoform-small')); if (opt) machEl.value = opt.value;
        }
        // Default labour to the thermoforming operator.
        const labEl = el<HTMLSelectElement>('tf-lab');
        if (labEl) { const opt = Array.from(labEl.options).find(o => o.value.includes('lab-uk-thermoform')); if (opt) labEl.value = opt.value; }
        wireThermoformingAdvisor();
      }, 0);
      break;

    case 'rotational_moulding':
      area.innerHTML = renderRotationalMouldingForm();
      populateSelects();
      setTimeout(() => {
        // Filter machine select to rotomoulders only
        const rmMachEl = el<HTMLSelectElement>('rm-mach');
        if (rmMachEl) {
          const rmMachs = library.machines.filter(m => m.id.startsWith('rotomould'));
          if (rmMachs.length) rmMachEl.innerHTML = rmMachs.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.machineClass)} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`).join('');
          if (Array.from(rmMachEl.options).some(o => o.value === 'rotomould-biaxial')) rmMachEl.value = 'rotomould-biaxial';
        }
        // Filter material select to roto grades (+ generic LLDPE fallback)
        const matEl = el<HTMLSelectElement>('rm-mat');
        if (matEl) {
          const rmMats = library.materials.filter(m => m.category === 'Rotational Moulding' || m.id === 'mat-lldpe');
          if (rmMats.length) matEl.innerHTML = rmMats.map(m => `<option value="${escHtml(m.id)}">${escHtml(m.grade)} — £${m.pricePerKg.toFixed(2)}/kg</option>`).join('');
          if (Array.from(matEl.options).some(o => o.value === 'mat-lldpe-roto')) matEl.value = 'mat-lldpe-roto';
        }
        const labEl = el<HTMLSelectElement>('rm-lab');
        if (labEl) { const opt = Array.from(labEl.options).find(o => o.value === 'lab-uk-roto') ?? Array.from(labEl.options).find(o => o.value === 'lab-uk-semiskilled'); if (opt) labEl.value = opt.value; }
        wireRotoDFM();
      }, 0);
      break;

    case 'rubber':
      area.innerHTML = renderRubberForm();
      populateSelects();
      setTimeout(() => {
        // Filter material select to rubber compounds only
        const matEl = el<HTMLSelectElement>('rub-mat');
        if (matEl) {
          const rubberMats = library.materials.filter(m => m.category === 'Rubber');
          matEl.innerHTML = rubberMats.map(m =>
            `<option value="${m.id}">${m.grade} — £${m.pricePerKg.toFixed(2)}/kg</option>`
          ).join('');
          if (Array.from(matEl.options).some(o => o.value === 'mat-epdm')) matEl.value = 'mat-epdm';
        }
        // Filter main machine select to rubber-specific machines only
        const rubberMachIds = new Set(['compression-mould-std','transfer-mould-std','lsr-injection-machine','extruder-rubber-60mm','die-cut-press-rubber']);
        const machEl = el<HTMLSelectElement>('rub-mach');
        if (machEl) {
          const rubberMachs = library.machines.filter(m => rubberMachIds.has(m.id));
          machEl.innerHTML = rubberMachs.map(m =>
            `<option value="${m.id}">${m.machineClass} — £${m.computedRatePerHr.toFixed(2)}/hr</option>`
          ).join('');
        }
        // Filter cure oven select to only the rubber cure oven
        const cureMachEl = el<HTMLSelectElement>('rub-cure-mach');
        if (cureMachEl) {
          const cureOven = library.machines.find(m => m.id === 'cure-oven-rubber');
          cureMachEl.innerHTML = `<option value="">— none —</option>${cureOven ? `<option value="${cureOven.id}">${cureOven.machineClass} — £${cureOven.computedRatePerHr.toFixed(2)}/hr</option>` : ''}`;
        }
        // Labour — default semi-skilled operator
        const labEl = el<HTMLSelectElement>('rub-lab');
        if (labEl) {
          const opt = Array.from(labEl.options).find(o => o.value === 'lab-uk-semiskilled');
          if (opt) labEl.value = 'lab-uk-semiskilled';
        }
        // Wire process change handler — sets defaults + info band for initial process
        wireRubberProcessChange();
        wireRubberDFM();
      }, 0);
      break;

    case 'composites':
      area.innerHTML = renderCompositesForm();
      populateSelects();
      setTimeout(() => {
        const cureEl = el<HTMLSelectElement>('comp-cure-mach');
        if (cureEl) { const opt = Array.from(cureEl.options).find(o => o.value.includes('autoclave') || o.value.includes('oven-composite')); if (opt) cureEl.value = opt.value; }
        const layupLabEl = el<HTMLSelectElement>('comp-layup-lab');
        if (layupLabEl) { const opt = Array.from(layupLabEl.options).find(o => o.value.includes('skilled')); if (opt) layupLabEl.value = opt.value; }
      }, 0);
      break;

    case 'wiring_harness':
      area.innerHTML = renderWiringHarnessForm();
      populateSelects();
      setTimeout(() => {
        const testMachEl = el<HTMLSelectElement>('harn-test-mach');
        if (testMachEl) { const opt = Array.from(testMachEl.options).find(o => o.value.includes('harness-test')); if (opt) testMachEl.value = opt.value; }
        const labEl = el<HTMLSelectElement>('harn-asm-lab');
        if (labEl) { const opt = Array.from(labEl.options).find(o => o.value.includes('semiskilled')); if (opt) labEl.value = opt.value; }
      }, 0);
      break;

    case 'ai_agent' as CommodityType:
      area.innerHTML = renderAgentForm();
      _wireAgentInputEvents();
      el('universal-costs').style.display = 'none';
      el('calc-btn').style.display = 'none';
      break;

    case 'cad_analysis':
      area.innerHTML = renderCADAnalysisForm();
      wireCADEvents();
      break;

    case 'automotive_software':
      el('universal-costs').style.display = 'none';
      el('calc-btn').style.display = 'none';
      initSWPanel(area);
      break;
  }

  // Inject inline demo cards for applicable commodities (after form renders)
  const _inlineDemoCommodities = new Set(['machining','sheet_metal','sheet_metal_fab','injection_moulding','blow_moulding','extrusion','thermoforming','rotational_moulding','casting','forging','painting','biw_assembly','cast_and_machine','rubber','composites','wiring_harness']);
  if (_inlineDemoCommodities.has(type as string)) {
    area.insertAdjacentHTML('afterbegin', buildInlineDemoSection(type as string));
  }

  // Inline CAD-to-fill uploader on geometry-relevant commodity forms (reuses the
  // CAD-to-Cost OCCT pipeline + applyCADToForm mapping). Injected on top.
  if (CAD_INLINE_COMMODITIES.has(type)) {
    area.insertAdjacentHTML('afterbegin', inlineCADPanelHTML());
    wireInlineCAD(type);
  }
}

// ─── Input collectors ─────────────────────────────────────────────────────────

function getUniversalTail(): Pick<UniversalStackInput, 'partName' | 'packagingPerPart' | 'logisticsPerPart' | 'overheadPct' | 'marginPct'> {
  return {
    partName: val('part-name') || 'Unnamed Part',
    packagingPerPart: num('packaging'),
    logisticsPerPart: num('logistics'),
    overheadPct: num('overhead-pct') / 100,
    marginPct: num('margin-pct') / 100,
  };
}

function collectMachiningInput(): UniversalStackInput {
  const ops: MachiningOperation[] = Array.from(document.querySelectorAll<HTMLElement>('#mach-ops-container .op-card')).map(card => {
    const id = card.dataset.opId!;
    const opName = (el<HTMLInputElement>(`${id}-name`))?.value ?? '';
    return {
      name: opName,
      type: validSel<MachiningOperation['type']>(`${id}-type`, ['turning','milling_3ax','milling_5ax','drilling','grinding','tapping','boring'], 'turning'),
      machineId: selMachineHealed(`${id}-mach`, opName),
      labourId: selLabourHealed(`${id}-lab`),
      cycleTimeHr: parseFloat((el<HTMLInputElement>(`${id}-ct`))?.value) || 0,
      partsPerCycle: parseInt((el<HTMLInputElement>(`${id}-ppc`))?.value) || 1,
      oee: parseFloat((el<HTMLInputElement>(`${id}-oee`))?.value) || 0.85,
      manning: parseFloat((el<HTMLInputElement>(`${id}-manning`))?.value) || 1,
      labourTimeHr: parseFloat((el<HTMLInputElement>(`${id}-lt`))?.value) || 0,
      labourEfficiency: parseFloat((el<HTMLInputElement>(`${id}-le`))?.value) || 0.92,
    };
  });

  // "Primary" toggle: feature machining becomes the cost basis, so the operations
  // table above is dropped and the machining time comes entirely from the geometry
  // features (material + setup + feature ops).
  const featurePrimary = machiningFeaturePrimary();

  const drivers = computeMachiningDrivers({
    materialId: sel('mach-mat'),
    netWeightKg: num('mach-net-wt'),
    stockWeightKg: num('mach-stock-wt') || num('mach-net-wt') / 0.65,
    materialUtilization: num('mach-mat-util'),
    operations: featurePrimary ? [] : ops,
    setup: {
      setupTimeHr: num('mach-setup-time'),
      batchSize: num('mach-batch-size') || 50,
      machineId: selMachineHealed('mach-setup-mach', 'Setup'),
      labourId: selLabourHealed('mach-setup-lab'),
    },
    programmingNRE: num('mach-prog-nre'),
    toolingCost: num('mach-tooling'),
    amortizationVolume: num('mach-amort') || num('annual-volume') || 100000,
    rejectRate: num('mach-reject') || undefined,
  });

  let operations = drivers.operations;
  // Fold in feature machining when it is the PRIMARY basis (toggle on) OR as a
  // FALLBACK when the OCCT bottom-up cycle estimate is absent (mesh/STL, text
  // fallback) — otherwise those features would be uncosted. When the cycle total
  // IS present and the toggle is off, the ops already cover the features, so we
  // skip to avoid double-counting. Tooling is intentionally NOT added here (the
  // form's own tooling/NRE fields already capture machining fixtures & programming).
  const hasOcctCycleTotal = !!(cadOCCTGeometry?.cncCycleTimeEstimate?.estimatedTotalHrs);
  if (featurePrimary || !hasOcctCycleTotal) {
    const secondary = collectSecondaryMachining('mach');
    if (secondary) operations = [...operations, ...secondary.ops];
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations, tooling: drivers.tooling };
}

function collectSheetMetalInput(): UniversalStackInput {
  const materialId = sel('sm-mat');
  const pressId = sel('sm-press');
  const perimeterMm = num('sm-perim');
  const thicknessMm = num('sm-thick');
  const shearStrengthMPa = num('sm-shear');

  // Density from the active library — enables the accurate strip-consumption
  // gross-material model in computeSheetMetalDrivers (captures trim/pierce scrap).
  const densityKgPerM3 = library.materials.find(m => m.id === materialId)?.densityKgPerM3;

  // Press-tonnage adequacy check (surfaced as a warning in compute()).
  _smExtraWarnings = [];
  const press = library.machines.find(m => m.id === pressId);
  // Tonnage is encoded in the id ('press-400t', 'press-schuler-400t') and/or class label.
  const pressLabel = `${press?.machineClass ?? ''} ${pressId}`;
  const tMatch = /(\d+(?:\.\d+)?)\s*t\b/i.exec(pressLabel);
  const capacityTonnes = tMatch ? parseFloat(tMatch[1]) : 0;
  if (perimeterMm > 0 && thicknessMm > 0 && shearStrengthMPa > 0) {
    const assessment = assessPressTonnage({ perimeterMm, thicknessMm, shearStrengthMPa }, capacityTonnes);
    if (assessment.message) _smExtraWarnings.push(`Press tonnage: ${assessment.message}`);
  }
  if ((num('sm-amort') || 0) <= 0) _smExtraWarnings.push('Amortisation volume is empty/zero — tooling NRE defaulted to 1 part (full die cost on this part). Set a realistic programme volume.');

  const dieType = validSel<StampingDieType>('sm-die-type', ['progressive', 'transfer', 'single_stage', 'fine_blanking'], 'progressive');
  const hotStamping = sel('sm-hs-on') === 'yes';
  const stations = num('sm-num-ops') || 1;

  // E-motor lamination finishing (join + stress-relief anneal energy + re-coat).
  let extraConsumablesPerPart: number | undefined;
  const lamMethod = sel('sm-lam-method');
  if (lamMethod) {
    const fin = estimateLaminationFinishing({
      stackMethod: lamMethod as StackMethod,
      laminationCount: num('sm-lam-count') || 1,
      stackHeightMm: num('sm-lam-height') || undefined,
      partWeightKg: num('sm-net-wt'),
      stressReliefAnneal: sel('sm-lam-anneal') === 'yes',
      reCoat: sel('sm-lam-coat') === 'yes',
      annealEnergyPricePerKwh: library.energy?.[0]?.electricityPerKwh ?? 0.23,
    });
    extraConsumablesPerPart = fin.totalPerPart;
    _smExtraWarnings.push(
      `Lamination finishing: £${fin.totalPerPart.toFixed(3)}/part — join £${fin.joinPerStack.toFixed(3)}/stack ÷ ${num('sm-lam-count') || 1}` +
      `${fin.annealEnergyPerPart ? ` + anneal £${fin.annealEnergyPerPart.toFixed(3)}` : ''}` +
      `${fin.coatingPerPart ? ` + coat £${fin.coatingPerPart.toFixed(3)}` : ''}. ` +
      `Add the anneal/weld/bond machine time as a secondary op if in-house.`
    );
  }
  const blankAreaCm2 = (num('sm-blank-l') * num('sm-blank-w')) / 100;
  const manualDieCost = num('sm-die-cost');
  const manualDieLife = num('sm-die-life');

  // Surface the die-cost estimate / die-life prediction when auto-derived.
  if (manualDieCost <= 0 && blankAreaCm2 > 0 && shearStrengthMPa > 0) {
    const est = estimateStampingDieCost({ dieType, stations, blankAreaCm2, shearStrengthMPa });
    _smExtraWarnings.push(
      `Tooling: die cost auto-estimated at £${est.total.toLocaleString()} ` +
      `(${dieType.replace('_', ' ')}, ${stations} stations, ${Math.round(blankAreaCm2)} cm², shear ${shearStrengthMPa} MPa). Enter a Die Cost to override.`
    );
  }
  if (manualDieLife <= 0 && shearStrengthMPa > 0 && thicknessMm > 0) {
    const life = estimateStampingDieLife({ shearStrengthMPa, thicknessMm, dieType });
    _smExtraWarnings.push(
      `Tooling: die life auto-predicted at ${life.toLocaleString()} strokes ` +
      `(shear ${shearStrengthMPa} MPa, ${thicknessMm} mm, ${dieType.replace('_', ' ')}). Enter Die Life to override.`
    );
  }

  const drivers = computeSheetMetalDrivers({
    materialId,
    netWeightKg: num('sm-net-wt'),
    blankLengthMm: num('sm-blank-l'),
    blankWidthMm: num('sm-blank-w'),
    thicknessMm,
    perimeterMm,
    shearStrengthMPa,
    stripWidthMm: num('sm-strip-w'),
    pitchMm: num('sm-pitch'),
    partsPerStroke: num('sm-pps') || 1,
    densityKgPerM3,
    pressId,
    labourId: sel('sm-lab'),
    strokesPerMin: num('sm-spm'),
    oee: num('sm-oee'),
    manning: num('sm-manning'),
    labourEfficiency: num('sm-lab-eff'),
    numOperations: num('sm-num-ops') || 1,
    dieType,
    dieLife: num('sm-die-life'),
    dieCostEstimate: num('sm-die-cost'),
    amortizationVolume: num('sm-amort') || num('annual-volume') || 100000,
    rejectRate: num('sm-reject') || undefined,
    secondaryOpsMachineId: sel('sm-sec-mach') || undefined,
    secondaryOpsLabourId: sel('sm-sec-lab') || undefined,
    secondaryOpsCycleHr: num('sm-sec-ct') || undefined,
    secondaryOpsOee: num('sm-sec-oee') || undefined,
    secondaryOpsManning: num('sm-sec-manning') || undefined,
    secondaryOpsLabourEfficiency: num('sm-sec-lab-eff') || undefined,
    secondaryOps: [
      { machineId: sel('sm-sec2-mach'), labourId: sel('sm-sec2-lab'), cycleTimeHr: num('sm-sec2-ct'), operationName: 'Secondary Operation 2' },
      { machineId: sel('sm-sec3-mach'), labourId: sel('sm-sec3-lab'), cycleTimeHr: num('sm-sec3-ct'), operationName: 'Secondary Operation 3' },
    ].filter(op => op.machineId && op.labourId && op.cycleTimeHr > 0),
    hotStamping,
    austenitiseEnergyKwhPerKg: hotStamping ? (num('sm-hs-energy') || 0.30) : undefined,
    hotStampingEnergyPricePerKwh: hotStamping ? (library.energy?.[0]?.electricityPerKwh ?? 0.23) : undefined,
    quenchDwellSec: hotStamping ? (num('sm-hs-dwell') || undefined) : undefined,
    furnaceMachineId: hotStamping ? (sel('sm-hs-furn-mach') || undefined) : undefined,
    furnaceLabourId: hotStamping ? (sel('sm-hs-furn-lab') || undefined) : undefined,
    furnaceCycleHrPerPart: hotStamping ? (num('sm-hs-furn-ct') || undefined) : undefined,
    extraConsumablesPerPart,
  });

  if (hotStamping) {
    _smExtraWarnings.push(
      `Hot stamping: austenitising-furnace energy costed at ${num('sm-hs-energy') || 0.30} kWh/kg × blank × £${library.energy?.[0]?.electricityPerKwh ?? 0.23}/kWh; ` +
      `press cycle set by ${num('sm-hs-dwell') || 8}s quench dwell (not SPM).`
    );
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** SM3: wire the stamping process-advisor + DFM widget. */
function wireStampingAdvisor(): void {
  const btn = document.getElementById('sm-adv-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    const materialFamily = validSel<SMMaterialFamily>('sm-adv-fam', ['steel','stainless','aluminium','galvanised'], 'steel');
    const thicknessMm = num('sm-thick') || 1.5;
    const complexity = validSel<'low'|'medium'|'high'>('sm-adv-cmplx', ['low','medium','high'], 'medium');
    const holeDensity = validSel<'low'|'high'>('sm-adv-holes', ['low','high'], 'low');
    const rec = adviseSheetMetalProcess({ annualVolume: num('sm-adv-vol') || 200000, thicknessMm, complexity, holeDensity, materialFamily });
    const dfm = analyseSheetMetalDFM({
      thicknessMm,
      materialFamily,
      highStrength: sel('sm-adv-hss') === 'yes',
      bendCount: num('sm-adv-bends') || undefined,
      minBendRadiusMm: num('sm-adv-bendr') || undefined,
      minHoleDiameterMm: num('sm-adv-hole') || undefined,
      minFeatureToEdgeMm: num('sm-adv-edge') || undefined,
    });
    const out = document.getElementById('sm-adv-result');
    if (!out) return;
    const volLabel = { low: '< 1k', medium: '1k–50k', high: '> 50k' }[rec.volumeCategory];

    // If a lamination stack method is selected, add a lamination-specific DFM panel.
    const lamMethod = sel('sm-lam-method');
    let lamHtml = '';
    if (lamMethod) {
      const lamDfm = analyseLaminationDFM({
        thicknessMm,
        minToothWidthMm: num('sm-lam-tooth') || undefined,
        stackMethod: lamMethod as StackMethod,
        stressReliefAnneal: sel('sm-lam-anneal') === 'yes',
        thinGauge: thicknessMm > 0 && thicknessMm <= 0.27,
      });
      lamHtml = `<div style="margin-top:6px;font-weight:600;color:#0059b3">Lamination DFM</div>${renderDFMPanel(lamDfm.score, lamDfm.issues, lamDfm.summary)}`;
    }

    out.innerHTML = `
      <div style="background:#fff;border:1px solid #e0e0e0;border-radius:4px;padding:8px;margin-bottom:6px">
        <div style="font-weight:700;color:#b34700">${escHtml(rec.primaryProcess)} → ${escHtml(rec.formingProcess)}</div>
        <div style="color:#555;margin-top:2px">Route: ${rec.processRoute.map(escHtml).join(' → ')}</div>
        <div style="margin-top:4px;display:flex;gap:12px;flex-wrap:wrap">
          <span><strong>Volume:</strong> ${volLabel}/yr</span>
          <span><strong>Tolerance:</strong> ${escHtml(rec.toleranceCapability)}</span>
          <span><strong>Tooling:</strong> ${escHtml(rec.toolingBand)}</span>
        </div>
        <div style="color:#555;margin-top:4px"><em>${escHtml(rec.reason)}</em></div>
      </div>
      ${renderDFMPanel(dfm.score, dfm.issues, dfm.summary)}
      ${lamHtml}`;
    out.style.display = 'block';
  });
}

function collectIMMInput(): UniversalStackInput {
  const runnerSystem = validSel<'cold'|'hot'>('imm-runner-sys', ['cold','hot'], 'cold');
  const cavities = num('imm-cav') || 1;
  const projectedAreaCm2 = num('imm-area');
  const cavityPressureMPa = num('imm-cav-press');
  const machineId = sel('imm-mach');
  const steelClass = validSel<MouldSteelClass>('imm-steel-class', ['prototype','standard','production','high_volume'], 'standard');
  const sideActionsLifters = num('imm-side-actions') || 0;
  const manualMouldCost = num('imm-mould-cost');

  const drivers = computeInjectionMouldingDrivers({
    materialId: sel('imm-mat'),
    partWeightKg: num('imm-part-wt'),
    runnerSystem,
    runnerWeightKg: num('imm-runner-wt'),
    regrindFraction: num('imm-regrind'),
    cavities,
    projectedAreaCm2,
    cavityPressureMPa,
    wallThicknessMm: num('imm-wall'),
    coolTimeFactorSPerMm2: num('imm-cool-f'),
    fillTimeSec: num('imm-fill'),
    packTimeSec: num('imm-pack'),
    ejectTimeSec: num('imm-eject'),
    machineId,
    labourId: sel('imm-lab'),
    oee: num('imm-oee'),
    manning: num('imm-manning'),
    labourEfficiency: num('imm-lab-eff'),
    // 0 / blank → estimate parametrically from cavities, area, steel class, side-actions, runner.
    mouldCost: manualMouldCost > 0 ? manualMouldCost : undefined,
    steelClass,
    sideActionsLifters,
    mouldLife: num('imm-mould-life'),
    amortizationVolume: num('imm-amort') || num('annual-volume') || 100000,
    toleranceMm: num('imm-tolerance') || undefined,
    surfaceFinishGrade: validSel<'standard'|'textured'|'high_gloss'|'painted'>('imm-finish', ['standard','textured','high_gloss','painted'], 'standard'),
  });

  // H5: clamping-tonnage validation — warn if the part needs more clamp than the selected machine.
  const ratedTonnage = parseImmRatedTonnage(machineId);
  if (ratedTonnage && projectedAreaCm2 > 0 && cavityPressureMPa > 0) {
    const requiredTonnage = estimateClampingTonnage({ projectedAreaCm2, cavityPressureMPa });
    if (requiredTonnage > ratedTonnage) {
      _smExtraWarnings.push(
        `Clamping tonnage: part needs ≈${Math.round(requiredTonnage)}T (${projectedAreaCm2} cm² × ${cavityPressureMPa} MPa × 1.15 SF) ` +
        `but the selected ${ratedTonnage}T machine is undersized — flash, short shots or press damage. ` +
        `Select a machine ≥ ${Math.ceil(requiredTonnage / 50) * 50}T, reduce cavitation, or lower cavity pressure.`
      );
    } else if (requiredTonnage > ratedTonnage * 0.9) {
      _smExtraWarnings.push(
        `Clamping tonnage: part needs ≈${Math.round(requiredTonnage)}T vs ${ratedTonnage}T rated — running above 90% of clamp capacity leaves little safety margin.`
      );
    }
  }

  // H3: surface the estimated tool cost when it was auto-derived (mould cost left at 0).
  if (manualMouldCost <= 0) {
    const est = estimateMouldCost({ cavities, projectedAreaCm2, steelClass, sideActionsLifters, runnerSystem });
    _smExtraWarnings.push(
      `Tooling: mould cost auto-estimated at £${est.total.toLocaleString()} ` +
      `(base £${est.base.toLocaleString()} + cavities £${est.cavityBlock.toLocaleString()}` +
      `${est.sideActions ? ` + side-actions £${est.sideActions.toLocaleString()}` : ''}` +
      `${est.hotRunner ? ` + hot-runner £${est.hotRunner.toLocaleString()}` : ''}). Enter a Mould Cost to override.`
    );
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** Parse an IMM machine's rated clamp tonnage from its id (e.g. 'imm-400t' → 400). */
function parseImmRatedTonnage(machineId: string): number | null {
  const m = /(?:^|-)(\d+)t\b/i.exec(machineId);
  return m ? Number(m[1]) : null;
}

/** M7: set the injection cool-factor field from the selected resin's diffusivity-derived value. */
function syncImmCoolFactor(): void {
  const matId = sel('imm-mat');
  const coolEl = el<HTMLInputElement>('imm-cool-f');
  if (!matId || !coolEl) return;
  coolEl.value = String(autoCoolFactorForMaterial(matId));
}

function collectCastingInput(): UniversalStackInput {
  const subtype = validSel<CastingSubtype>('cast-subtype', ['hpdc', 'sand', 'gravity', 'investment'], 'hpdc');
  const common = {
    subtype,
    materialId: sel('cast-mat'),
    partWeightKg: num('cast-part-wt'),
    castingYield: num('cast-yield'),
    rejectRate: num('cast-reject'),
    labourId: sel('cast-lab'),
    oee: num('cast-oee'),
    manning: num('cast-manning'),
    labourEfficiency: num('cast-lab-eff'),
    amortizationVolume: num('cast-amort') || num('annual-volume') || 100000,
  };
  let extra = {};
  if (subtype === 'hpdc') extra = { hpdc: { machineId: sel('cast-hpdc-mach'), cycleTimeSec: num('cast-hpdc-ct'), cavities: num('cast-hpdc-cav') || 1, dieCost: num('cast-hpdc-die-cost'), dieLife: num('cast-hpdc-die-life') } };
  else if (subtype === 'sand') extra = { sand: { mouldLineId: sel('cast-sand-line'), cycleTimeHr: num('cast-sand-ct'), patternCost: num('cast-sand-pat-cost'), patternLife: num('cast-sand-pat-life'), coreCostPerPart: num('cast-sand-core') } };
  else if (subtype === 'gravity') extra = { gravity: { machineId: sel('cast-grav-mach'), cycleTimeHr: num('cast-grav-ct'), mouldCost: num('cast-grav-mould-cost'), mouldLife: num('cast-grav-mould-life') } };
  else if (subtype === 'investment') extra = { investment: { pourMachineId: sel('cast-inv-mach'), pourLabourId: sel('cast-inv-lab') || sel('cast-lab'), pourCycleHr: num('cast-inv-ct'), waxCostPerPart: num('cast-inv-wax'), shellBuildCostPerPart: num('cast-inv-shell'), waxRecoveryFraction: num('cast-inv-wax-rec') } };

  // C17: Warn when casting yield and reject rate appear to double-count losses
  const castYield = num('cast-yield');
  const castReject = num('cast-reject');
  if (castYield < 0.55 && castReject > 0.08) {
    showToast(
      `Casting: yield ${(castYield * 100).toFixed(0)}% AND reject rate ${(castReject * 100).toFixed(0)}% are both high. ` +
      'Yield (runner/gate loss) and reject rate (quality scrap) are additive — verify both are not capturing the same losses.',
      'warning'
    );
  }

  const secondary = collectSecondaryMachining('cast');
  const drivers = computeCastingDrivers({
    ...common, ...extra,
    secondaryMachiningOps: secondary?.ops,
    secondaryMachiningToolingCost: secondary?.toolingCost,
  });
  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function collectForgingInput(): UniversalStackInput {
  const trimCt = num('forge-trim-ct');
  const trimmingMachineId = sel('forge-trim-mach') || undefined;
  const trimmingLabourId = sel('forge-trim-lab') || undefined;

  const materialId = sel('forge-mat');
  const forgeId = sel('forge-mach');
  const partWeightKg = num('forge-part-wt');
  const flashAndScaleKg = num('forge-flash');
  const yieldFraction = num('forge-yield');
  const projectedAreaCm2 = num('forge-proj-area');
  const shapeComplexity = validSel<ShapeComplexity>('forge-shape', ['simple','moderate','complex'], 'moderate');
  const dieSteel = validSel<DieSteel>('forge-die-steel', ['h13','premium','hammer'], 'h13');
  const dieImpressions = num('forge-die-impr') || 2;
  const manualDieCost = num('forge-die-cost');
  const furnaceType = validSel<FurnaceType>('forge-furnace', ['induction','gas','electric-resistance'], 'induction');

  // F-C1: resolve the region's heating tariff for the selected fuel from the active library.
  const elecPerKwh = library.energy?.[0]?.electricityPerKwh ?? 0.23;
  const gasPerKwh = library.energy?.[0]?.gasPerKwh ?? 0.065;
  const heatingEnergyPricePerKwh = resolveFurnaceEnergyPricePerKwh(furnaceType, elecPerKwh, gasPerKwh);

  const alloyFamily = forgingAlloyFamilyFor(materialId);

  // F2-A: predict die life from alloy/size/complexity when left at 0.
  const manualDieLife = num('forge-die-life');
  const dieLife = manualDieLife > 0
    ? manualDieLife
    : estimateForgingDieLife({ alloyFamily, projectedAreaCm2, complexity: shapeComplexity });

  // F2-C: optional preform / blocker stage.
  const preformCt = num('forge-preform-ct');
  const preformMachineId = sel('forge-preform-mach') || undefined;
  const preformLabourId = sel('forge-preform-lab') || undefined;

  const forgeSecondary = collectSecondaryMachining('forge');

  const drivers = computeForgingDrivers({
    materialId,
    partWeightKg,
    flashAndScaleKg,
    yieldFraction,
    forgeId,
    labourId: sel('forge-lab'),
    strokesToForm: num('forge-strokes') || 1,
    timePerBlowSec: num('forge-time-per-blow') || undefined,
    cycleTimeHr: num('forge-ct'),
    oee: num('forge-oee'),
    manning: num('forge-manning'),
    labourEfficiency: num('forge-lab-eff'),
    heatingEnergyKwhPerKg: num('forge-heat-energy'),
    heatingEnergyPricePerKwh,
    dieLife,
    // 0 / blank → estimate parametrically from area, steel, impressions and complexity.
    dieCost: manualDieCost > 0 ? manualDieCost : undefined,
    projectedAreaCm2,
    dieSteel,
    dieImpressions,
    dieComplexity: shapeComplexity,
    amortizationVolume: num('forge-amort') || num('annual-volume') || 100000,
    secondaryMachiningOps: forgeSecondary?.ops,
    secondaryMachiningToolingCost: forgeSecondary?.toolingCost,
    heatTreatCostPerKg: num('forge-ht-cost') || undefined,
    descaleCostPerKg: num('forge-descale') || undefined,
    coiningCostPerPart: num('forge-coining') || undefined,
    ndtCostPerPart: num('forge-ndt') || undefined,
    preformMachineId: preformCt > 0 ? preformMachineId : undefined,
    preformLabourId: preformCt > 0 ? preformLabourId : undefined,
    preformCycleHr: preformCt > 0 ? preformCt : undefined,
    trimmingMachineId: trimCt > 0 ? trimmingMachineId : undefined,
    trimmingLabourId: trimCt > 0 ? trimmingLabourId : undefined,
    trimmingCycleHr: trimCt > 0 ? trimCt : undefined,
  });

  // F2-A: surface the predicted die life when auto-derived.
  if (manualDieLife <= 0) {
    _smExtraWarnings.push(
      `Tooling: die life auto-predicted at ${dieLife.toLocaleString()} forgings/set ` +
      `(${alloyFamily}, ${projectedAreaCm2} cm², ${shapeComplexity}). Enter Die Life to override.`
    );
  }

  // F-H2: forging-load validation — warn if the part needs more force than the press can deliver.
  // Only force-rated machines (press / screw / upsetter) carry a tonnage; hammers do not.
  const ratedTonnage = parseForgeRatedTonnage(forgeId);
  if (ratedTonnage && projectedAreaCm2 > 0) {
    const requiredTonnage = estimateForgingTonnage({ projectedAreaCm2, alloyFamily, shapeComplexity });
    if (requiredTonnage > ratedTonnage) {
      _smExtraWarnings.push(
        `Forging load: part needs ≈${Math.round(requiredTonnage)}T (${projectedAreaCm2} cm² × ${alloyFamily} flow stress × ${shapeComplexity} shape) ` +
        `but the selected ${ratedTonnage}T press is undersized — under-fill, laps or press overload. ` +
        `Select a press ≥ ${Math.ceil(requiredTonnage / 500) * 500}T, simplify the shape, or split into a preform + finish sequence.`
      );
    } else if (requiredTonnage > ratedTonnage * 0.9) {
      _smExtraWarnings.push(
        `Forging load: part needs ≈${Math.round(requiredTonnage)}T vs ${ratedTonnage}T rated — running near press capacity leaves little margin for die wear/temperature drop.`
      );
    }
  }

  // F-H3: surface the die-cost estimate when it was auto-derived.
  if (manualDieCost <= 0) {
    const est = estimateForgingDieCost({ projectedAreaCm2, partWeightKg, dieSteel, impressions: dieImpressions, complexity: shapeComplexity });
    _smExtraWarnings.push(
      `Tooling: die cost auto-estimated at £${est.total.toLocaleString()} ` +
      `(block £${est.block.toLocaleString()} + machining £${est.machining.toLocaleString()} + HT £${est.heatTreat.toLocaleString()} + polish £${est.polish.toLocaleString()}). Enter a Die Cost to override.`
    );
  }

  // F-M4: scale double-count guard — flash+scale AND a low yield both cite furnace scale.
  if (flashAndScaleKg > 0 && yieldFraction > 0 && yieldFraction < 0.85 && partWeightKg > 0) {
    const flashFrac = flashAndScaleKg / (partWeightKg + flashAndScaleKg);
    if (flashFrac > 0.15) {
      _smExtraWarnings.push(
        `Material loss: Flash+Scale (${(flashFrac * 100).toFixed(0)}% of forged weight) AND yield ${(yieldFraction * 100).toFixed(0)}% both account for scale. ` +
        `Enter flash in "Flash + Scale" and reserve Yield for end-crop/bar-loss only, or scale may be double-counted.`
      );
    }
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** Parse a force-rated forge machine's tonnage from its id (press/screw/upsetter only). */
function parseForgeRatedTonnage(machineId: string): number | null {
  if (!/press|screw|upsetter/i.test(machineId)) return null;   // hammers are energy-rated
  const m = /(\d+)t\b/i.exec(machineId);
  return m ? Number(m[1]) : null;
}

/** Infer the forging alloy family from a material's library category (for load estimation). */
function forgingAlloyFamilyFor(materialId: string): ForgingAlloyFamily {
  const cat = (library.materials.find(m => m.id === materialId)?.category ?? '').toLowerCase();
  if (cat.includes('titanium')) return 'titanium';
  if (cat.includes('superalloy') || cat.includes('nickel')) return 'superalloy';
  if (cat.includes('stainless')) return 'stainless-steel';
  if (cat.includes('alloy steel')) return 'alloy-steel';
  if (cat.includes('aluminium') || cat.includes('magnesium')) return 'aluminium';
  if (cat.includes('brass') || cat.includes('copper') || cat.includes('bronze')) return 'copper';
  return 'carbon-steel';
}

/** F2-B: wire the forging process/DFM advisor widget (process route + geometry check). */
function wireForgingAdvisor(): void {
  const btn = document.getElementById('forge-adv-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    const volume = num('forge-adv-vol') || 100000;
    const alloyFamily = validSel<ForgingAlloyFamily>('forge-adv-alloy',
      ['carbon-steel','alloy-steel','microalloyed-steel','stainless-steel','aluminium','titanium','superalloy','copper'], 'alloy-steel');
    const complexity = validSel<ComplexityLevel>('forge-adv-cmplx', ['low','medium','high'], 'medium');
    const toleranceClass = validSel<ToleranceClass>('forge-adv-tol', ['loose','standard','tight'], 'standard');
    const isRingShape = sel('forge-adv-ring') === 'yes';
    const safetyCritical = sel('forge-adv-safety') === 'yes';
    const partWeightKg = num('forge-part-wt') || 1.5;

    const rec = adviseForgingProcess({ annualVolume: volume, partWeightKg, complexity, alloyFamily, toleranceClass, isRingShape, safetyCritical });
    const dfm = analyseForgingDFM({
      process: rec.process as ForgingProcess,
      minWebThicknessMm: num('forge-adv-web') || rec.reference.minWebMm,
      draftAngleDeg: num('forge-adv-draft'),
      filletRadiusMm: num('forge-adv-fillet') || undefined,
      ribHeightToThickness: num('forge-adv-rib') || undefined,
      machiningStockMm: num('forge-adv-stock') || undefined,
    });

    const sevColor: Record<string, string> = { critical: '#c62828', major: '#e65100', minor: '#f9a825', opportunity: '#2e7d32' };
    const scoreColor = dfm.score >= 8 ? '#2e7d32' : dfm.score >= 5 ? '#e65100' : '#c62828';
    const issuesHtml = dfm.issues.length === 0
      ? `<div style="color:#2e7d32;margin-top:4px">✓ ${escHtml(dfm.summary)}</div>`
      : dfm.issues.map(i => `
          <div style="margin-top:4px;padding-left:6px;border-left:3px solid ${sevColor[i.severity] ?? '#999'}">
            <div style="font-weight:600;color:${sevColor[i.severity] ?? '#555'}">[${i.severity.toUpperCase()}] ${escHtml(i.title)}</div>
            <div style="color:#555">${escHtml(i.description)}</div>
            <div style="color:#333"><em>Fix:</em> ${escHtml(i.recommendation)}</div>
          </div>`).join('');

    const resultEl = document.getElementById('forge-adv-result');
    if (!resultEl) return;
    resultEl.innerHTML = `
      <div style="background:#fff;border:1px solid #e0e0e0;border-radius:4px;padding:8px">
        <div style="font-weight:700;color:#b34700">${escHtml(rec.processLabel)}</div>
        <div style="color:#555;margin-top:2px">Route: ${rec.processRoute.map(escHtml).join(' → ')}</div>
        <div style="margin-top:4px;display:flex;gap:12px;flex-wrap:wrap">
          <span><strong>Yield:</strong> ${(rec.reference.yieldBand[0] * 100).toFixed(0)}–${(rec.reference.yieldBand[1] * 100).toFixed(0)}%</span>
          <span><strong>Tolerance:</strong> ${escHtml(rec.reference.toleranceMm)}</span>
          <span><strong>Tooling:</strong> ${escHtml(rec.reference.toolingBand)}</span>
        </div>
        <div style="color:#555;margin-top:4px"><em>${escHtml(rec.reason)}</em></div>
        ${rec.suggestedSecondary.length ? `<div style="color:#555;margin-top:4px"><strong>Secondary:</strong> ${rec.suggestedSecondary.map(escHtml).join(', ')}</div>` : ''}
        <div style="margin-top:6px;border-top:1px solid #eee;padding-top:6px">
          <span style="font-weight:700">DFM score: <span style="color:${scoreColor}">${dfm.score}/10</span></span>
          ${issuesHtml}
        </div>
      </div>`;
    resultEl.style.display = 'block';
  });
}

